var Descs = map[i18n.Language]map[schema.GDID]string{"de": map[schema.GDID]string{"ActivatedCoal": "Eine poröse Form von Karbon mit herausragenden absorbierenden Eigenschaften. Kommt bei der Filterung von Gasen und Flüssigkeiten zum Einsatz.", "Actuator": "Ein Gerät, das Flüssigkeitsdruck in präzise, kontrollierte Bewegungen umwandelt.", "Alternator": "Ein Gerät, das einen starken Halleffekt erzeugt, der Ionentriebwerken die Beschleunigung ihres Treibmittels ermöglicht.", "AluK": "Eine Aluminiumlegierung mit geringem Gewicht und ausgezeichneten Dämmwerten.", "AluminiumIngot": "Ein für seine geringe Dichte und hohe Leitfähigkeit bekanntes Material. Es ist zwar relativ verbreitet, kommt in der Natur aber nur selten in Reinform vor.", "Antimatter_Empty": "Ein Behälter für die Aufbewahrung von Antipartikeln. Die nur schwer herzustellende Antimaterie ist noch schwieriger zu lagern.", "Aquamarine": "Ein Kristall aus der Beryllfamilie. Aufgrund seiner hellblauen Färbung ein beliebter Edelstein.", "AutoBoostModule": "Diese kleine Computerkomponente verbessert die Schubsteuerung: Tippe auf [key.Booster], um den Boost ein-/auszuschalten.", "AutoMineModule": "Diese kleine Computerkomponente verbessert die Steuerung des Minenlasers: Tippe auf [key.Booster], um die Bergbau-Fähigkeit ein-/auszuschalten.", "AzuriteStone": "Ein vorwiegend aus Kupfer bestehender Karbonatkristall, der in der Menschheitsgeschichte häufig als Pigment genutzt wurde.", "BTitanium": "Eine Legierung aus Titan und Vanadium, die aufgrund ihrer bemerkenswerten Formbarkeit ein ausgezeichnetes Schweißmaterial ist.", "B_AntimatterSynthPH": "Dieses Gebäude verbraucht hohe Mengen Elektrizität, um Spuren von Antimaterie zu erzeugen, was durchaus bemerkenswert ist.", "B_Battery": "Dieses Gebäude speichert chemische Energie, wenn das Stromnetz Überkapazitäten erzeugt. Diese Energie kann zur Deckung von Verbrauchsspitzen wieder in Elektrizität umgewandelt werden.", "B_BottlingPlant": "Dieses Gebäude füllt flüssige oder halbflüssige Produkte in standardisierte Behälter ab.", "B_Chemical": "Dieses Gebäude setzte chemische Elemente zu industriellen Verbundstoffen zusammen. Es bedarf er keiner menschlichen Eingriffe und eignet sich ideal für Großproduktionen.", "B_Chest": "In dieser kleinen Kiste können alle Mitglieder der Korporation des Besitzers der Basis Geschenke hinterlassen oder abholen.", "B_Cistern": "Dieses Gebäude dient der Lagerung flüssiger oder halbflüssiger Materialien.", "B_ControlBase": "Dieses zentrale Gebäude beherbergt die für den Betrieb einer kleinen Basis erforderlichen Lager-, Energie- und Verwaltungssysteme. Durch die Stationierung einer Basis entsteht ein Rechtsanspruch auf die Umgebung und die Lager, über denen sie platziert wird. Außerdem verfügt die Basis über einfache Schmelz- und Fertigungsmaschinen.", "B_ControlBase2": "Dieses Gebäude ermöglicht einer Basis die Ausweitung auf einen Landbereich der Stufe 2. Dies verdoppelt ihren maximalen Fußabdruck und schaltet Erlebnisschwellen bis auf 800 Punkte frei.", "B_ControlBase3PH": "Dieses Gebäude ermöglicht einer Basis die Ausweitung auf einen Landbereich der Stufe 3. Dies verdoppelt ihren maximalen Fußabdruck und schaltet Erlebnisschwellen bis auf 2.000 Punkte frei.", "B_ControlBase_Corpo1": "Eine rechtlich sanktionierte Korporation von Bedeutung braucht einen Ort für die Zentralisierung ihrer Operationen. Dieses Gebäude erhöht die maximale Größe einer Basis der Korporation und umfasst Fertigungsmaschinen, einen Konferenzraum und viele Entfaltungsmöglichkeiten.", "B_Crystaliser": "Dises Gebäude stellt Kristalle mittels chemischer Lösungen deutlich schneller her als durch natürliche Prozesse.", "B_ElectricPillar": "Diese Stange kann Stromkabel tragen, um ein Gebäude an das Stromnetz der Basis anzuschließen. Um ein Kabel damit zu verbinden, visiere die Spitze des Pylons an und drücke E.", "B_Extractor": "Dieses Gebäude kann nur über einem Ressourcenlager errichtet werden, um Roherz automatisch abzubauen.", "B_FTLCistern": "Dieses Gebäude dient der Lagerung von aktivem Mag-Plasma.", "B_Factory1": "Dieses Gebäude setzte Ressourcen zu Industriekomponenten zusammen. Als automatisierte Alternative zur manuellen Werkstatt bedarf er keiner menschlichen Eingriffe und eignet sich ideal für Großproduktionen.", "B_Factory2": "Die größten Schiffsmaterialien können nur in riesigen Fabriken gebaut werden, die sehr viel Energie verschlingen.", "B_Farm": "Dieses Gebäude bietet eine geeignete Umgebung für die Kultivierung lebender Organismen.", "B_Generator": "Dieses Gebäude wandelt karbonbasierten Treibstoff in elektrischen Strom für den Betrieb der Basis um. Es ist effektiv und kompakt, aber ressourcenintensiv.", "B_LaboPH": "Dieses Gebäude enthält ein kompaktes Ninmah-Labor mit allem, was man für die Analyse exotischer Substanzen benötigt.", "B_LandingPad": "Auf dieser Plattform kann ein Schiff an der Basis andocken und sich mit ihrem Verteilungssystem verbinden, um Treibstoff oder andere Flüssigkeiten zu transferieren.", "B_LiquidExtractor": "Dieses Gebäude kann nur über einem geothermischen Becken errichtet werden, um Flüssigkeiten automatisch zu extrahieren.", "B_Organiser": "Dieses Gebäude kann verschiedene Drohnenrouten überwachen und zu Produktionsketten verknüpfen. Das Rückgrat einer gut organisierten Pipeline.", "B_PathwayHolder": "Diese hochaufragende Struktur kann einen vorhandenen Raumzeit-Tunnel selbst innerhalb des Gravitationsfeldes eines Planeten stabilisieren. Ein Schiff kann eine derartige Wegbahn mit seinem regulären ÜLG-Triebwerk nutzen.", "B_PowerTransmitter": "Dieses Gebäude nutzt modernste Schildtechnologien und die gravitatorische Krümmung der Raumzeit, um Elektrizität ohne Energieverlust zu den Basen eines Sternsystems zu transportieren.", "B_RecyclingPlant": "Dieses Gebäude gewinnt aus Schrott verschiedene Komponenten und bereitet diese für die industrielle Verwendung auf.", "B_Shipyard": "Auf dieser Plattform kann ein Schiff an der Basis andocken, um seine Struktur zu modifizieren und einzelne Module zu ersetzen. Sie ähnelt den Werften auf Raumstationen.", "B_ShuttlePad": "Auf dieser Plattform kann ein Shuttle an der Basis andocken, um Waren zu liefern oder abzuholen.", "B_Smelter": "Dieses Gebäude wandelt Roherz in industrielle Barren um. Als automatisierte Alternative zum manuellen Schmelzer bedarf er keiner menschlichen Eingriffe und eignet sich ideal für Großproduktionen.", "B_SmelterSA": "Meitner & Karls haben den Schmelzprozess von Erz zu Barren mit Mikroschmelzöfen optimiert. Da er schneller und kleiner ist als ein normaler Schmelzer, ist er das perfekte Accessoire für deine tägliche Arbeit.", "B_SolarPanel": "Dieses Gebäude wandelt elektromagnetische Strahlung in elektrischen Strom für den Betrieb der Basis um. Es erfordert Platz und muss korrekt ausgerichtet sein, arbeitet aber ohne Treibstoff.", "B_Warehouse": "Dieses Gebäude dient der Lagerung fester Materialien, die problemlos von Drohnen befördert werden können.", "BarrierShield1": "Dieses Plasmaschild-Modul kann ein Raumschiff vor leichten Waffen menschlicher Herstellung schützen, lädt sich aber langsamer auf als reguläre Schilde.", "Battery": "Ein Gerät, das chemische Energie speichern und in Elektrizität umwandeln kann. Bildet die Basis größerer Batterie-RSMs.", "Battery1": "Dieses Gerät kann chemische Energie speichern und in Elektrizität für andere RSMs umwandeln.", "Beacon": "Eine experimentelle Methode der Hochgeschwindigkeitskommunikation. Dieser Sender kann seine Position sofort an eine Quantensignatur in einem beliebigen Teil der Galaxie melden.", "BeaconKey": "Eine experimentelle Methode der Hochgeschwindigkeitskommunikation. Dieses Gerät kann sofort die Position des mit ihm verknüpften Senders orten.", "Beam1": "Ein langes Metallstück mit H-förmigem Querschnitt. Dient im Bauwesen der Erhöhung der strukturellen Stabilität.", "BlastMissile0": "Sprengstoff dient bei Minenoperationen dem Abbau durch harte Oberflächen geschützter Mineralien.", "Blueprint": "Dieser Plan enthält alle erforderlichen Anweisungen für den Bau eines spezifischen Schiffsmoduls. Er ist für Menschen und Maschinen lesbar.", "BottlePlasma_Empty": "Ein robuster Mag-Plasma-Behälter, der die Lagerung dieser Substanz in regulären Frachträumen ermöglicht.", "Bottle_Empty": "Ein einfacher, aber verlässlicher Behälter für flüssige oder halbflüssige Substanzen, der ihre Lagerung in regulären Frachträumen ermöglicht.", "CalcifiedInvariant": "Von den Energien des Urknalls geschaffene Steine haben oft eine Energiesignatur, an der man sie eindeutig identifizieren kann.", "Calcite": "Ein auch als Alabaster bekannter Karbonatkristall. Als Hauptkomponente von Kalkstein und Marmor gilt er als ultimatives Material für Bildhauer.", "Carbon": "Ein in Form von Kohle, Diamant oder Graphit für die meisten Industrien essentielles Material. Eines von nur sechs chemischen Elementen, das in allen bekannten Lebensformen nachweisbar ist.", "CarbonGenerator": "Dieses Gerät verbraucht karbonbasierten Treibstoff, um elektrischen Strom für den Betrieb anderer RSMs zu erzeugen.", "CarbonicFuel": "Ein hochverarbeitetes Karbonderiwat, als effizientere Alternative zu natürlichen fossilen Brennstoffen entwickelt wurde.", "Cartridge_Iron": "Das Universelle Verteidigungskorps setzt bis heute Projektilwaffen ein, die in verschiedenen Kalibern produziert werden.", "Cinnabar": "Ein Kristall aus Quecksilbersulfid. Bevor man die hohe Toxizität von Quecksilber erkannte, wurde es aufgrund seiner roten Färbung häufig als Pigment verwendet.", "Cockpit_AE1": "Das individuelle Cockpit von Aegir wurde modernisiert, um die Gefahr kritischer Schäden bei ÜLG-Sprüngen zu reduzieren. Außerdem ist es mit einer kleinen, aber hocheffizienten Batterie ausgestattet.", "Cockpit_AE2": "Das Großraumcockpit von Aegir ist ein technologisches Wunder. Es kann eine präzise Position speichern, zu der das Schiff ohne den Einsatz von Mag-Plasma oder das Risiko von Schäden jederzeit zurückspringen kann.", "Cockpit_DA1": "Das individuelle Cockpit von Damona ist als Meisterwerk der Isolationstechnik weniger anfällig gegen Außentemperaturen, verlangsamt aber auch die Abkühlung der Laser. Es verfügt außerdem über einen kleinen Radiator, mit dem das Schiff Wärme ableiten oder erzeugen kann.", "Cockpit_MK1": "Das individuelle Cockpit von Meitner & Karls wurde hinsichtlich Frachtkapazität und Kollisionsresistenz optimiert und ist damit die perfekte Wahl für den Transport von Waren durch Asteroidenfelder.", "Cockpit_MK2": "Das Großraumcockpit von Meitner & Karls ist groß genug für einen bordeigenen Schmelzer, der den Modellen in landgestützten Basen entspricht.", "Cockpit_TC1": "Das Einstiegscockpit der Kompanie. Vor allem in Testfahrzeugen verbaut.", "Coil": "Ein einfaches Gerät, das Magnetfelder in elektrischen Strom umwandelt und umgekehrt.", "Concrete": "Ein künstliches Gemisch aus Materialien, die von einer als Zement bekannten chemischen Substanz gebunden werden. Der vor allem für Bauvorhaben genutzte Beton war das meistgefertigte Material der Erde.", "ControlBaseCore": "Dieses Gerät beansprucht die Umgebung der Basis eines Nutzers und versorgt sie mit elektrischem Strom. Die Nutzung ist autorisierten Mitarbeitern der Kompanie vorbehalten.", "ControlBaseKit": "Dieses autonome Gerät kann in wenigen Sekunden eine Planetenbasis stationieren. Die Nutzung ist autorisierten Mitarbeitern der Kompanie vorbehalten.", "CopperIngot": "Ein für seine Vielseitigkeit bekanntes leitfähiges Material. Tritt in der Natur als natürliches Metall auf, ist aber auch in Kristallen zu finden.", "CorpoCredits": "Dieser Credits gehören keiner Einzelperson, sondern einer Korporation.", "CorpoReputation": "Schließt eine Korporation Anfragen ab, verbessert sich ihr Ruf in der Galaxie.", "Crystal": "Edelsteine können unterschiedliche Zusammensetzungen, Aspekte und Eigenschaften haben. Ihr gemeinsames Merkmal ist eine ansprechende Optik, die sie für Menschen wertvoll macht.", "CrystalLattice_C": "Ein sauber geschnittener Kristall für optische Geräte. Seine kubische Struktur ist die einfachste natürlich vorkommende Kristallform.", "CrystalLattice_H": "Ein sauber geschnittener Kristall für optische Geräte. Seine hexagonale Struktur ist die meistverbreitete natürlich vorkommende Variante.", "CrystalLattice_M": "Ein sauber geschnittener Kristall für optische Geräte. Seine monokline Struktur ist ausgesprochen asymmetrisch.", "Diamond": "Eine kristalline Form von reinem Karbon. Nach wie vor das härteste und am beste wärmeleitende Material aller Zeiten.", "Drone0": "Dieses autonome Fahrzeug transportiert Frachten auf einer vorgegebenen Route von A nach B.", "Elmerium": "Ein wenig erforschtes Material, dessen elektromagnetische Eigenschaften Plasmafelder bilden können. Seine Entdeckung in der Epoche der Vereinten Planeten ermöglichte die Entwicklung von ÜLG-Schilden.", "ElmeriumEngine": "Ein Gerät, das ein Plasmafeld durch ein Kugelvolumen zerstreut. Eine essentielle Komponenten der meisten Schildmodelle.", "Emerald": "Ein Kristall aus der Beryllfamilie. Aufgrund seiner dunkelgrünen Färbung ein beliebter Edelstein.", "EngineBooster": "Das einfache Hilfstriebwerk-Modul von Luo Ri verschafft Piloten für einen überschaubaren Preis einen spürbaren Geschwindigkeitsvorteil.", "Ethanol": "Ethanol ist bekannt für seine entspannenden Eigenschaften, kann aber auch als Biotreibstoff und Ölentfernungsmittel genutzt werden.", "ExplodingToolMk1": "Ein Modul, das eine einzelne Sprengladung an einem entfernten Ziel anbringt.", "FTLEngine1": "Die wohl größte Erfindung in der Epoche der Vereinten Planeten. Diese Modulkategorie kann den Raum kontrahieren und dehnen, um Reisen mit Überlichtgeschwindigkeit zu ermöglich.", "FTLEngine3_Solo": "Die wohl größte Erfindung in der Epoche der Vereinten Planeten. Diese Modulkategorie kann den Raum kontrahieren und dehnen, um Reisen mit Überlichtgeschwindigkeit zu ermöglich. Dieses Modell ist für ein Einzelschiff optimiert.", "FTLEngine3_Support": "Die wohl größte Erfindung in der Epoche der *Vereinten Planeten*. Diese Modulkategorie kann den Raum kontrahieren und dehnen, um Reisen mit Überlichtgeschwindigkeit zu ermöglich. Dieses Modell kann mehrere Schiffe gleichzeitig transportieren.", "FTLTank1": "Dieses Lagermodul ist für aktives Mag-Plasma geeignet. Seine MACS-Verbindungen ermöglichen die Unterstützung von Schild-RSMs.", "FToiL": "Die Entdeckung dieses bemerkenswerten Treibstoffs hat ÜLG-Sprünge erst möglich gemacht.", "Fertilizer_Neutral": "Ein pulverförmiger Zusatz, der außerirdischen Pflanzen zugeführt werden kann, um sie mit allen erforderlichen Nährstoffen zu versorgen.", "FluidPumpingTool1": "Ein Modul, das mittels einer starken Sogwirkung alle Arten von Flüssigkeiten in der Umgebung sammelt.", "Focuser": "Ein optisches Gerät, das Strahlung durch polierte Kristalle konzentriert.", "Graphene": "Ein aus Karbonatomen bestehendes Material. Aufgrund seiner beispiellosen Dehnfestigkeit ist es eine optimale Lösung, wenn Leichtigkeit und Haltbarkeit entscheidend sind.", "Graphenoid": "Eine Graphenstruktur mit molekularen Quanteneffekten, die erforderlich sind, damit hochwertige ÜLG-Triebwerke eine negative Masse erreichen.", "GraphiteCrystal": "Ein aus mehreren Graphenschichten bestehendes Material. Obwohl man es als unfertigen Diamanten bezeichnen könnte, ist es billig genug für den Einsatz in Bleistiften.", "Grating": "Ein optisches Gerät, das Licht in ein Spektrum von Frequenzen aufspaltet.", "GraviteDetector": "Dieser Spezialdetektor kann Gravitgestein präzise lokalisieren. Er unterscheidet sich deutlich von anderen Detektoren, die mit Ausnahme von Gravit praktisch alles orten können.", "Gunpowder": "Eine chemische Verbindung, die bei Erhitzung verpufft.", "Heater": "Ein Heizgerät wandelt in der kalten Umgebung elektrische Energie in Wärme um.", "Hematite": "Ein aufgrund seiner hohen Dichte im Strahlenschutz eingesetztes kristallines Eisenoxid. Ist darüber hinaus elektrisch leitfähig.", "HullMK1_004": "Raumschiffe bestehen aus drei Hauptelementen: einer leerenbeständigen Außenschicht aus robusten Materialien, einem aus schweren Trägern bestehenden strukturellen Innenskelett und den internen Systemen, die das Schiff bewohn- und nutzbar machen.", "IronIngot": "Ein eng mit der menschlichen Zivilisation verknüpftes Material. Es wird industriell genutzt und zählt zu den häufigsten Elementen terrestrischer Planeten.", "Kaolinite": "Ein häufig vorkommendes Silikatmineral, das in der Produktion von Papier und Farbe zum Einsatz kommt und häufig in Lehmkrusten zu finden ist. In kleinen Mengen verzehrbare Zutat von Zahnpasta.", "KineticShield1": "Dieses Modul erzeugt mit zwei Teslaspulen eine Blase aus geladenem Plasma, die ein Schiff vor Strahlung und Partikeln schützen kann.", "Levinium": "Ein kürzlich entdecktes metallisches Material mit einem ausgesprochen geringen Gewicht. Seine Eigenschaften und Einsatzmöglichkeiten sind noch weitgehend unbekannt.", "LicensePoints": "Diese Punkte regulieren den Zugang zu industriellen Lizenzen und werden von der Universellen Lizenzierungsagentur der Republik ausgegeben.", "Light_01": "Ein gutes Licht, das dir in der Dunkelheit den Weg weist.", "Lime": "Eine für gewöhnlich in Zement und Beton enthaltene mineralische Komponente. Wird durch die Karbonisierung von Kalkstein gewonnen und besteht vorwiegend aus Kalziumoxiden.", "LiquidStorage1": "Dieses Lagermodul ist für flüssige oder halbflüssige Materialien geeignet. Seine MACS-Verbindungen ermöglichen ihm die Versorgung anderer RSMs, wenn es Treibstoff oder Kühlflüssigkeit enthält.", "MagSheet": "Ein magnetisch polarisiertes Elmeriumblech, das für die Auskleidung von Mag-Plasma-Tanks genutzt wird.", "MagneticChamber": "Ein Gerät, das eine schnelle Kreisbewegung des Plasmastroms ermöglicht, ohne von seiner Bahn abzuweichen.", "MalachiteStone": "Ein vorwiegend aus Kupfer bestehender Karbonatkristall, der im antiken Ägypten und von den mesoamerikanischen Maya als Grabschmuck genutzt wurde.", "Mercury": "Quecksilber ist das einzige bekannte Material, das bei Raumtemperatur flüssig ist. Seine Amalgame können viele andere Metalle enthalten und sind für Menschen hochgiftig.", "MetalBolt": "Ein einfache Gerät, das Komponenten mittels Drehkraft verbindet.", "MetalSheet1": "Ein industriell gefertigtes Metallblech, das als einfaches Baumaterial dient.", "MicroChip": "Ein elektronisches Gerät, das mittels einfacher mathematischer Operationen Computerprogramme ausführt. Auch als \"CPU\" bekannt.", "MiningTool1": "Dieses optische Modul verstärkt Licht auf eine Intensität, die viele Materialien verdampfen kann. Derzeit ist dies die präziseste Möglichkeit, Objekte zu schneiden.", "MiningTool_Cold": "Dieser Hochdruckstrahl aus verflüssigtem Gas ist eine Alternative zu Laserstrahlen und hat einen gegenteiligen Effekt auf die Temperatur des Ziels. Beide Technologien können kombiniert eingesetzt werden.", "MissileAirframe_Small": "Ein Metallgehäuse mit Antriebssystem für den Abschuss eines explosiven Gefechtskopfes.", "ModuleCasing1": "Ein universeller Standard, der als Basis für alle darauf aufbauende Raumschiffmodule dient. Verankert den RSM mittels elektromagnetischer Magnete mit dem jeweiligen Schiff.", "Motor": "Ein Gerät, das elektrische Energie in Bewegung umwandelt und umgekehrt.", "Navigator": "Dieses Modul nutzt komplexe Algorithmen und präzise räumliche Koordinaten, um abgelenkte Kontraktoren bei der Planung ihrer Route zu unterstützen.", "P_ColdSuit": "Dieses Zubehör verbessert den Schutz eines Anzugs vor niedrigen Temperaturen. Zur Erhöhung der Effizienz können verschiedene Chips integriert werden.", "P_ConstructionTool": "Die \"Plansynthese* erzeugt eine Wolke schwebender Nanobots, die Materialien basierend auf einem vordefinierten Muster erkennen, schneiden und montieren können. Kurz gesagt: Sie baut Objekte.", "P_DismentlingTool": "Dieses verbesserte Werkzeug umfasst die Funktion \"Material-Desynthese\", die ein fertiges Objekt ohne nennenswerte Schäden in seine Komponenten zerlegt.", "P_FarmingTool": "Die Ausbringung von Samen mag gewöhnlich erscheinen, aber dieses Werkzeug verfeinert die Kunst der Positionierung einer außerirdischen Pflanze an einem Ort, der ein gesundes Wachstum garantiert.", "P_HeatSuit": "Dieses Zubehör verbessert den Schutz eines Anzugs vor hohen Temperaturen. Zur Erhöhung der Effizienz können verschiedene Chips integriert werden.", "P_Jetpack": "[NOTIMPL]", "P_JetpackV2": "[NOTIMPL]", "P_MovingTool": "Dieses verbesserte Werkzeug umfasst die Funktion \"Kontinuierliche Integrität\", die ein Gebäude innerhalb einer Basis ohne vorherige Demontage verlegen kann.", "P_RadSuit": "Dieses Zubehör verbessert den Schutz eines Anzugs vor Strahlung. Zur Erhöhung der Effizienz können verschiedene Chips integriert werden.", "P_ThermoSuit": "Dieses Zubehör verbessert den Schutz eines Anzugs vor hohen und niedrigen Temperaturen. Zur Erhöhung der Effizienz können verschiedene Chips integriert werden.", "PathwayAmmo": "In Kombination mit einem [PathwayPuncher] kann dieser Kernel eine Wegbahn zu einem verfügbaren [B_PathwayHolder] graben. Auf dieser Wegbahn kann man anschließend mit einem gewöhnlichen ÜLG-Triebwerk von A nach B fliegen.", "PathwayPuncher": "Ein Modul, das ein winziges Loch in das Raumzeit-Kontinuum bohrt. Dies ermöglicht den Einsatz von [PathwayAmmo], um eine Wegbahn zu einem existierenden [B_PathwayHolder] zu graben.", "Pipe1": "Eine einfache Vorrichtung für den Transport von Flüssigkeiten von A nach B.", "Plate1": "Eine dicke Metallplatte, die harten Wetterbedingungen standhält. Wird meist für Baumaßnahmen im Freien oder Schiffsrümpfe genutzt.", "PlatinumIngot": "Ein besonders wertvolles Edelmetall. Seine bemerkenswerte Korrosionsbeständigkeit macht es zu einer wichtigen Industriekomponente.", "PressureStorage1": "Dieses Lagermodul ist für die Einlagerung von Flüssiggas unter extremem Druck geeignet. Seine MACS-Verbindungen ermöglichen ihm die Versorgung anderer RSMs, wenn es Treibstoff oder Kühlflüssigkeit enthält.", "Protein": "Eine wichtige Komponente lebender Organismen sind Aminosäureketten bildende Biomoleküle.", "Pump": "Ein Gerät für die Beförderung von Flüssigkeiten durch verbundene Rohre.", "Pyrite": "Ein kristallines Eisensulfid. Das als wertloses \"Katzengold\" bekannte Mineral ist ein nützlicher Halbleiter und eine wichtige photovoltaische Komponente.", "Quartz": "Ein vorwiegend aus Siliziumdioxid bestehender Kristall. Wichtige Komponente vieler astronomischer Geräte. Seit der Antike in seinen zahllosen Variationen ein wichtiges Handelsgut.", "RBattery0": "Dieses Modul kann ohne die Nachteile chemischer Batterien mittels einer rotierenden Scheibe kinetische Energie für den Betrieb anderer RSMs speichern.", "Radar0": "Durch die Erzeugung elektromagnetischer Wellen und die Interpretation ihrer Brechung kann dieses Radar metallische Objekte in einem großen Radius orten und identifizieren.", "Radar_Smart": "Mittels Spektralanalyse und deren Abgleich mit einer Datenbank von Komponenten kann dieser Detektor bekannte Ressourcen aus großer Entfernung identifizieren.", "Radar_Sniffer": "Mittels einer Probe der gewünschten Ressource kann dieser Detektor nahe Lager lokalisieren, die dasselbe Element enthalten.", "Radiator": "Dieses Modul kann große Mengen thermischer Energie freisetzen. Es dient primär der Kühlung eines Raumschiffs, indem es die Wärme in den Weltraum ableitet.", "Radon": "Ein gefährliches radioaktives Gas, mit dem man nicht ohne korrekte Ausrüstung hantieren sollte.", "Rockwood_DreamwoodFruit": "Vom Verzehr dieser Frucht ist dringend abzuraten. Mögliche Nebenwirkungen wären Halluzinationen, Wahnvorstellungen und ein plötzlicher Tod.", "Rockwood_GlowwoodBark": "Diese dunkle Rinde ist in einer radioaktiven Umgebung beheimatet, scheint aber nicht darunter zu leiden.", "Rockwood_GlowwoodFruit": "Diese glänzende Beere ist warm, was für eine erhöhte Radioaktivität spricht.", "Rockwood_Seed": "Steinholz vereint mineralische und organische Komponenten auf ungewöhnliche Weise. Es produziert häufig komplexe Mineralstrukturen, die in der Natur sonst nur selten zu finden sind.", "Sandstone": "Ein vorwiegend aus oxidiertem Silizium bestehendes Sedimentgestein. Eine wichtige Komponente von Glas, Keramik und Zement, die derart verbreitet ist, dass terrestrische Planeten auch als \"Silikatwelten\" bekannt sind.", "Scanner0": "Dieses Modul identifiziert die Zusammensetzung einer Probe mittels Massenspektometrie. Minenlaser können nur Ressourcen bearbeiten, die auf diese Weise identifiziert wurden.", "SeekerMissile0": "Vor dem Exodus waren einfache chemische Sprengstoffe eine verbreitete Waffe. Es gibt auch destruktivere Optionen, aber keine ist derart billig und leicht zu produzieren.", "Semiconductor": "Ein leerer Träger für einen Mikrochip oder eine Solarzelle.", "Shuttle0": "Dieses autonome Fahrzeug transportiert Frachten in und aus Basen und von einer Basis zur anderen.", "SiliciumIngot": "Ein bemerkenswerter Halbleiter, der in den meisten elektronischen Geräten zum Einsatz kommt. Dieses Metalloid ist außerdem in Ton, Glas und verschiedenen Gesteinen zu finden.", "SiliconeGel": "Ein nicht reaktives, hochsaugfähiges Material, das in der Chemie, bei der Wasserfilterung und Kühlung zum Einsatz kommt.", "SilverIngot": "Das leitfähigste und reflektierendste aller Metalle. Kommt in reiner Form natürlich vor und wird von der Menschheit seit Jahrtausenden industriell und künstlerisch genutzt.", "SolarCell": "Ein elektronisches Gerät, das elektromagnetische Wellen in Elektrizität umwandelt.", "SolarPanel1": "Dieses Modul wandelt elektromagnetische Strahlung in elektrischen Strom für den Betrieb anderer RSMs um.", "SpaceWheat_FrostPulp": "Trotz seines Namens ist dieser Brei seltsam lauwarm, als würde sich die Außentemperatur nicht auf ihn auswirken.", "SpaceWheat_PlainPulp": "Dieser Brei ist trotz der ungewöhnlichen Nährstoffe, die er enthält, nahezu geschmacksneutral.", "SpaceWheat_Seed": "Das Raumkorn ist ein hochgradig anpassungsfähiger außerirdischer Organismus. Außerdem ist er eine für den menschlichen Körper verwertbare Nahrungsquelle.", "SpaceWheat_SourPulp": "Dieser Brei ist bereits verdorben und könnte eine Quelle für fermentierte Verbindungen sein.", "SpaceWheat_WoolyKorn": "Diese harte, faserige Schale könnte einige Raumkorn-Samen enthalten. Du brauchst eine Mühle, um sie zu extrahieren.", "Steel": "Eine Legierung aus Eisen und Karbon, der häufig Chrom zugesetzt wird, um das Oxidieren zu verhindern. Aufgrund seiner Verlässlichkeit und geringen Kosten ein Pfeiler der meisten Industrien.", "SteelCasingMK1": "Ein modularer Rumpf für Schiffe oder RSMs. Das Gehäuse verringert die Reibung in atmosphärischen Räumen und schützt vor elektromagnetischer Strahlung.", "Storage1": "Dieses Lagermodul ist für feste Materialien geeignet. Sein magnetisches Stabilisationssystem schützt die Fracht unabhängig von den Bewegungen des Schiffs vor Kollisionen.", "Sulfur": "Ein kristallines Material, eine chemische Komponente und ein Dünger. Eines von nur sechs chemischen Elementen, das in allen bekannten Lebensformen nachweisbar ist.", "SupportCasing": "Ein standardisiertes Set aus Kabeln und Leitungen, über die RSMs mit ihrem Schiff kommunizieren. Folgt der Konvention \"Module Assembly Circulatory System\" (MACS).", "ThermalIsolant": "Eine Mineralfaser, die dünne Luftschichten einschließt, um die Wärmeleitung zu verlangsamen. Der Name weckt angenehme Erinnerungen an eine Zeit, in der es noch echte Wolle gab.", "ThermalPaste": "Diese halborganische Paste ist ungewöhnlich resistent gegen Temperaturschwankungen. Sie kann vor extremen Bedingungen schützen.", "ThermalSheet": "Ein industriell gefertigtes Metallblech, mit erstaunlich geringer Wärmeleitfähigkeit.", "Thruster0": "Dieses elektrische Antriebssystem sorgt für Auftrieb und Schub, ohne fossilen nicht erneuerbaren Treibstoff zu benötigen.", "ThrusterAE1": "Dieses Aegir-Triebwerk ist aufwendig in die Systeme des Schiffs integriert, um eine beispiellose Effizienz und die dunkelsten Winkel des Weltraums zu erreichen.", "ThrusterDA1": "Die Wissenschaft lässt wissbegierige Forscher häufig die Sicherheit vergessen. Mit diesem Triebwerk gibt ihnen Damona die Möglichkeit, sofort in die gesicherte Leere des Weltraums zurückzukehren.", "ThrusterMK1": "Meitner & Karls haben dieses leistungsstarke Triebwerk so konzipiert, dass es der trockenen Hitze einer Minenoperation trotzen kann.", "TitaniumIngot": "Ein wegen seines Gewichts, seiner Robustheit und seiner Biokompatibilität häufig für Legierungen verwendetes Material. Ist außerdem in den meisten lebenden Organismen zu finden.", "TungstenIngot": "Ein dichtes und hartes Metall mit einem außergewöhnlich hohen Schmelzpunkt. Wolfram ist schwer zu verarbeiten, aufgrund seiner Eigenschaften aber eine wichtige Komponente vieler Legierungen.", "Turquoise": "Ein durch den Kontakt von Meteoritenwasser und Kupferporphyr geformter durchsichtiger Edelstein.", "Unbendinium": "Diese mysteriöse Legierung war für die Raumfahrtlogistik der Menschheit von herausragender Bedeutung. Kein anderes bekanntes Metall hat eine vergleichbare Dehnfestigkeit und Stärke.", "UraniumNugget": "Ein gefährliches radioaktives Material, mit dem man nicht ohne korrekte Ausrüstung hantieren sollte.", "VanadiumIngot": "Ein in vielen Metalllegierungen enthaltenes Material. Ist außerdem als Toxin in verschiedenen lebenden Organismen nachweisbar.", "Vitriol": "Schwefelsäure ist eine der meistgenutzten Industriesubstanzen. Es gibt viele Wege, diese Komponente zu produzieren, und noch mehr Einsatzmöglichkeiten.", "Water": "Als bemerkenswert neutrale Flüssigkeit mit starker Polarität und kleinen Molekülen ist Wasser für alle bekannten Lebensformen und die meisten Industrien von essentieller Bedeutung.", "Water_Brine": "Große Wasserflächen unter freiem Himmel sind mit vielen Stoffen verunreinigt und müssen vor der chemischen Nutzung behandelt werden.", "Wire": "Ein einfaches Gerät zur Übertragung elektrischer Ströme von A nach B.", "XenicOil": "Ein aus außerirdischen Samen gewonnenes organisches Hydrokarbon. Xeno-Öl ist ein nützliches Schmiermittel und ein mittelmäßiger Treibstoff.", "ZirconiumIngot": "Ein korrosions- und hitzebeständiges Material. Speichert radioaktive Energie mit minimalem Verlust."}, "en": map[schema.GDID]string{"ActivatedCoal": "A porous form of carbon with outstanding adsorptive properties. Widely used to filter gases and fluids.", "Actuator": "A device that convert fluid pressure into precise, controlled movements.", "Alternator": "A device capable of producing a strong Hall effect, allowing ion thrusters to accelerate their propellant.", "AluK": "An alloy of aluminum, with a low weight and an excellent thermal isolation.", "AluPowder": "[NOT IMPL]", "AluminiumIngot": "A material noted for its very low density and high conductivity. Though abundant, it seldom appears naturally in pure form.", "Antimatter_Empty": "A container for holding antiparticles. Notoriously hard to produce, antimatter is even harder to store.", "Aquamarine": "A crystal of the beryl family, traded as a gemstone and valued for its characteristic light-blue hue.", "AutoBoostModule": "This small piece of computer improves the control of the thrusters: tap [key.Booster] to toggle the boost.", "AutoMineModule": "This small piece of computer improves the control of the mining laser: tap [key.Mine] to toggle the mining skill.", "AzuriteStone": "A carbonate crystal mostly made up of copper and often used as a pigment throughout human history.", "BTitanium": "An alloy of titanium and vanadium, valued for the remarkable formability that makes it an excellent welding material.", "B_AntimatterSynthPH": "This building consumes huge amounts of electricity to produce trace amounts of antimatter, which is still rather remarkable.", "B_AtmoDome": "[NOT IMPL] Building that reduces or negates entirely weather pattern and environmental stuff around the base and in a tube above it, up to space, allowing ship that are not equipped for it to interact with the base.", "B_Battery": "This building stores chemical energy when the power grid produces excess power. It can then readily convert that energy back to electricity during spikes in consumption.", "B_BottlingPlant": "This building packages liquid or semi-fluid products into standardized containers.", "B_Chemical": "This building assembles chemical elements into industrial compounds. It can function continuously with no human input, which makes it appropriate for large-scale production.", "B_Chest": "This small box let anyone from the same corporation than the base owner leave, or take, gifts.", "B_Cistern": "This building is suitable for storing liquid or semi-fluid materials.", "B_ControlBase": "This central building provides the basic storage, electric power and administrative systems needed to operate a small land base. Deploying a base constitutes a legal claim over the area and deposits it is placed over. It also comes with basic manual smelting and crafting machines.", "B_ControlBase2": "This building allows a base to expand over a Level 2 land area, doubling its maximum footprint and unlocking experience thresholds up to 800 points.", "B_ControlBase3PH": "This building allows a base to expand over a Level 3 land area, doubling its maximum footprint and unlocking experience thresholds up to 2000 points.", "B_ControlBase_Corpo1": "A legally sanctionned corporation of importance often requires a place to centralized its operation. This building increases the maximum size of a single base of the corporation and contains crafting machines, a conference room, and many customizable space.", "B_Crystaliser": "This building uses chemical solutions to generate crystals at exceptionally high speeds compared to their natural formation process.", "B_ElectricPillar": "This pole can support electric cables and connect the base's power grid to another building. To plug a cable into it, target the top of the pylon and press E.", "B_Extractor": "This building can only be assembled over a resource deposit, which it will then drill into to extract raw ore automatically.", "B_FTLCistern": "This building is suitable for storing active mag-plasma.", "B_FTLGatherer": "[NOT IMPL] Building that produce mag-plasma slowly, based on some local properties (maybe proximity from other condensator, and space station reduce production)", "B_Factory1": "This building assembles basic resources into industrial compounds. As an automated alternative to the manual workshop, it can function continuously with no human input, which makes it appropriate for large-scale production.", "B_Factory2": "The biggest ship materials can only be built in a custom large-scale factory that consumes a lot of energy.", "B_Farm": "This building provides an appropriate environment to cultivate living organisms.", "B_FusionGenerator": "[NOT IMPL]", "B_Generator": "This building consumes carbon-based fuel to produce electric current, supplying the base's power grid. It is effective and compact, but resource-intensive.", "B_Generator2": "[NOT IMPL]", "B_HeatRecouper": "[NOT IMPL] reduce temperature around the base. Produce power based on current temperature", "B_Hypergate": "[NOT IMPL] Building that allows the creation of a tunnel toward a hypergate beacon from the same corporation. Consume a lot of power.", "B_LaboPH": "This building contains a compact Ninmah laboratory with everything needed to analyze exotic substances.", "B_LandingPad": "This platform allows a ship to dock on the base and connect to its distribution system to transfer fuel or other fluids.", "B_LiquidExtractor": "This building can only be assembled over a geothermal pool, from which it will extract pure fluid automatically.", "B_Observatory": "[NOT IMPL] Building that allow either the owner or its corporation to see invisible FTL pathways and remove the required level to use an FTL pathway, up to a certain range.", "B_Organiser": "This building can monitor multiple drone routes and merge them into full-fledged production chains. The backbone of a well-organized pipeline.", "B_PathwayHolder": "This towering structure can keep an existing spacetime tunnel stable, even in the gravitational well of a planet. A ship can travel through such a pathway with their regular FTL engine.\nRequires the deployment of a [PathwayAmmo] with a [PathwayPuncher] at the exit point.", "B_PowerTransmitter": "This building exploits cutting-edge shield technology and gravitational spacetime deformation to beam electricity without loss between different bases in the same stellar system.", "B_RecyclingPlant": "This building processes scraps to extract their various components and prepare them for industrial reuse.", "B_Shipyard": "This platform allows a ship to dock on the base to have its structure modified and its modules replaced. It is similar to the shipyards of space stations.", "B_ShuttlePad": "This platform allows a shuttle to dock on the base, transporting goods into and out of it.", "B_Smelter": "This building converts raw ore into industrial ingots. As an automated alternative to the manual smelter, it can function continuously with no human input, which makes it appropriate for large-scale production.", "B_SmelterSA": "Meitner & Karls have refined the process of turning ore into ingots with this micro-furnace. Smaller and faster than a regular smelter, it's the perfect accessory for your days of heavy manual crafting.", "B_SolarPanel": "This building converts electromagnetic radiation into electric current, supplying the base's power grid. It takes up space and must be oriented correctly, but it operates without fuel.", "B_StandaloneFoundation": "[DEPRECATED]", "B_SunStation": "[NOT IMPL] Space Building that produce a huge amount of power from a nearby star. Damage itself when its batteries are full.", "B_Warehouse": "This building is suitable for storing solid materials, which can be easily moved in and out by drones.", "BarrierShield1": "This plasma shield module has enough charge to protect a spaceship from light man-made weapons, but takes longer to load than regular shields.", "Battery": "A device that can store chemical energy and convert it to electricity. Forms the basis of larger battery RSMs.", "Battery1": "This module can store chemical energy and readily convert it to electric current to power other RSMs.", "Beacon": "An experimental method of high-speed communication. This beacon can instantly reveal its position to a quantum signature across the galaxy, no matter where it is.", "BeaconKey": "An experimental method of high-speed communication. This device can instantly pick up the position of the beacon it is paired with.", "Beam1": "An elongated piece of metal with an H-shaped cross-section. Commonly used in construction to provide structural resistance.", "BlastMissile0": "Explosives are often used in mining operations to access minerals protected by heavy surface materials.", "Blueprint": "This detailed plan contains all the necessary instructions to build a specific ship module. It can be read by a human or by a machine.", "BottlePlasma_Empty": "A sturdy mag-plasma container, making it possible to store this substance in regular cargo holds.", "Bottle_Empty": "A rudimentary but reliable container for liquid or semi-fluid substances, making it possible to store them in regular cargo holds.", "CalcifiedInvariant": "Ancient stones, bathed in the primordial energies of the big bang, sometimes have an energy signature that makes them uniquely identifiable.", "Calcite": "A carbonate crystal also known as alabaster. As the main component of limestone and marble, it is the ultimate sculpting material.", "Carbon": "An essential material in most industries, whether in the form of coal, diamond or graphite. It is also one of only six chemical elements found in all known forms of life.", "CarbonGenerator": "This module consumes carbon-based fuel to produce electric current to power other RSMs.", "CarbonicFuel": "An ultra-processed derivative of carbon, engineered as a more efficient alternative to natural fossil fuels.", "Cartridge_Iron": "Projectile weapons are still used extensively by the Universal Defense Corps, which developed an array of standards for cartridge calibers.", "Cinnabar": "A crystal of mercury sulfide, that was widely used as pigment because of its bright red color, before the high toxicity or mercury was recognized.", "Cockpit_AE1": "Aegir's individual cockpit is streamlined to reduce the probability of critical damage during FTL jumps. It also comes with a small but highly efficient power battery.", "Cockpit_AE2": "Aegir's large size cockpit is a technological wonder, capable of saving a precise location to which it can jump back at any time with no mag-plasma use and no risk of damage.", "Cockpit_AE3": "[NOT IMPL]", "Cockpit_DA1": "Damona's individual cockpit is a feat of insulation engineering that makes it less vulnerable to outside temperatures, but also slows down laser cooling. It also comes with a small radiator to help the ship evacuate excess heat or generate some when it gets cold.", "Cockpit_DA2": "[TODO] I don't know the effect, nor the name of this one", "Cockpit_DA3": "[NOT IMPL]", "Cockpit_LR1": "[NOT IMPL]", "Cockpit_LR2": "[NOT IMPL]", "Cockpit_LR3": "[NOT IMPL]", "Cockpit_MK1": "Meitner & Karls' individual cockpit is optimized for storage space and collision resistance, making it the perfect pick for transporting cargo through asteroid fields.", "Cockpit_MK2": "Meitner & Karls' large size cockpit is massive enough to include an onboard smelter, similar to the ones you could build in a land base.", "Cockpit_MK3": "[NOT IMPL]", "Cockpit_TC1": "The Company's entry-level cockpit, mostly equipped on test vehicles.", "Coil": "A simple device converting magnetic fields into electric current, and vice versa.", "CombatMissile_AntiMatter": "[NOT IMPL]", "Concrete": "An artificial aggregate of minerals held together by a chemical substance known as cement. Mostly used in construction, concrete was the most manufactured material on Earth.", "ControlBaseCore": "This device can claim the surrounding area for the user's base and supply it with electric power. Its use is reserved to authorized associates selected by The Company.", "ControlBaseKit": "This autonomous device can deploy a planetary base in a matter of seconds. Its use is reserved to authorized associates selected by The Company.", "CopperIngot": "A highly conductive material noted for its versatility. Occurs in nature as a native metal, but can also be found in crystals.", "CorpoCredits": "These credits are owned by a corporation rather than an individual.", "CorpoReputation": "As each Corpo completes its various requests, their reputation across the galaxy improves.", "Crystal": "Gemstones can have different compositions, aspects and properties. Their common trait is an aesthetic appeal that makes them valuable to humans.", "CrystalLattice_C": "A cleanly cut crystal that can be used in an optical device. Its cubic structure is the simplest crystal shape found in nature.", "CrystalLattice_H": "A cleanly cut crystal that can be used in an optical device. Its hexagonal structure is the most commonly found in nature.", "CrystalLattice_M": "A cleanly cut crystal that can be used in an optical device. Its monoclinic structure is remarkably asymmetrical.", "Diamond": "A crystalline form of pure carbon. It remains the hardest and most thermally conductive material ever observed.", "Drone0": "This autonomous vehicle carries loads from one point to another along a predefined route.", "Elmerium": "A relatively poorly understood material whose electromagnetic properties can shape plasma fields. Its discovery during the United Planets era sparked the development of FTL shields.", "ElmeriumEngine": "A device capable of dispersing a plasma field through a spherical volume. An essential component of most Shield models.", "Emerald": "A crystal of the beryl family, traded as a gemstone and valued for its characteristic dark-green hue.", "EngineBooster": "Luo Ri's entry level auxiliary engine module can give a substantial speed advantage to pilots on a budget.", "Ethanol": "While it is well known for its recreative properties, ethanol is also a dense bio-fuel, and an useful solvent for oily stains.", "ExplodingToolMk1": "A module used to deliver a single explosive payload to a remote target.", "ExplodingToolMk2": "[NOT IMPL]", "FTLEngine1": "Regarded as the greatest invention of the United Planets era, this category of modules can contract and expand space, making faster-than-light travel possible.", "FTLEngine3_Solo": "Regarded as the greatest invention of the United Planets era, this category of modules can contract and expand space, making faster-than-light travel possible. This model is optimized for a single ship.", "FTLEngine3_Support": "Regarded as the greatest invention of the *United Planets* era, this category of modules can contract and expand space, making faster-than-light travel possible. This model can transport several ships at once.", "FTLTank1": "This storage module is suitable for active mag-plasma. Its MACS connections enable it to supply shield RSMs.", "FToiL": "The discovery of this remarkable fuel is what made the invention of FTL jumps possible.", "Fertilizer_Neutral": "A powdered supplement that can be administered to alien plants to supply them with specific nutrients.", "FluidPumpingTool1": "A module designed to gather all kinds of fluid present in the environnement, through a powerful suction.", "Focuser": "An optical device to concentrate radiation through polished crystals.", "FusionGenerator": "[NOT IMPL] Produce Power and consume hydrogen or something", "Graphene": "A material composed of interlocked carbon atoms. Its unequaled tensile strength makes it an optimal solution when both lightness and solidity are essential.", "Graphenoid": "A graphene structure exhibiting quantum molecular effects, essential to the ability of high-end FTL engines to reach negative mass.", "GraphiteCrystal": "A crystal comprising multiple layers of graphene. Although it could be described as an unfinished diamond, it is cheap enough to be used in pencils.", "Grating": "An optical device that decomposes light into a spectrum of frequencies.", "GraviteDetector": "This specialized detector can locate gravite stones with precision. It greatly differs from other detectors, which can locate pretty much everything except gravite.", "Gunpowder": "A chemical compound that deflagrates when heated.", "HeatRecouper": "[NOT IMPL] Turn heat into power slowly and increase heat capacity alot", "HeatShield": "[NOT IMPL] Improve the shield of the ship, so that, as long as it is active, the ship also benefit from a protection from environmental heat and cold (reduction of the heat interface), and from heat-related weapons", "Heater": "A heater is used to combat the harsh cold exterior by turning electrical power into raw heat.", "HeavyShield2": "[NOT IMPL A heavy combat shield, that ignores light damage, at an increased energy cost.]", "Helium": "[NOT IMPL]", "Hematite": "A crystalline iron oxide, useful in radiation shielding because of its high density. It is also noted for its electric conductivity.", "HullMK1_001_AX": "[NOT IMPL]", "HullMK1_002_AX": "[NOT IMPL]", "HullMK1_003_AX": "[NOT IMPL]", "HullMK1_004": "Space crafts are composed of three main layers: a voidproof outside layer, made of resistant material, a structurally sound internal skeleton of heavy beams, and the internal systems keeping the ship inhabitable and functioning.\n\nStellar Engineering brings together all three layers in its modular part designs to help you build the ship of your dreams.", "HullMK1_004_AX": "[NOT IMPL]", "HullMK1_005_AX": "[NOT IMPL]", "HullMK1_006_AX": "[NOT IMPL]", "HullMK2_004_AX": "[NOT IMPL]", "HullMK2_005_AX": "[NOT IMPL]", "HullMK2_006_AX1": "[NOT IMPL]", "HullMK2_007_AX": "[NOT IMPL]", "HullMK2_008_AX1": "[NOT IMPL]", "HypergateBeacon": "[NOT IMPL] Exit point for a Hypergate tunnel.", "IronIngot": "A material closely associated with the advent of human civilization. Widely used in industry, it is one of the most abundant elements on terrestrial planets.", "IsotopicGenerator": "[NOT IMPL] Produce Power but do not require anything (not even light !!!)", "Kaolinite": "A very common type of silicate mineral, widely used in the production of paper and paint, and often found in clay shells. Safe to ingest in small quantities, it is also a common ingredient in toothpaste.", "KineticShield1": "Using a pair of Tesla coils, this module generates a bubble of charged plasma that can protect a spaceship from radiation and particles.", "KineticShield_Group": "[NOT IMPL] Generate shield for all ships in the group at relatively close proximity.", "Levinium": "A recently discovered metallic material, noted for its remarkable lightness. Its properties and use cases are still relatively unknown.", "LicensePoints": "Regulating access to industrial licenses, these points are issued by The Republic's Universal Licensing Agency.", "Light_01": "A good light, used to open a path of vision in the darkness.", "Lime": "A mineral component commonly used in cement and concrete. Obtained by carbonating limestone, it is mostly composed of calcium oxides.", "LiquidStorage1": "This storage module is suitable for liquid or semi-fluid materials. Its MACS connections allow it to supply other RSMs if it contains fuel or cooling fluid.", "LockedCapsule": "[NOT IMPL] A capsule whose access is configurable.", "MagSheet": "A magnetically polarized sheet of elmerium, commonly used for the inner shells of mag-plasma tanks.", "MagShield": "[NOT IMPL] Shield that negate 30% of damage received and turn it into power for the ship. If there are no batteries to hold that power, the excedent power gain is turned back into damage that affect directly the hull.", "MagneticChamber": "A device allowing plasma current to flow in high-speed circular motion without escaping its trajectory.", "MalachiteStone": "A carbonate crystal mostly made up of copper and used as a funeral ornament from Ancient Egypt to Mayan Mesoamerica.", "Mercury": "Mercury is the only known metal that is liquid at room temperature. It amalgams with many other metals, and is highly toxic to humans.", "MetalBolt": "A simple device using twisting force to fasten components together.", "MetalSheet1": "An industrially processed sheet of metal, commonly used as a basic construction material.", "MicroChip": "An electronic device executing computer programs through a series of simple mathematical operations. Also known as a \"Central Processing Unit\".", "MiningTool1": "This optical module amplifies light to an intensity that can vaporise many materials. It is currently the most precise way to cut through things.", "MiningTool_Cold": "This high-pressure stream of liquefied gas provides an alternative to laser beams, with the opposite effect on the target's temperature. The two can be used in combination.", "MissileAirframe_Small": "A metal casing and propulsion structure capable of transporting an explosive warhead.", "ModuleCasing1": "A universal standard serving as a basis for all \"Reliant Spaceship Modules\". Anchors the RSM to its associated ship using B-Switch electropermanent magnets.", "Motor": "A device converting electric power into motion, and vice versa.", "Navigator": "This module use complex algorithms and precise spatial coordinates to help the distracted contractor plan a route across the stars.", "NitroCapsule": "[NOT IMPL Ammunition for the nitrogenerator]", "Nitrogenerator": "[NOT IMPL] gives a skill usable in and out of combat that consumes hydrogen capsule, to produce a lot of power for a short time (with a long cooldown)", "PBattery": "[NOT IMPL] A Battery that load fully when jumping in FTL (and cannot reload in any other way). Is consumed before any other battery.", "PShuttle": "[NOT IMPL shuttle but transport power instead of goods", "P_ColdSuit": "This accessory increases a suit's insulation capacity against low temperatures. Multiple chips can be applied for increased efficiency.", "P_ConstructionTool": "\"Blueprint Synthesis\" releases a cloud of hovering nanobots that can recognize, cut and assemble materials based on a predefined pattern. In short, it builds stuff.", "P_CritterPheromon": "[NOT IMPL a grenade that attracts Critters where it lands for a while]", "P_DismentlingTool": "This improved tool includes the \"Material De-Synthesis\" feature, which can reverse a finished construction process and retrieve some of the components involved.", "P_FarmingTool": "Putting a dirty seed to soak might seem like a mundane task, but this tool sublimates the art of positioning a germinating piece of alien plant at the perfect place for the success of its developpement.", "P_HeatSuit": "This accessory increases a suit's insulation capacity against high temperatures. Multiple chips can be applied for increased efficiency.", "P_Jetpack": "[NOTIMPL]", "P_JetpackV2": "[NOTIMPL]", "P_MovingTool": "This improved tool includes the \"Continuous Integrity\" feature, which can relocate a building within a base without dismantling it first.", "P_RadSuit": "This accessory increases a suit's insulation capacity against radiation. Multiple chips can be applied for increased efficiency.", "P_ThermoSuit": "This accessory increases a suit's insulation capacity against both high and low temperatures. Multiple chips can be applied for increased efficiency.", "PathwayAmmo": "Used with a [PathwayPuncher], this kernel can bore a pathway to any available [B_PathwayHolder]. Such a Pathway can then be used to travel between two locations with a regular FTL engine.", "PathwayPuncher": "A module that bores a tiny hole in the spacetime continuum. This allows the deployment of a [PathwayAmmo] that will dig a pathway toward an existing [B_PathwayHolder].", "Pipe1": "A simple device to move fluids between two points.", "Plate1": "A thick metallic panel that can resist harsh weather conditions. Commonly used in outdoor construction or ship hulls.", "PlatinumIngot": "A noble metal of especially high value. Its remarkable resistance to corrosion makes it a prized industrial component.", "PowerSharerPH": "[NOT IMPL] Act as a hub for every ship in the group to share power (from low battery to high battery)", "PressureStorage1": "This storage module is suitable for liquid gas requiring extreme pressurization. Its MACS connections allow it to supply other RSMs if it contains fuel or cooling fluid.", "Protein": "An essential component of living organisms, proteins are biomolecules comprising amino acid chains.", "Pump": "A device for propelling fluids through connected pipes.", "Pyrite": "A crystalline iron sulphide. Cheap enough to be known as \"fool's gold\", it is nevertheless a useful semiconductor and a common photovoltaic component.", "Quartz": "A crystal mostly made up of silica, and a major component of many astronomical objects. Its numerous varieties have been traded as gemstones since human antiquity.", "RBattery0": "This module can store kinetic energy with a rotating wheel to power other RSMs while avoiding the disadvantages of chemical batteries.", "Radar0": "By emitting electromagnetic waves and interpreting their refraction, this radar can detect and identify metallic objects within a large perimeter.", "Radar_Smart": "Using spectral analysis and comparison with a database of components, this detector can identify known resources from afar.", "Radar_Sniffer": "Using a sample of a determined resource, this detector can locate nearby deposits containing the same element.", "Radiator": "This module can release large quantities of thermal energy. It is mostly used to cool off a spaceship’s interior by dispersing its heat into space.", "Radon": "A dangerous radioactive gaz that should not be handle without the proper equipement.", "Rockwood_DreamwoodFruit": "Consumption of this fruit is strongly discouraged. Side effects might include: vivid hallucinations, acute paranoia, and sudden death.", "Rockwood_GlowwoodBark": "This dark thick bark has grown in a radioactive environment, but it does not seem to have suffered from it.", "Rockwood_GlowwoodFruit": "This shiny berry is slightly warm to the touch, a sign of latent radioactivity.", "Rockwood_Seed": "The Rockwood combines mineral and organic compounds in an unusual way. It often produces complex mineral structures that are rarely found anywhere else in nature.", "Sandstone": "A sedimentary rock mostly made up of oxidized silicon. A component in glass, ceramics and cement, it is so abundant that terrestrial planets are also known as \"silicate planets\".", "Scanner0": "This module identifies the composition of a sample via mass spectrometry. Mining lasers can only be used on resources that were identified through this process.", "SeekerMissile0": "Before the exode, simple chemical explosives were a commonplace weapon. More destructive options exist, but none are as cheap and easy to produce.", "Semiconductor": "A blank page for a future microchip or solar cell.", "Shuttle0": "This autonomous vehicle carries loads into and out of the base, transporting them to or from other bases.", "Shuttle1": "[NOT IMPL bigger shuttle]", "SiliciumIngot": "A remarkably balanced semiconductor used in most electronic devices. This metalloid can also be found in clay, glass, and numerous types of stone.", "SiliconeGel": "A non-reactive, highly absorbent semi-solid, notably used in chemistry, water filtration and cooling.", "SilverIngot": "The most conductive and reflective of all metals. It can be found in its pure form naturally, and has been used in numerous aspects of human industry and art for millennia.", "SolarCell": "An electronic device converting electromagnetic waves into electricity.", "SolarPanel1": "This module converts electromagnetic radiation into electric current to power other RSMs.", "SpaceWheat_FrostPulp": "Despite its name, this pulp is strangely tepid, as if unaffected by outside temperature.", "SpaceWheat_PlainPulp": "This pulp is mostly tasteless, despite the unusual nutrient it contains.", "SpaceWheat_Seed": "The Spacekorn is a highly adaptable alien organism. Even better, it’s a source of nutrients compatible with human biology.", "SpaceWheat_SourPulp": "This pulp has clearly turned already, and might be a source of fermented compounds.", "SpaceWheat_WoolyKorn": "This hard fibrous shell should contain a few spacekorn seed. A grinder is required to extract them.", "StealthModule_Group": "[NOT IMPL] Tool that makes it more difficult to detect the ship (both for PC and NPC) and friendly ships around (Consume Antimatter Core)", "StealthModule_Personnal": "[NOT IMPL] Tool that makes it more difficult to detect the ship (both for PC and NPC) (Consume Antimatter Core)", "Steel": "An alloy of iron and carbon, frequently incorporating chromium to prevent oxidation. Its reliability and low cost make it a staple of most industries.", "SteelCasingMK1": "A modular hull encasing a ship or an RSM. In addition to limiting friction in atmospheric spaces, the casing provides protection against electromagnetic radiation.", "Storage1": "This storage module is suitable for solid materials. Its magnetic stabilization system protects its load from collisions, regardless of the ship's movements.", "Sulfur": "A crystalline material, chemical component and fertilizer. Described in the Bible as the brimstone of hell, it is one of only six chemical elements found in all known forms of life.", "SupportCasing": "A standardized set of cables and pipes allowing all RSMs to communicate with their associated ship. Follows the \"Module Assembly Circulatory System\" or MACS convention.", "ThermalIsolant": "A mineral fiber that traps thin layers of air to slow down thermal conduction. Its name evokes the gentle memory of a time when real wool still existed.", "ThermalPaste": "This semi-organic paste is unusually resistant to temperature changes. It can be use to protect from extreme condition.", "ThermalSheet": "An industrially processed sheet of metal with remarkably low thermal conductivity.", "Thruster0": "This electric propulsion device can provide thrust and lift to a spaceship without requiring any combustion or non-renewable fuel.", "ThrusterAE1": "This subtle AEgir thruster integrates deeply with the ship's system to reach both summits of power efficiency and uncharted darkness.", "ThrusterDA1": "Science often brings the inquisitive minds beyond the edge of safety. With this thruster, Damona gives them a way to return promptly to the secured emptyness of space.", "ThrusterMK1": "Meitner & Karls have designed this powerful thruster to deal with the dry heat of the most instense mining trip.", "TitaniumIngot": "A material commonly used in alloys for its lightness, resistance and biocompatibility. It can also be found in most living organisms.", "TungstenIngot": "A dense and hard metal with an exceptionally high melting point, tungsten is difficult to work, but its properties also make it a critical component of many alloys.", "Turquoise": "An opaque gemstone formed by the contact of meteoritic water and copper porphyry.", "Unbendinium": "This mysterious alloy has been critical to humankind spacefaring logistics. Its tensile and yield strenghts are unmatched by any other metal known to man.", "UraniumNugget": "A dangerous radioactive material that should not be handle without the proper equipement.", "VanadiumIngot": "A material commonly used in steel alloys. It can also be found as a toxin in a number of living organisms.", "Vitriol": "Sulphuric acid is one of the most widely used industrial substances. There are many ways to produce this component, and even more ways to use it.", "Water": "As a remarkably neutral solvent with a strong polarity and small molecular size, water is essential to all known lifeforms and most known industries.", "Water_Brine": "Large open body of water under an open sky are contaminated with many compounds, and need to be treated before being used in chemical applications.", "Water_Waste": "[NOT IMPL]", "Wire": "A simple device to transmit electric current between two points.", "XenicOil": "An organic hydrocarbon extracted from alien seeds, xenic oil is an useful lubricant and a mediocre fuel.", "ZirconiumIngot": "A material remarkably resistant to corrosion and high temperatures. It is also capable of storing radioactive energy with minimal loss."}, "es": map[schema.GDID]string{"ActivatedCoal": "Una forma porosa de carbono con excelentes propiedades de adsorción. Ampliamente utilizado para filtrar gases y fluidos.", "Actuator": "Un dispositivo que convierte la presión de un fluido en movimientos precisos y controlados.", "Alternator": "Un dispositivo capaz de producir un fuerte efecto Hall, que permite a los propulsores iónicos acelerar su propelente.", "AluK": "Una aleación de aluminio, de bajo peso y con un excelente aislamiento térmico.", "AluminiumIngot": "Un material que destaca por su muy baja densidad y alta conductividad. Aunque es abundante, rara vez aparece de forma natural en estado puro.", "Antimatter_Empty": "Un contenedor para guardar antipartículas. La antimateria, notoriamente difícil de producir, es aún más difícil de almacenar.", "Aquamarine": "Cristal de la familia del berilo, comercializado como piedra preciosa y valorado por su característico tono azul claro.", "AutoBoostModule": "Este pequeño componente informático mejora el control de los propulsores: pulsa [key.Booster] para activar el potenciador.", "AutoMineModule": "Este pequeño componente informático mejora el control del láser minero: pulsa [key.Mine] para activar la habilidad de minería.", "AzuriteStone": "Cristal de carbonato rico en cobre y utilizado a menudo como pigmento a lo largo de la historia de la humanidad.", "BTitanium": "Aleación de titanio y vanadio, valorada por su extraordinaria maleabilidad, que la convierte en un excelente material para soldar.", "B_AntimatterSynthPH": "Este edificio consume enormes cantidades de electricidad para producir cantidades ínfimas de antimateria, lo cual no deja de ser sorprendente.", "B_Battery": "Este edificio almacena energía química cuando la red eléctrica produce un exceso de energía. Luego, puede convertir fácilmente esa energía de nuevo en electricidad durante los picos de consumo.", "B_BottlingPlant": "Este edificio envasa productos líquidos o semifluidos en recipientes estandarizados.", "B_Chemical": "Este edificio reúne elementos químicos para formar complejos industriales. Puede funcionar de forma continua sin intervención humana, lo que la hace idónea para la producción a gran escala.", "B_Chest": "Esta pequeña caja permite que cualquier persona de la misma corporación que el propietario de la base deje o reciba regalos.", "B_Cistern": "Este edificio es apto para almacenar materiales líquidos o semifluidos.", "B_ControlBase": "Este edificio central proporciona los sistemas básicos de almacenamiento, energía eléctrica y administración necesarios para operar una pequeña base territorial. Desplegar una base constituye una reclamación legal sobre el área y los depósitos sobre los que se ubica. También incluye máquinas básicas de fundición y fabricación manual.", "B_ControlBase2": "Este edificio permite que una base se expanda sobre un área de terreno de nivel 2, lo que duplica su superficie máxima y desbloquea umbrales de experiencia de hasta 800 puntos.", "B_ControlBase3PH": "Este edificio permite que una base se expanda sobre un área de terreno de nivel 3, lo que duplica su superficie máxima y desbloquea umbrales de experiencia de hasta 2000 puntos.", "B_ControlBase_Corpo1": "Una corporación importante y legalmente reconocida a menudo necesita un lugar donde centralizar sus operaciones. Este edificio aumenta el tamaño máximo de una sola base de la corporación y contiene máquinas de fabricación, una sala de conferencias y muchos espacios personalizables.", "B_Crystaliser": "Este edificio utiliza soluciones químicas para generar cristales a velocidades excepcionalmente altas en comparación con su proceso de formación natural.", "B_ElectricPillar": "Este poste puede soportar cables eléctricos y conectar la red eléctrica de la base con otro edificio. Para conectar un cable, apunta a la parte superior del pilón y pulsa E.", "B_Extractor": "Este edificio solo puede ensamblarse sobre un yacimiento de recursos, en el que luego perforará para extraer la mena en bruto automáticamente.", "B_FTLCistern": "Este edificio es adecuado para almacenar plasma magnético activo.", "B_Factory1": "Este edificio reúne recursos básicos para formar complejos industriales. Como alternativa automatizada al taller manual, puede funcionar de forma continua sin intervención humana, lo que la hace idónea para la producción a gran escala.", "B_Factory2": "Los materiales para las naves más grandes solo pueden fabricarse en una fábrica especializada a gran escala que consume mucha energía.", "B_Farm": "Este edificio proporciona un entorno adecuado para el cultivo de organismos vivos.", "B_Generator": "Este edificio consume combustible a base de carbono para producir corriente eléctrica, que abastece la red eléctrica de la base. Es eficaz y compacta, pero requiere muchos recursos.", "B_LaboPH": "Este edificio alberga un laboratorio Ninmah compacto con todo lo necesario para analizar sustancias exóticas.", "B_LandingPad": "Esta plataforma permite que una nave se acople a la base y se conecte a su sistema de distribución para transferir combustible u otros fluidos.", "B_LiquidExtractor": "Este edificio solo puede construirse sobre un pozo geotérmico, del cual extraerá fluido puro automáticamente.", "B_Organiser": "Este edificio puede supervisar múltiples rutas de drones e integrarlas en cadenas de producción completas. La columna vertebral de un oleoducto bien organizado.", "B_PathwayHolder": "Esta imponente estructura puede mantener estable un túnel espaciotemporal existente, incluso en el pozo gravitacional de un planeta. Una nave puede viajar a través de dicha ruta con su motor superlumínico convencional.", "B_PowerTransmitter": "Este edificio aprovecha la tecnología de blindaje de vanguardia y la deformación gravitacional del espacio-tiempo para transmitir electricidad sin pérdidas entre diferentes bases en el mismo sistema estelar.", "B_RecyclingPlant": "Este edificio procesa los desechos para extraer sus diversos componentes y prepararlos para su reutilización industrial.", "B_Shipyard": "Esta plataforma permite que una nave se acople a la base para modificar su estructura y reemplazar sus módulos. Es similar a los astilleros de las estaciones espaciales.", "B_ShuttlePad": "Esta plataforma permite que una lanzadera se acople a la base, transportando mercancías dentro y fuera de ella.", "B_Smelter": "Este edificio transforma la mena en bruto en lingotes industriales. Como alternativa automatizada a la fundición manual, puede funcionar de forma continua sin intervención humana, lo que la hace idónea para la producción a gran escala.", "B_SmelterSA": "Meitner & Karls han perfeccionado el proceso de transformación del mineral en lingotes con este microhorno. Más pequeño y rápido que una fundición regular, es el accesorio perfecto para tus días de fabricación manual intensiva.", "B_SolarPanel": "Este edificio convierte la radiación electromagnética en corriente eléctrica, suministrando energía a la red eléctrica de la base. Ocupa espacio y debe estar correctamente orientada, pero funciona sin combustible.", "B_Warehouse": "Este edificio es apto para almacenar materiales sólidos, que pueden ser fácilmente transportados dentro y fuera mediante drones.", "BarrierShield1": "Este módulo de escudo de plasma tiene suficiente carga para proteger una nave espacial de armas ligeras fabricadas por el hombre, pero tarda más en cargarse que los escudos normales.", "Battery": "Un dispositivo capaz de almacenar energía química y convertirla en electricidad. Constituye la base de los RSM de baterías más grandes.", "Battery1": "Este módulo puede almacenar energía química y convertirla fácilmente en corriente eléctrica para alimentar otros módulos RSM.", "Beacon": "Un método experimental de comunicación de alta velocidad. Esta baliza puede revelar instantáneamente su posición mediante una firma cuántica en toda la galaxia, sin importar dónde se encuentre.", "BeaconKey": "Un método experimental de comunicación de alta velocidad. Este dispositivo puede detectar instantáneamente la posición de la baliza con la que está emparejado.", "Beam1": "Una pieza de metal alargada con una sección transversal en forma de H. Se utiliza comúnmente en la construcción para proporcionar resistencia estructural.", "BlastMissile0": "Los explosivos se utilizan con frecuencia en las operaciones mineras para acceder a los minerales protegidos por materiales superficiales densos.", "Blueprint": "Este plano detallado contiene todas las instrucciones necesarias para construir un módulo específico de la nave. Puede ser leído por un ser humano o por una máquina.", "BottlePlasma_Empty": "Un contenedor de plasma magnético resistente, que permite almacenar esta sustancia en bodegas de carga convencionales.", "Bottle_Empty": "Un recipiente rudimentario pero fiable para sustancias líquidas o semifluidas, que permite almacenarlas en las bodegas de carga habituales.", "CalcifiedInvariant": "Las piedras antiguas, bañadas por las energías primordiales del Big Bang, a veces poseen una huella energética que las hace inconfundibles.", "Calcite": "Cristal de carbonato también conocido como alabastro. Principal componente de la piedra caliza y el mármol, es el material de escultura por excelencia.", "Carbon": "Un material esencial en la mayoría de las industrias, ya sea en forma de carbón, diamante o grafito. Además es uno seis únicos elementos químicos presentes en todas las formas de vida conocidas.", "CarbonGenerator": "Este módulo consume combustible a base de carbono para producir corriente eléctrica que alimenta a otros RSM.", "CarbonicFuel": "Un derivado del carbono ultraprocesado, diseñado como una alternativa más eficiente a los combustibles fósiles naturales.", "Cartridge_Iron": "Las armas de proyectiles todavía son muy utilizadas por el Cuerpo de Defensa Universal y para ello desarrolló una serie de estándares para los calibres de los cartuchos.", "Cinnabar": "Un cristal de sulfuro de mercurio, que fue muy utilizado como pigmento por su brillante color rojo, antes de que se reconociera la alta toxicidad o la presencia del mercurio.", "Cockpit_AE1": "La cabina individual del AEgir es aerodinámica para reducir la probabilidad de daños críticos durante los saltos superlumínicos. También incluye una batería pequeña, pero de alta eficiencia.", "Cockpit_AE2": "La espaciosa cabina de mando del Aegir es una maravilla tecnológica, capaz de guardar una ubicación precisa a la que puede regresar en cualquier momento sin usar plasma magnético y sin riesgo de sufrir daños.", "Cockpit_DA1": "La cabina individual de Damona es una proeza de la ingeniería de aislamiento que la hace menos vulnerable a las temperaturas exteriores, pero también ralentiza el enfriamiento por láser. También incluye un pequeño radiador para ayudar a la nave a evacuar el exceso de calor o a generarlo cuando hace frío.", "Cockpit_MK1": "La cabina individual de Meitner & Karls está optimizada para ofrecer espacio de almacenamiento y resistencia a las colisiones, lo que la convierte en la opción perfecta para transportar carga a través de campos de asteroides.", "Cockpit_MK2": "La cabina de mando de Meitner & Karls es lo suficientemente grande como para incluir una fundición a bordo, parecida a las que se construirían en una base terrestre.", "Cockpit_TC1": "La cabina de nivel básico de la Compañía, instalada principalmente en vehículos de prueba.", "Coil": "Un dispositivo sencillo que convierte campos magnéticos en corriente eléctrica, y viceversa.", "Concrete": "Un agregado artificial de minerales unidos por una sustancia química conocida como cemento. El hormigón, utilizado principalmente en la construcción, era el material más fabricado en la Tierra.", "ControlBaseCore": "Este dispositivo puede reclamar el área circundante para la base del usuario y suministrarle energía eléctrica. Su uso está reservado a los asociados autorizados seleccionados por la Compañía.", "ControlBaseKit": "Este dispositivo autónomo puede desplegar una base planetaria en cuestión de segundos. Su uso está reservado a los asociados autorizados seleccionados por la Compañía.", "CopperIngot": "Un material altamente conductor que destaca por su versatilidad. Se presenta en la naturaleza como un metal nativo, pero también se puede encontrar en forma de cristales.", "CorpoCredits": "Estos créditos pertenecen a una corporación, no a un particular.", "CorpoReputation": "A medida que cada corpo completa sus diversas solicitudes, su reputación en toda la galaxia mejora.", "Crystal": "Las piedras preciosas pueden tener diferentes composiciones, aspectos y propiedades. Su rasgo común es un atractivo estético que los hace valiosos para los humanos.", "CrystalLattice_C": "Un cristal tallado con precisión que puede utilizarse en un dispositivo óptico. Su estructura cúbica es la forma cristalina más simple que se encuentra en la naturaleza.", "CrystalLattice_H": "Un cristal tallado con precisión que puede utilizarse en un dispositivo óptico. Su estructura hexagonal es la más común en la naturaleza.", "CrystalLattice_M": "Un cristal tallado con precisión que puede utilizarse en un dispositivo óptico. Su estructura monoclínica es notablemente asimétrica.", "Diamond": "Una forma cristalina de carbono puro. Sigue siendo el material más duro y con mayor conductividad térmica jamás observado.", "Drone0": "Este vehículo autónomo transporta cargas de un punto a otro siguiendo una ruta predefinida.", "Elmerium": "Un material relativamente poco conocido cuyas propiedades electromagnéticas pueden moldear los campos de plasma. Su descubrimiento durante la era de los Planetas Unidos impulsó el desarrollo de los escudos superlumínicos.", "ElmeriumEngine": "Un dispositivo capaz de dispersar un campo de plasma a través de un volumen esférico. Un componente esencial de la mayoría de los modelos Escudo.", "Emerald": "Cristal de la familia del berilo, comercializado como piedra preciosa y valorado por su característico tono verde oscuro.", "EngineBooster": "El módulo de motor auxiliar básico de Luo Ri puede proporcionar una ventaja de velocidad sustancial a los pilotos con presupuesto ajustado.", "Ethanol": "Aunque es bien conocido por sus propiedades recreativas, el etanol es un biocombustible denso y un disolvente útil para las manchas de grasa.", "ExplodingToolMk1": "Módulo utilizado para lanzar una única carga explosiva a un objetivo remoto.", "FTLEngine1": "Considerado como el mayor invento de la era de los Planetas Unidos, esta categoría de módulos puede contraer y expandir el espacio, haciendo posible viajar más rápido que la luz.", "FTLEngine3_Solo": "Considerado como el mayor invento de la era de los Planetas Unidos, esta categoría de módulos puede contraer y expandir el espacio, haciendo posible viajar más rápido que la luz. Este modelo está optimizado para una sola nave.", "FTLEngine3_Support": "Considerado como el mayor invento de la era de los *Planetas Unidos*, esta categoría de módulos puede contraer y expandir el espacio, haciendo posible viajar más rápido que la luz. Este modelo puede transportar varias naves a la vez.", "FTLTank1": "Este módulo de almacenamiento es adecuado para plasma magnético activo. Sus conexiones MACS le permiten suministrar RMS del escudo.", "FToiL": "El descubrimiento de este extraordinario combustible fue lo que hizo posible la invención de los saltos superlumínicos.", "Fertilizer_Neutral": "Un suplemento en polvo que se puede administrar a plantas alienígenas para proporcionarles nutrientes específicos.", "FluidPumpingTool1": "Un módulo diseñado para recoger todo tipo de fluidos presentes en el ambiente mediante una potente succión.", "Focuser": "Un dispositivo óptico para concentrar la radiación a través de cristales pulidos.", "Graphene": "Un material compuesto por átomos de carbono entrelazados. Su inigualable fuerza de tracción lo convierte en una solución óptima cuando la ligereza y la solidez son esenciales.", "Graphenoid": "Una estructura de grafeno que exhibe efectos moleculares cuánticos, esenciales para que los motores superlumínicos de alta gama puedan alcanzar masa negativa.", "GraphiteCrystal": "Un cristal compuesto por múltiples capas de grafeno. Aunque podría describirse como un diamante sin pulir, es lo suficientemente barato como para utilizarse en lápices.", "Grating": "Un dispositivo óptico que descompone la luz en un espectro de frecuencias.", "GraviteDetector": "Este detector especializado puede localizar piedras de gravita con precisión. Se diferencia en gran medida de otros detectores, que pueden localizar prácticamente todo excepto la gravita.", "Gunpowder": "Compuesto químico que deflagra al calentarse.", "Heater": "Un calentador se utiliza para combatir el frío intenso del exterior, transformando la energía eléctrica en calor puro.", "Hematite": "Óxido de hierro cristalino, útil como blindaje contra la radiación debido a su alta densidad. También destaca por su conductividad eléctrica.", "HullMK1_004": "Las naves espaciales se componen de tres capas principales: una capa exterior antivacío, hecha de material resistente; un esqueleto interno estructuralmente sólido formado por vigas pesadas; y los sistemas internos que mantienen la nave habitable y en funcionamiento.", "IronIngot": "Un material estrechamente relacionado con la llegada de la civilización humana. Ampliamente utilizado en la industria, es uno de los elementos más abundantes en los planetas terrestres.", "Kaolinite": "Un tipo de mineral de silicato muy común, ampliamente utilizado en la producción de papel y pintura y que se encuentra a menudo en capas de arcilla. Es seguro ingerirlo en pequeñas cantidades, y también es un ingrediente común en la pasta de dientes.", "KineticShield1": "Mediante un par de bobinas de Tesla, este módulo genera una burbuja de plasma cargado que puede proteger una nave espacial de la radiación y las partículas.", "Levinium": "Un material metálico descubierto recientemente, que destaca por su extraordinaria ligereza. Sus propiedades y casos de uso son aún relativamente desconocidos.", "LicensePoints": "Estos puntos, que regulan el acceso a las licencias industriales, son emitidos por la Agencia Universal de Licencias de la República.", "Light_01": "Una buena luz, utilizada para abrir un camino de visión en la oscuridad.", "Lime": "Un componente mineral que se utiliza comúnmente en el cemento y el hormigón. Se obtiene mediante la carbonatación de la piedra caliza y está compuesta principalmente de óxidos de calcio.", "LiquidStorage1": "Este módulo de almacenamiento es adecuado para materiales líquidos o semifluidos. Sus conexiones MACS le permiten suministrar otros RSM si contiene combustible o líquido refrigerante.", "MagSheet": "Una chapa de elmerio polarizada magnéticamente, comúnmente utilizada para las capas internas de los tanques de plasma magnético.", "MagneticChamber": "Un dispositivo que permite que la corriente de plasma fluya en movimiento circular a alta velocidad sin desviarse de su trayectoria.", "MalachiteStone": "Cristal de carbonato rico en cobre y utilizado como adorno funerario desde el Antiguo Egipto hasta la Mesoamérica maya.", "Mercury": "El mercurio es el único metal conocido que se encuentra en estado líquido a temperatura ambiente. Se amalgama con muchos otros metales y es altamente tóxico para los seres humanos.", "MetalBolt": "Un dispositivo sencillo que utiliza la fuerza de torsión para unir componentes.", "MetalSheet1": "Una chapa de metal procesada industrialmente, por lo general utilizada como material básico de construcción.", "MicroChip": "Un dispositivo electrónico que ejecuta programas informáticos mediante una serie de operaciones matemáticas sencillas. También conocido como \"unidad central de procesamiento\".", "MiningTool1": "Este módulo óptico amplifica la luz hasta una intensidad capaz de vaporizar muchos materiales. Actualmente es la forma más precisa de cortar cosas.", "MiningTool_Cold": "Este chorro de gas licuado a alta presión ofrece una alternativa a los rayos láser, con el efecto contrario sobre la temperatura del objetivo. Ambos pueden utilizarse en combinación.", "MissileAirframe_Small": "Una carcasa metálica y una estructura de propulsión capaces de transportar una ojiva explosiva.", "ModuleCasing1": "Un estándar universal que sirve de base para todos los \"módulos de nave Reliant\". El RSM se ancla a su nave asociada mediante imanes electropermanentes B-Switch.", "Motor": "Un dispositivo que convierte la energía eléctrica en movimiento, y viceversa.", "Navigator": "Este módulo utiliza algoritmos complejos y coordenadas espaciales precisas para ayudar al contratista distraído a planificar una ruta a través de las estrellas.", "P_ColdSuit": "Este accesorio aumenta la capacidad de aislamiento del traje frente a temperaturas bajas. Se pueden utilizar varios chips para aumentar la eficiencia.", "P_ConstructionTool": "La \"síntesis de planos\" libera una nube de nanobots flotantes capaces de reconocer, cortar y ensamblar materiales basándose en un patrón predefinido. En resumen, construye cosas.", "P_DismentlingTool": "Esta herramienta mejorada incluye la función de \"Desintetización de materiales\", capaz de revertir un proceso de construcción finalizado con un daño mínimo a los componentes implicados.", "P_FarmingTool": "Poner a remojo una semilla sucia puede parecer una tarea mundana, pero esta herramienta sublima el arte de colocar una pieza de planta alienígena en germinación en el lugar perfecto para el éxito de su desarrollo.", "P_HeatSuit": "Este accesorio aumenta la capacidad de aislamiento del traje frente a temperaturas altas. Se pueden utilizar varios chips para aumentar la eficiencia.", "P_Jetpack": "[NOTIMPL]", "P_JetpackV2": "[NOTIMPL]", "P_MovingTool": "Esta herramienta mejorada incluye la función de \"Integridad continua\", que permite reubicar un edificio dentro de una base sin necesidad de desmantelarlo antes.", "P_RadSuit": "Este accesorio aumenta la capacidad de aislamiento del traje frente a la radiación. Se pueden utilizar varios chips para aumentar la eficiencia.", "P_ThermoSuit": "Este accesorio aumenta la capacidad de aislamiento térmico del traje frente a temperaturas altas y bajas. Se pueden utilizar varios chips para aumentar la eficiencia.", "PathwayAmmo": "Utilizado con un [PathwayPuncher], este núcleo puede perforar una ruta a cualquier [B_PathwayHolder] disponible. Dicha ruta puede utilizarse para viajar entre dos ubicaciones con un motor superlumínico convencional.", "PathwayPuncher": "Un módulo que perfora un pequeño agujero en el continuo espacio-tiempo. Esto permite el despliegue de un [PathwayAmmo] que excavará una ruta hacia un [B_PathwayHolder] existente.", "Pipe1": "Un dispositivo sencillo para transferir fluidos entre dos puntos.", "Plate1": "Un panel metálico grueso capaz de resistir condiciones climáticas adversas. Se utiliza habitualmente en la construcción de exteriores o en cascos de naves.", "PlatinumIngot": "Un metal noble de valor especialmente elevado. Su notable resistencia a la corrosión lo convierte en un componente industrial muy valorado.", "PressureStorage1": "Este módulo de almacenamiento es adecuado para gases licuados que requieren una presurización extrema. Sus conexiones MACS le permiten suministrar otros RSM si contiene combustible o líquido refrigerante.", "Protein": "Las proteínas, un componente esencial de los organismos vivos, son biomoléculas compuestas por cadenas de aminoácidos.", "Pump": "Un dispositivo para impulsar fluidos a través de tuberías conectadas.", "Pyrite": "Sulfuro de hierro cristalino. Conocida popularmente como el \"oro de los tontos\" por su bajo valor, no obstante es un semiconductor útil y un componente fotovoltaico común.", "Quartz": "Cristal compuesto principalmente de sílice, y un componente importante de muchos objetos astronómicos. Sus numerosas variedades se han comercializado como piedras preciosas desde la antigüedad.", "RBattery0": "Este módulo puede almacenar energía cinética mediante una rueda giratoria para alimentar otros RSM, evitando así las desventajas de las baterías químicas.", "Radar0": "Al emitir de ondas electromagnéticas e interpretar su refracción, este radar puede detectar e identificar objetos metálicos dentro de un perímetro grande.", "Radar_Smart": "Mediante el análisis espectral y la comparación con una base de datos de componentes, este detector puede identificar recursos conocidos a distancia.", "Radar_Sniffer": "Mediante una muestra de un recurso determinado, este detector puede localizar depósitos cercanos que contengan el mismo elemento.", "Radiator": "Este módulo puede liberar grandes cantidades de energía térmica. Se utiliza principalmente para enfriar el interior de una nave espacial dispersando su calor en el espacio.", "Radon": "Un gas radiactivo peligroso que no debe manipularse sin el equipo adecuado.", "Rockwood_DreamwoodFruit": "Se desaconseja totalmente el consumo de esta fruta. Los efectos secundarios pueden incluir: alucinaciones vívidas, paranoia aguda y muerte súbita.", "Rockwood_GlowwoodBark": "Esta corteza oscura y gruesa ha crecido en un entorno radiactivo, pero no parece haber sufrido por ello.", "Rockwood_GlowwoodFruit": "Esta baya brillante está ligeramente tibia al tacto, señal de radiactividad latente.", "Rockwood_Seed": "La madera de roca combina compuestos minerales y orgánicos de una manera inusual. Con frecuencia produce estructuras minerales complejas que rara vez se encuentran en otros lugares de la naturaleza.", "Sandstone": "Roca sedimentaria compuesta principalmente de silicio oxidado. Componente esencial del vidrio, la cerámica y el cemento, es tan abundante que los planetas terrestres también se conocen como \"planetas de silicato\".", "Scanner0": "Este módulo identifica la composición de una muestra mediante espectrometría de masas. Los láseres de minería solo pueden utilizarse en recursos que hayan sido identificados mediante este proceso.", "SeekerMissile0": "Antes del éxodo, los explosivos químicos simples eran un arma común. Existen opciones más destructivas, pero ninguna es tan barata ni tan fácil de producir.", "Semiconductor": "Una página en blanco para un futuro microchip o célula solar.", "Shuttle0": "Este vehículo autónomo transporta cargas dentro y fuera de la base, conectándola con otras bases.", "SiliciumIngot": "Un semiconductor extraordinariamente equilibrado que se utiliza en la mayoría de los dispositivos electrónicos. Este metaloide también se puede encontrar en la arcilla, el vidrio y numerosos tipos de piedra.", "SiliconeGel": "Un semisólido no reactivo y altamente absorbente, utilizado principalmente en química, filtración de agua y refrigeración.", "SilverIngot": "Es el metal más conductor y reflectante de todos. Se puede encontrar en su forma pura de manera natural, y se ha utilizado en numerosos aspectos de la industria humana y el arte durante milenios.", "SolarCell": "Un dispositivo electrónico que convierte las ondas electromagnéticas en electricidad.", "SolarPanel1": "Este módulo convierte la radiación electromagnética en corriente eléctrica para alimentar otros módulos RSM.", "SpaceWheat_FrostPulp": "A pesar de su nombre, esta pulpa es extrañamente tibia, como si no le afectara la temperatura exterior.", "SpaceWheat_PlainPulp": "Esta pulpa es prácticamente insípida, a pesar del nutriente inusual que contiene.", "SpaceWheat_Seed": "La semilla de maíz espacial es un organismo alienígena altamente adaptable. Mejor aún, es una fuente de nutrientes compatibles con la biología humana.", "SpaceWheat_SourPulp": "Esta pulpa ya se ha echado a perder y podría ser una fuente de compuestos fermentados.", "SpaceWheat_WoolyKorn": "Esta cáscara dura y fibrosa debería contener algunas semillas de maíz espacial. Se necesita un molinillo para extraerlas.", "Steel": "Aleación de hierro y carbono, que frecuentemente incorpora cromo para prevenir la oxidación. Su fiabilidad y bajo coste lo convierten en un elemento básico de la mayoría de las industrias.", "SteelCasingMK1": "Un casco modular que recubre un barco o un RSM. Además de limitar la fricción en espacios atmosféricos, la carcasa proporciona protección contra la radiación electromagnética.", "Storage1": "Este módulo de almacenamiento es adecuado para materiales sólidos. Su sistema de estabilización magnética protege la carga de colisiones, independientemente de los movimientos de la nave.", "Sulfur": "Material cristalino, componente químico y fertilizante. Descrito en la Biblia como el azufre del infierno, es uno de los seis únicos elementos químicos presentes en todas las formas de vida conocidas.", "SupportCasing": "Un conjunto estandarizado de cables y tuberías que permite a todos los RSM comunicarse con su nave asociada. Sigue la convención del \"Sistema de circulación de ensamblaje de módulos\" o MACS.", "ThermalIsolant": "Una fibra mineral que atrapa finas capas de aire para ralentizar la conducción térmica. Su nombre evoca el dulce recuerdo de una época en la que todavía existía la lana auténtica.", "ThermalPaste": "Esta pasta semiorgánica es excepcionalmente resistente a los cambios de temperatura. Puede utilizarse para protegerse de condiciones extremas.", "ThermalSheet": "Una chapa de metal procesada industrialmente con una conductividad térmica extraordinariamente baja.", "Thruster0": "Este dispositivo de propulsión eléctrica genera empuje y sustentación a una nave espacial sin necesidad de combustión ni de combustibles no renovables.", "ThrusterAE1": "Este sutil propulsor AEgir se integra profundamente en los sistemas de la nave para alcanzar la cima de la eficiencia energética y la oscuridad inexplorada.", "ThrusterDA1": "La ciencia a menudo lleva a las mentes curiosas más allá de los límites de la seguridad. Con este propulsor, Damona les proporciona una forma de regresar rápidamente al vacío seguro del espacio.", "ThrusterMK1": "Meitner & Karls han diseñado este potente propulsor para hacer frente al calor seco de las expediciones mineras más intensas.", "TitaniumIngot": "Un material comúnmente utilizado en aleaciones por su ligereza, resistencia y biocompatibilidad. También se puede encontrar en la mayoría de los organismos vivos.", "TungstenIngot": "El tungsteno es un metal denso y duro con un punto de fusión excepcionalmente alto, lo que hace que sea difícil de trabajar, pero sus propiedades también lo convierten en un componente fundamental de muchas aleaciones.", "Turquoise": "Gema opaca formada por el contacto de agua meteórica y pórfido de cobre.", "Unbendinium": "Esta misteriosa aleación ha sido fundamental para la logística de los viajes espaciales de la humanidad. Su resistencia a la tracción y su límite elástico no se pueden comparar a ningún otro metal conocido por el hombre.", "UraniumNugget": "Material radiactivo peligroso que no debe manipularse sin el equipo adecuado.", "VanadiumIngot": "Un material comúnmente utilizado en aleaciones de acero. También se puede encontrar como toxina en diversos organismos vivos.", "Vitriol": "El ácido sulfúrico es una de las sustancias industriales más utilizadas. Existen muchas maneras de producir este componente, e incluso más maneras de utilizarlo.", "Water": "Al ser un disolvente extraordinariamente neutro con una fuerte polaridad y un pequeño tamaño molecular, el agua es esencial para todas las formas de vida conocidas y la mayoría de las industrias conocidas.", "Water_Brine": "Las grandes masas de agua abiertas al cielo están contaminadas con muchos compuestos y necesitan ser tratadas antes de utilizarse en aplicaciones químicas.", "Wire": "Un dispositivo sencillo para transmitir corriente eléctrica entre dos puntos.", "XenicOil": "El aceite xénico, un hidrocarburo orgánico extraído de semillas alienígenas, es un lubricante útil y un combustible mediocre.", "ZirconiumIngot": "Un material extraordinariamente resistente a la corrosión y a las altas temperaturas. También es capaz de almacenar energía radiactiva con una pérdida mínima."}, "fr": map[schema.GDID]string{"ActivatedCoal": "Du carbone sous une forme poreuse aux propriétés absorbantes remarquables. Largement utilisé pour filtrer des gaz et fluides.", "Actuator": "Un dispositif qui transforme la pression des fluides en mouvements précis et contrôlés.", "Alternator": "Un dispositif capable de produire un puissant effet Hall, ce qui permet aux propulseurs ioniques d'accélérer leur propergol.", "AluK": "Un alliage d'aluminium léger et doté d'une excellente isolation thermique.", "AluminiumIngot": "Un matériau de faible densité à la conductibilité élevée. Bien qu'il soit très abondant, on en trouve rarement à l'état pur dans la nature.", "Antimatter_Empty": "Un contenant permettant de stocker des antiparticules. L'antimatière est notoirement difficile à produire, et encore plus à conserver.", "Aquamarine": "Un cristal de la famille des béryls vendu comme pierre précieuse et apprécié pour sa couleur bleu clair caractéristique.", "AutoBoostModule": "Ce petit composant informatique renforce le contrôle des propulseurs. Appuyez sur [key.Booster] pour activer ou désactiver l'accélération.", "AutoMineModule": "Ce petit composant informatique renforce le contrôle du laser d'extraction. Appuyez sur [key.Mine] pour activer ou désactiver la compétence d'extraction.", "AzuriteStone": "Un cristal de carbonate principalement constitué de cuivre et souvent utilisé comme pigment à travers l'Histoire.", "BTitanium": "Un alliage de titane et de vanadium apprécié pour sa formabilité remarquable, qui en fait un excellent matériau pour la soudure.", "B_AntimatterSynthPH": "Ce bâtiment consomme de grandes quantités d'électricité pour produire des quantités infimes d'antimatière, ce qui relève tout de même de l'exploit.", "B_Battery": "Ce bâtiment stocke de l'énergie chimique lorsque le réseau électrique est en surproduction. Il permet ensuite de la reconvertir en électricité lors des pics de consommation.", "B_BottlingPlant": "Ce bâtiment permet de conditionner des produits liquides ou semi-fluides dans des contenants normalisés.", "B_Chemical": "Ce bâtiment combine des éléments chimiques pour produire des composés industriels. Il peut fonctionner en continu sans intervention humaine, ce qui le rend très utile pour toute production à grande échelle.", "B_Chest": "Cette petite boîte permet à tous les membres de la même corpo que son propriétaire de déposer des cadeaux ou d'en prendre.", "B_Cistern": "Ce bâtiment convient au stockage de matériaux liquides et semi-fluides.", "B_ControlBase": "Ce bâtiment central fournit le stockage, l'électricité et les systèmes administratifs essentiels au fonctionnement d'une petite base planétaire. En termes juridiques, le déploiement d'une base permet de revendiquer la zone où elle se trouve et ses gisements. Le centre est également équipé d'une fonderie manuelle et de machines de fabrication rudimentaires.", "B_ControlBase2": "Ce bâtiment permet à une base de s'étendre sur une zone de terrain de niveau\u00a02 et ainsi de doubler sa capacité d'encombrement et de débloquer les seuils d'expérience jusqu'à 800\u00a0points.", "B_ControlBase3PH": "Ce bâtiment permet à une base de s'étendre sur une zone de terrain de niveau\u00a03 et ainsi de doubler sa capacité d'encombrement et de débloquer les seuils d'expérience jusqu'à 2000\u00a0points.", "B_ControlBase_Corpo1": "Toute corporation légale digne de ce nom a besoin d'un endroit où centraliser ses opérations. Ce bâtiment augmente la taille maximale d'une base de la corporation et contient des machines de fabrication, une salle de conférence et un vaste espace personnalisable.", "B_Crystaliser": "Ce bâtiment utilise des solutions chimiques pour générer des cristaux à une vitesse nettement plus élevée que le procédé naturel.", "B_ElectricPillar": "Cette structure permet de supporter des câbles électriques et de relier des bâtiments au réseau électrique de la base. Pour y raccorder un câble, visez le haut du pylône et appuyez sur E.", "B_Extractor": "Ce bâtiment ne peut être assemblé que sur un gisement de ressources, qu'il pourra automatiquement forer afin d'en extraire du minerai brut.", "B_FTLCistern": "Ce bâtiment permet de conserver du mag-plasma actif.", "B_Factory1": "Ce bâtiment assemble des ressources de base pour produire des composés industriels. Il s'agit d'une alternative automatisée à l'atelier manuel. Il peut fonctionner en continu sans intervention humaine, ce qui le rend très utile pour toute production à grande échelle.", "B_Factory2": "Les plus gros éléments des vaisseaux ne peuvent être construits que dans une grande usine dédiée qui consomme énormément d'énergie.", "B_Farm": "Ce bâtiment fournit un environnement adapté à la culture d'organismes vivants.", "B_Generator": "Ce bâtiment consomme un combustible carbonique pour produire du courant électrique afin d'alimenter le réseau de la base. Il est efficace et compact, mais gourmand en ressources.", "B_LaboPH": "Ce bâtiment contient un laboratoire Ninmah compact, qui contient tout le nécessaire pour analyser des substances exotiques.", "B_LandingPad": "Cette plateforme permet de stationner un vaisseau dans la base et de le relier à un système de distribution de carburant ou d'autres fluides.", "B_LiquidExtractor": "Ce bâtiment peut uniquement être construit au-dessus d'un bassin géothermique dont il extrait automatiquement le fluide pur.", "B_Organiser": "Ce bâtiment permet de gérer plusieurs itinéraires de drones et de les combiner pour créer de véritables chaînes de production. C'est le pilier de toute entreprise industrielle bien rodée.", "B_PathwayHolder": "Cette structure imposante permet de stabiliser un tunnel spatiotemporel, même dans le puits gravitationnel d'une planète. Les vaisseaux dotés d'un réacteur supraluminique peuvent emprunter ces couloirs.", "B_PowerTransmitter": "Ce bâtiment se sert d'une technologie de bouclier de pointe et de la déformation gravitationnelle de l'espace-temps pour alimenter en électricité, sans déperdition, les différentes bases de son système stellaire.", "B_RecyclingPlant": "Ce bâtiment traite rebuts et débris pour en extraire divers composants et les préparer à être réutilisés.", "B_Shipyard": "Cette plateforme permet de stationner un vaisseau dans la base pour modifier sa structure ou remplacer ses modules. Elle est semblable aux chantiers spatiaux des stations spatiales.", "B_ShuttlePad": "Cette plateforme permet de stationner une navette dans la base pour le transport de marchandises.", "B_Smelter": "Ce bâtiment convertit des minéraux bruts en lingots industriels. Il s'agit d'une alternative à la fonderie manuelle. Il peut fonctionner en continu sans intervention humaine, ce qui le rend très utile pour toute production à grande échelle.", "B_SmelterSA": "Meitner\u00a0&\u00a0Karls ont optimisé le processus de transformation de minerai en lingots avec ce micro-fourneau. Plus petit et plus rapide qu'une fonderie normale, c'est l'accessoire idéal pour les périodes de fabrication intenses.", "B_SolarPanel": "Ce bâtiment convertit les rayonnements électromagnétiques en courant électrique afin d'alimenter le réseau de la base. Il nécessite de la place et doit être orienté correctement, mais il fonctionne sans combustible.", "B_Warehouse": "Ce bâtiment permet de stocker des matériaux solides, qui peuvent aisément être déplacés par drone.", "BarrierShield1": "Ce module de bouclier plasma est assez puissant pour protéger un vaisseau des armes de fabrication humaine légères, mais son chargement est plus long que celui des boucliers ordinaires.", "Battery": "Un dispositif permettant de stocker de l'énergie chimique et de la convertir en électricité. Il s'agit de la base des MVD aux batteries plus imposantes.", "Battery1": "Ce module stocke de l'énergie chimique, qu'il convertit en courant électrique afin d'alimenter d'autres MVD.", "Beacon": "Une méthode expérimentale de communication à grande vitesse. Cette balise peut instantanément dévoiler sa position à une signature quantique, où qu'elle se trouve dans la galaxie.", "BeaconKey": "Une méthode expérimentale de communication à grande vitesse. Ce dispositif peut instantanément localiser la balise à laquelle il est associé.", "Beam1": "Une longue pièce métallique à la section transversale en forme de H. Elle est communément utilisée dans le secteur du bâtiment afin de fournir une résistance structurelle.", "BlastMissile0": "Lors des opérations d'extraction, des explosifs sont souvent utilisés pour accéder à des minéraux protégés par d'épaisses surfaces.", "Blueprint": "Ce plan détaillé contient toutes les instructions nécessaires à la construction d'un module de vaisseau précis. Il peut être lu par un être humain ou une machine.", "BottlePlasma_Empty": "Un contenant robuste destiné au mag-plasma et permettant de stocker cette substance dans toutes les soutes.", "Bottle_Empty": "Un contenant rudimentaire, mais fiable permettant de conserver des substances liquides ou semi-fluides et de les stocker dans une soute.", "CalcifiedInvariant": "Certaines pierres antiques, baignées des énergies primordiales du Big Bang, présentent parfois des signatures énergétiques singulières.", "Calcite": "Un cristal de carbonate également connu sous le nom d'albâtre. Principal composant du calcaire et du marbre, c'est le matériau idéal pour la sculpture.", "Carbon": "Un matériau essentiel dans la plupart des industries, aussi bien sous forme de charbon que de diamant ou de graphite. C'est également l'un des six éléments chimiques qui se retrouvent dans toutes les formes de vie connues.", "CarbonGenerator": "Ce module consomme un combustible carbonique pour produire du courant électrique afin d'alimenter les autres MDV.", "CarbonicFuel": "Un dérivé de carbone ultra-transformé conçu comme alternative plus efficace aux combustibles fossiles naturels.", "Cartridge_Iron": "Les armes à projectiles sont encore largement utilisées par le Contingent de Défense Universelle, qui a créé toutes sortes de normes pour le calibre des cartouches.", "Cinnabar": "Ce cristal de sulfure de mercure était très utilisé comme pigment en raison de sa couleur rouge vif, avant que l'on découvre que le mercure était hautement toxique.", "Cockpit_AE1": "Avec ses lignes épurées, le cockpit individuel d'AEgir est conçu pour atténuer les risques de dégâts critiques lors des sauts supraluminiques. Il est également équipé d'une petite batterie hautement efficace.", "Cockpit_AE2": "Le cockpit de grande taille d'AEgir est un véritable bijou de technologie. Il peut garder en mémoire un emplacement précis et y revenir à tout moment sans consommer de mag-plasma ni subir de dégâts.", "Cockpit_DA1": "Le cockpit individuel de Damona est un petit bijou d'ingénierie en matière d'isolation. Moins vulnérable aux températures extérieures, il ralentit cependant le refroidissement des lasers. Il est également équipé d'un petit radiateur qui permet au vaisseau d'évacuer le trop-plein de chaleur ou d'en générer quand les températures chutent.", "Cockpit_MK1": "Le cockpit individuel de Meitner\u00a0&\u00a0Karls est optimisé pour le stockage et la résistance aux collisions. C'est le choix idéal pour le transport de marchandises à travers des champs d'astéroïdes.", "Cockpit_MK2": "Le cockpit de grande taille de Meitner\u00a0&\u00a0Karls peut accueillir une fonderie embarquée semblable à celles que vous pouvez construire dans une base.", "Cockpit_TC1": "Le cockpit d'entrée de gamme de la Compagnie. Il est surtout utilisé dans les appareils  destinés aux tests.", "Coil": "Un dispositif simple permettant de convertir les champs magnétiques en courant électrique, et inversement.", "Concrete": "Un agrégat artificiel de minéraux fixés ensemble par une substance chimique appelée ciment. Il est principalement utilisé dans le secteur du bâtiment, et il s'agissait du matériau produit en plus grande quantité sur Terre.", "ControlBaseCore": "Ce dispositif permet de revendiquer les alentours de la base de son utilisateur et de les alimenter en électricité. Son utilisation est réservée aux auxiliaires ayant reçu l'autorisation de la Compagnie.", "ControlBaseKit": "Ce dispositif autonome permet de déployer une base planétaire en quelques secondes. Son utilisation est réservée aux auxiliaires ayant reçu l'autorisation de la Compagnie.", "CopperIngot": "Un matériau hautement conducteur qui offre une grande polyvalence. C'est un métal natif que l'on peut trouver dans la nature, mais aussi dans les cristaux.", "CorpoCredits": "Ces crédits sont partagés par les membres d'une corpo.", "CorpoReputation": "À mesure qu'une corpo accomplit des contrats, sa réputation s'améliore dans la galaxie.", "Crystal": "Les gemmes peuvent présenter différents aspects, compositions et propriétés. Leur point commun est leur attrait esthétique qui les rend précieuses aux yeux des humains.", "CrystalLattice_C": "Un cristal découpé avec précision et qui peut être utilisé dans un dispositif optique. Sa structure cubique est la forme de cristal la plus simple que l'on puisse trouver dans la nature.", "CrystalLattice_H": "Un cristal découpé avec précision et qui peut être utilisé dans un dispositif optique. Sa structure hexagonale est la plus commune dans la nature.", "CrystalLattice_M": "Un cristal découpé avec précision et qui peut être utilisé dans un dispositif optique. Sa structure monoclinique est d'une asymétrie remarquable.", "Diamond": "Une forme cristalline du carbone pur. Il reste le matériau le plus dur et le meilleur conducteur thermique jamais observé.", "Drone0": "Ce véhicule autonome transporte des charges d'un point\u00a0A à un point\u00a0B en suivant un itinéraire prédéfini.", "Elmerium": "Un matériau dont on sait encore peu de choses. Ses propriétés électromagnétiques permettent de façonner des champs de plasma. Sa découverte au cours de l'ère des Planètes-Unies a été à l'origine du développement des boucliers supraluminiques.", "ElmeriumEngine": "Un dispositif permettant de disperser un champ de plasma sous forme de sphère. C'est un composant essentiel de la plupart des modèles de bouclier.", "Emerald": "Un cristal de la famille des béryls, vendu comme pierre précieuse et apprécié pour sa couleur vert foncé caractéristique.", "EngineBooster": "Le module de moteur auxiliaire d'entrée de gamme de Luo\u00a0Ri. Il offre un avantage de vitesse non négligeable aux pilotes au budget limité.", "Ethanol": "Très connu pour ses propriétés récréatives, l'éthanol est également un biocarburant concentré et un solvant pratique pour éliminer les taches d'huile.", "ExplodingToolMk1": "Ce module permet d'envoyer une charge explosive vers une cible éloignée.", "FTLEngine1": "Considérée comme la plus grande invention de l'ère des Planètes-Unies, cette catégorie de modules permet de contracter et d'étendre l'espace, ce qui rend le voyage supraluminique possible.", "FTLEngine3_Solo": "Considérée comme la plus grande invention de l'ère des Planètes-Unies, cette catégorie de modules permet de contracter et d'étendre l'espace, ce qui rend le voyage supraluminique possible. Ce modèle est optimisé pour un seul vaisseau.", "FTLEngine3_Support": "Considérée comme la plus grande invention de l'ère des Planètes-Unies, cette catégorie de modules permet de contracter et d'étendre l'espace, ce qui rend le voyage supraluminique possible. Ce modèle peut prendre en charge plusieurs vaisseaux à la fois.", "FTLTank1": "Ce module de stockage permet de conserver du mag-plasma actif. Ses raccordements SCAM lui permettent d'alimenter les MVD de bouclier.", "FToiL": "La découverte de ce carburant remarquable a permis l'invention des sauts supraluminiques.", "Fertilizer_Neutral": "Un complément en poudre à administrer aux xénoplantes afin de leur fournir des nutriments spécifiques.", "FluidPumpingTool1": "Ce module est conçu pour recueillir toutes sortes de fluides présents dans l'environnement grâce à son aspiration puissante.", "Focuser": "Un dispositif optique qui concentre les rayonnements à travers des cristaux polis.", "Graphene": "Un matériau composé d'atomes de carbone imbriqués les uns dans les autres. Grâce à sa résistance à la traction inégalée, il constitue une solution idéale quand solidité et légèreté sont de mise.", "Graphenoid": "Une structure en graphène présentant des effets moléculaires quantiques. Indispensable pour permettre aux réacteurs supraluminiques d'atteindre une masse négative.", "GraphiteCrystal": "Un cristal constitué de plusieurs couches de graphène. Bien qu'on puisse le qualifier de diamant inachevé, il est assez bon marché pour servir à faire des crayons.", "Grating": "Un dispositif optique qui décompose la lumière en spectre de fréquences.", "GraviteDetector": "Ce détecteur spécialisé permet de localiser la gravite avec précision. Il est très différent des autres détecteurs, qui permettent de localiser à peu près tout, sauf la gravite.", "Gunpowder": "Un composé chimique qui explose lorsqu'il est chauffé.", "Heater": "Les chauffages permettent d'affronter les environnements glaciaux en transformant l'électricité en chaleur brute.", "Hematite": "Un oxyde de fer cristallin capable de protéger des radiations grâce à sa densité élevée. Ce minéral conduit également l'électricité.", "HullMK1_004": "Les vaisseaux spatiaux sont constitués de trois couches principales\u00a0: une couche externe résistante au vide, constituée d'un matériau solide, un châssis solide constitué de lourdes poutrelles, et des systèmes internes qui permettent au vaisseau de rester habitable et fonctionnel.", "IronIngot": "Un matériau étroitement associé aux progrès de la civilisation humaine. Cet élément, très largement utilisé dans l'industrie, est l'un des plus abondants sur les planètes telluriques.", "Kaolinite": "Ce type de silicate très répandu, largement utilisé dans la fabrication de papier et de peinture, se trouve souvent dans les nodules d'argile. Il peut être ingéré en petite quantité, ce qui en fait un ingrédient courant des dentifrices.", "KineticShield1": "Grâce à ses deux bobines Tesla, ce module génère une bulle de plasma chargé permettant de protéger un vaisseau des rayonnements et particules.", "Levinium": "Un matériau métallique récemment découvert et à la légèreté remarquable. Ses propriétés et cas d'usage sont encore méconnus.", "LicensePoints": "Ces points régulent l'accès aux licences industrielles. Ils sont distribués par l'Agence d'accréditation universelle de la République.", "Light_01": "Un bon éclairage qui permet d'illuminer les ténèbres.", "Lime": "Un composant minéral communément utilisé dans le ciment et le béton. Obtenu en carbonatant de la pierre à chaux, il est principalement composé d'oxydes de calcium.", "LiquidStorage1": "Ce module de stockage convient aux matériaux liquides ou semi-fluides. Ses raccordements SCAM lui permettent d'alimenter d'autres MVD s'il contient du carburant ou du liquide de refroidissement.", "MagSheet": "Une plaque d'elmérium à polarisation magnétique, communément utilisée comme revêtement intérieur dans les réservoirs de mag-plasma.", "MagneticChamber": "Un dispositif permettant à un courant de plasma de s'écouler à haute vitesse dans un mouvement circulaire, sans quitter sa trajectoire.", "MalachiteStone": "Un cristal de carbonate principalement constitué de cuivre et utilisé comme ornement funéraire en Égypte antique et par les Mayas d'Amérique centrale.", "Mercury": "Le mercure est le seul métal connu qui soit liquide à température ambiante. Il s'amalgame à de nombreux autres métaux et est très toxique pour les humains.", "MetalBolt": "Un dispositif simple qui emploie la force de torsion pour fixer des composants.", "MetalSheet1": "Une plaque de métal de facture industrielle, communément utilisée comme matériau de construction de base.", "MicroChip": "Un dispositif électronique permettant d'exécuter des programmes informatiques via une série d'opérations mathématiques élémentaires. On l'appelle également «\u00a0processeur\u00a0».", "MiningTool1": "Ce module optique amplifie la lumière à une intensité telle qu'elle peut désintégrer la plupart des matériaux. Il n'existe pas actuellement de méthode de découpe plus précise.", "MiningTool_Cold": "Ce flux de gaz liquéfié à haute pression offre une alternative aux rayons laser\u00a0: il a l'effet opposé sur la température de la cible. Les deux lasers peuvent être utilisés ensemble.", "MissileAirframe_Small": "Une enveloppe métallique dotée d'une structure de propulsion et conçue pour contenir une ogive explosive.", "ModuleCasing1": "La norme universelle qui sert de base à tous les «\u00a0modules de vaisseau dépendants\u00a0» (MVD). Ce kit permet de fixer un MVD à un vaisseau grâce à des électroaimants permanents à interrupteur\u00a0B.", "Motor": "Un dispositif permettant de convertir l'énergie électrique en mouvement, et inversement.", "Navigator": "Ce module utilise des algorithmes complexes et des coordonnées spatiales précises afin de permettre aux auxiliaires les plus distraits de prévoir leur itinéraire à travers les étoiles.", "P_ColdSuit": "Cet accessoire augmente la capacité isolante d'une combinaison face aux températures basses. Plusieurs puces peuvent être appliquées à la fois pour accroître leur efficacité.", "P_ConstructionTool": "La «\u00a0synthèse de plan\u00a0» libère un nuage de nanorobots capables de reconnaître, découper et assembler des matériaux selon un modèle prédéfini. Pour résumer, elle permet de construire des objets.", "P_DismentlingTool": "Cet outil amélioré inclut la fonctionnalité «\u00a0déconstruction de matière\u00a0», qui permet d'inverser un procédé de construction achevé en causant des dégâts minimes aux composants utilisés.", "P_FarmingTool": "Faire tremper une graine sale peut sembler une tâche banale, mais cet outil sublime l'art de mettre un germe de xénoplante à l'endroit idéal pour assurer sa croissance.", "P_HeatSuit": "Cet accessoire augmente la capacité isolante d'une combinaison face aux températures élevées. Plusieurs puces peuvent être appliquées à la fois pour accroître leur efficacité.", "P_Jetpack": "[NOTIMPL]", "P_JetpackV2": "[NOTIMPL]", "P_MovingTool": "Cet outil amélioré inclut la fonctionnalité «\u00a0intégrité continue\u00a0», qui permet de déplacer un bâtiment au sein d'une base sans le démanteler au préalable.", "P_RadSuit": "Cet accessoire augmente la capacité isolante d'une combinaison face aux radiations. Plusieurs puces peuvent être appliquées à la fois pour accroître leur efficacité.", "P_ThermoSuit": "Cet accessoire augmente la capacité isolante d'une combinaison face aux températures basses et élevées. Plusieurs puces peuvent être appliquées à la fois pour accroître leur efficacité.", "PathwayAmmo": "Combiné à un [PathwayPuncher], ce noyau permet d'ouvrir un couloir vers n'importe quel [B_PathwayHolder] disponible. Ce couloir vous permettra de voyager entre deux points à l'aide d'un réacteur supraluminique.", "PathwayPuncher": "Ce module peut percer un petit trou dans le continuum espace-temps, ce qui permet de déployer un [PathwayAmmo] et d'ouvrir un couloir vers un [B_PathwayHolder] existant.", "Pipe1": "Un dispositif simple permettant d'acheminer un fluide entre deux points.", "Plate1": "Un épais panneau de métal qui peut résister aux conditions météorologiques les plus rudes. Il est communément utilisé dans la construction de bâtiments ou de fuselages.", "PlatinumIngot": "Un métal noble de très grande valeur. En raison de sa résistance remarquable à la corrosion, il s'agit d'un composant industriel prisé.", "PressureStorage1": "Ce module de stockage convient aux gaz liquides qui nécessitent une mise sous pression extrême. Ses raccordements SCAM lui permettent d'alimenter d'autres MVD s'il contient du carburant ou du liquide de refroidissement.", "Protein": "Composant essentiel des organismes vivants, les protéines sont des biomolécules qui renferment des chaînes d'acides aminés.", "Pump": "Un dispositif permettant de propulser des fluides dans des tuyaux reliés.", "Pyrite": "Une forme cristalline du disulfure de fer. Appelée «\u00a0or des fous\u00a0» en raison de sa faible valeur, elle reste malgré tout un semi-conducteur utile et un composant photovoltaïque répandu.", "Quartz": "Un cristal principalement constitué de silice, et l'un des composants principaux de nombreux corps astronomiques. Ses nombreuses variétés ont été vendues comme pierres fines depuis l'Antiquité.", "RBattery0": "Ce module permet de stocker de l'énergie cinétique à l'aide d'une roue en rotation afin d'alimenter d'autres MVD tout en évitant les désavantages des batteries chimiques.", "Radar0": "Ce radar émet des ondes électromagnétiques et interprète leur réfraction pour détecter et identifier les objets métalliques dans un large périmètre.", "Radar_Smart": "Ce détecteur compare une analyse spectrale à une base de composants pour identifier les ressources connues à distance.", "Radar_Sniffer": "Ce détecteur peut utiliser un échantillon d'une ressource déterminée pour localiser les gisements proches contenant le même élément.", "Radiator": "Ce module peut libérer de grandes quantités d'énergie thermique. Il est principalement utilisé pour refroidir l'intérieur d'un vaisseau en dispersant sa chaleur dans l'espace.", "Radon": "Ce gaz radioactif dangereux ne doit pas être manipulé sans équipement adéquat.", "Rockwood_DreamwoodFruit": "La consommation de ce fruit est fortement découragée. Effets secondaires possibles\u00a0: hallucinations, paranoïa aiguë, mort subite.", "Rockwood_GlowwoodBark": "Cette écorce sombre et rugueuse vient d'un environnement radioactif, mais elle ne semble pas avoir été affectée.", "Rockwood_GlowwoodFruit": "Ce fruit brillant dégage une douce chaleur, signe d'une radioactivité latente.", "Rockwood_Seed": "Le lithobois combine des composés minéraux et organiques de façon inhabituelle. Il peut produire des structures minérales complexes que l'on trouve rarement ailleurs dans la nature.", "Sandstone": "Une roche sédimentaire principalement constituée de silicone oxydé. Ce composant du verre, de la céramique et du ciment est si abondant que les planètes telluriques sont aussi connues sous le nom de «\u00a0planètes silicatées\u00a0».", "Scanner0": "Ce module emploie la spectrométrie de masse pour identifier la composition d'un échantillon. Les lasers d'extraction ne peuvent être utilisés que sur les ressources ainsi identifiées.", "SeekerMissile0": "Avant l'exode, les explosifs chimiques simples étaient des armes répandues. Il existe des options plus destructrices, mais aucune n'est aussi simple à produire et bon marché.", "Semiconductor": "Une page blanche prête à accueillir une future micropuce ou une cellule photovoltaïque.", "Shuttle0": "Ce véhicule autonome transporte différentes cargaisons entre les bases.", "SiliciumIngot": "Un semi-conducteur remarquablement équilibré utilisé dans la plupart des appareils électroniques. Ce métalloïde se trouve également dans l'argile, le verre et de nombreux autres types de pierres.", "SiliconeGel": "Un composant semi-solide hautement absorbant et non réactif, notamment utilisé en chimie, pour la filtration de l'eau et le refroidissement.", "SilverIngot": "Le métal le plus réfléchissant et le plus conducteur. On le trouve à l'état pur dans la nature, et il est utilisé dans de nombreux aspects de l'industrie et de l'art humains depuis des millénaires.", "SolarCell": "Un dispositif électronique qui convertit les ondes électromagnétiques en électricité.", "SolarPanel1": "Ce module convertit les rayonnements électromagnétiques en courant électrique afin d'alimenter les autres MVD.", "SpaceWheat_FrostPulp": "Malgré son nom, cette pulpe est étonnamment tiède, comme si les températures extérieures ne l'affectaient pas.", "SpaceWheat_PlainPulp": "Cette pulpe n'a presque aucun goût malgré ses nutriments inhabituels.", "SpaceWheat_Seed": "L'astrengrain est un organisme extraterrestre très polyvalent. Mieux encore\u00a0: c'est une source de nutriments compatible avec la biologie humaine.", "SpaceWheat_SourPulp": "Cette pulpe a déjà tourné et pourrait représenter une source de composés fermentés.", "SpaceWheat_WoolyKorn": "Cette enveloppe fibreuse dure devrait contenir quelques graines d'astrengrain. Une meule est nécessaire pour les en extraire.", "Steel": "Un alliage de fer et de carbone, auquel l'on ajoute fréquemment du chrome afin de prévenir l'oxydation. C'est un matériau incontournable pour la plupart des industries en raison de sa fiabilité et de son faible coût.", "SteelCasingMK1": "Un carter modulaire destiné à recouvrir un vaisseau ou un MVD. En plus de limiter la friction dans les espaces atmosphériques, ce carter offre une protection contre les rayonnements électromagnétiques.", "Storage1": "Ce module de stockage convient aux matériaux solides. Son système de stabilisation magnétique protège son contenu des collisions lorsque le vaisseau est en mouvement.", "Sulfur": "Un cristal, composant chimique et engrais. Mentionné plusieurs fois dans la Bible, il s'agit de l'un des six éléments chimiques qui se retrouvent dans toutes les formes de vie connues.", "SupportCasing": "Un ensemble de câbles et tuyaux normalisés permettant de relier tous les MVD à leur vaisseau. Ils sont conformes à la norme SCAM («\u00a0système circulatoire d'assemblage de modules\u00a0»).", "ThermalIsolant": "Une fibre minérale qui piège de fines couches d'air et ralentit ainsi la conduction thermique. Son nom évoque le doux souvenir d'un temps où la véritable laine existait encore.", "ThermalPaste": "Une pâte semi-organique exceptionnellement résistante aux changements de température. Elle peut servir de protection face à des conditions extrêmes.", "ThermalSheet": "Une plaque de métal de facture industrielle à la conductibilité thermique remarquablement faible.", "Thruster0": "Ce dispositif de propulsion électrique permet de pousser et d'élever un vaisseau sans consommer de combustible ou de carburant non renouvelable.", "ThrusterAE1": "Ce propulseur subtil d'AEgir s'intègre en profondeur au système du vaisseau pour atteindre des sommets en matière d'efficacité énergétique au cœur des ténèbres inexplorées.", "ThrusterDA1": "La science entraîne souvent les esprits curieux dans des situations périlleuses. Grâce à ce propulseur, Damona leur permet de retourner rapidement dans le vide sans danger de l'espace.", "ThrusterMK1": "Meitner\u00a0&\u00a0Karls ont conçu ce propulseur puissant pour résister à la chaleur sèche des expéditions minières les plus intenses.", "TitaniumIngot": "Un matériau communément utilisé dans les alliages pour sa légèreté, sa résistance et sa biocompatibilité. Il est aussi possible d'en trouver dans la plupart des organismes vivants.", "TungstenIngot": "Le tungstène est un métal dur et lourd avec un point de fusion exceptionnellement élevé. Il est difficile à travailler, mais ses propriétés en font un composant essentiel de nombreux alliages.", "Turquoise": "Une pierre fine opaque formée par le contact entre de l'eau météorique et du porphyre cuprifère.", "Unbendinium": "Cet alliage mystérieux s'est révélé essentiel à l'humanité pour le voyage spatial. Sa résistance à la traction et sa limite d'élasticité sont inégalées parmi tous les métaux connus.", "UraniumNugget": "Cette matière radioactive dangereuse ne doit pas être manipulée sans équipement adéquat.", "VanadiumIngot": "Un matériau communément utilisé dans les alliages d'acier. C'est également une toxine que l'on trouve dans de nombreux organismes vivants.", "Vitriol": "L'acide sulfurique est l'une des substances industrielles les plus répandues. Il existe de nombreux moyens de le produire, et encore plus de l'utiliser.", "Water": "Un solvant d'une neutralité remarquable doté d'une polarité élevée et d'une taille moléculaire réduite. L'eau est indispensable à toutes les formes de vie connues, ainsi qu'à la plupart des industries.", "Water_Brine": "À ciel ouvert, les vastes étendues d'eau sont exposées à la contamination de nombreux composés. Elles doivent être traitées avant de servir à toute opération chimique.", "Wire": "Un dispositif simple permettant d'acheminer un courant électrique entre deux points.", "XenicOil": "L'huile xénique est un hydrocarbure organique extrait de xénograines. C'est un bon lubrifiant, mais un carburant médiocre.", "ZirconiumIngot": "Un matériau doté d'une résistance remarquable à la corrosion et aux températures élevées. Il permet également de stocker de l'énergie radioactive en limitant les pertes."}, "pl": map[schema.GDID]string{"ActivatedCoal": "Porowata forma węgla o wyjątkowych właściwościach adsorpcyjnych. Powszechnie stosowany do filtracji gazów i cieczy.", "Actuator": "Urządzenie, które zmienia ciśnienie płynu w precyzyjne, kontrolowane ruchy.", "Alternator": "Urządzenie zdolne do wytwarzania silnego efektu Halla. Umożliwia silnikom jonowym przyspieszanie materiału napędowego.", "AluK": "Stop aluminium o niskiej masie i doskonałych właściwościach izolacji termicznej.", "AluminiumIngot": "Materiał wyróżniający się bardzo niską gęstością i wysoką przewodnością. Choć jest powszechny, rzadko występuje w naturze w czystej postaci.", "Antimatter_Empty": "Pojemnik do przechowywania antycząstek. Antymateria jest niezwykle trudna do wytworzenia, a jeszcze trudniejsza do przechowywania.", "Aquamarine": "Kryształ z rodziny beryli. Wykorzystywany jako kamień szlachetny i ceniony za swoją charakterystyczną jasnoniebieską barwę.", "AutoBoostModule": "Ten niewielki komputer poprawia kontrolę nad silnikami sterującymi: naciśnij [key.Booster], by włączyć dopalacz.", "AutoMineModule": "Ten niewielki komputer poprawia kontrolę nad laserem górniczym: naciśnij [key.Mine], by włączyć umiejętność wydobywania.", "AzuriteStone": "Węglanowy kryształ złożony głównie z miedzi. Od wieków wykorzystywany jako pigment.", "BTitanium": "Stop tytanu i wanadu. Ceniony za wyjątkową podatność na formowanie, co czyni go doskonałym materiałem do spawania.", "B_AntimatterSynthPH": "Ten budynek zużywa ogromne ilości energii elektrycznej, aby wytwarzać śladowe ilości antymaterii, co i tak jest imponujące.", "B_Battery": "Ten budynek magazynuje energię chemiczną, gdy sieć energetyczna produkuje nadwyżki energii. Może ją następnie szybko przekształcić z powrotem w prąd elektryczny w momentach zwiększonego zapotrzebowania.", "B_BottlingPlant": "Ten budynek pakuje płynne lub półpłynne produkty do standaryzowanych pojemników.", "B_Chemical": "Ten budynek łączy pierwiastki chemiczne w związki przemysłowe. Może działać nieprzerwanie bez udziału człowieka, co czyni go odpowiednim do produkcji na dużą skalę.", "B_Chest": "To małe pudełko umożliwia wszystkim osobom z tej samej korporacji zostawiać i odbierać prezenty.", "B_Cistern": "Ten budynek służy do przechowywania materiałów płynnych lub półpłynnych.", "B_ControlBase": "Ten centralny budynek zapewnia podstawowe magazynowanie, zasilanie elektryczne oraz systemy administracyjne niezbędne do funkcjonowania małej bazy lądowej. Rozlokowanie bazy stanowi formalne roszczenie do obszaru oraz złóż, nad którymi zostaje rozlokowana. Budynek wyposażony jest również w podstawowe ręczne urządzenia do przetapiania i wytwarzania.", "B_ControlBase2": "Ten budynek umożliwia rozszerzenie bazy na obszar lądowy poziomu 2, podwajając jej maksymalny zasięg oraz odblokowując progi doświadczenia do 800 punktów.", "B_ControlBase3PH": "Ten budynek umożliwia rozszerzenie bazy na obszar lądowy poziomu 3, podwajając jej maksymalny zasięg oraz odblokowując progi doświadczenia do 2000 punktów.", "B_ControlBase_Corpo1": "Legalnie działająca korporacja o dużym zasięgu czasami wymaga miejsca do prowadzenia scentralizowanych operacji. Ten budynek zwiększa maksymalny rozmiar pojedynczej bazy korporacji i dysponuje maszynami wytwórczymi, pomieszczeniem konferencyjnym oraz przestrzenią do zagospodarowania.", "B_Crystaliser": "Ten budynek wykorzystuje roztwory chemiczne do tworzenia kryształów w niezwykle szybkim tempie w porównaniu z ich naturalnym procesem powstawania.", "B_ElectricPillar": "Ten słup może podtrzymywać przewody elektryczne i łączyć sieć energetyczną bazy z innym budynkiem. Aby podłączyć do niego kabel, wyceluj w szczyt pylonu i naciśnij E.", "B_Extractor": "Ten budynek można zbudować wyłącznie na złożu surowców, w które następnie będzie się wwiercał, wydobywając automatycznie rudę.", "B_FTLCistern": "Ten budynek służy do przechowywania aktywnej mag-plazmy.", "B_Factory1": "Ten budynek przetwarza podstawowe surowce w związki przemysłowe. Jako zautomatyzowana alternatywa dla warsztatu ręcznego może działać nieprzerwanie bez udziału człowieka, co czyni go odpowiednim do produkcji na dużą skalę.", "B_Factory2": "Największe materiały statku można stworzyć wyłącznie w specjalnej wielkiej fabryce, która wymaga dużych zapasów mocy.", "B_Farm": "Ten budynek zapewnia odpowiednie warunki do hodowli organizmów żywych.", "B_Generator": "Ten budynek zużywa paliwo na bazie węgla do wytwarzania prądu elektrycznego, zasilając sieć energetyczną bazy. Jest wydajny i kompaktowy, ale wymaga dużych nakładów surowców.", "B_LaboPH": "Ten budynek zawiera kompaktowe laboratorium Ninmah, które dysponuje osprzętem do analizy egzotycznych substancji.", "B_LandingPad": "Ta platforma umożliwia statkowi dokowanie do bazy i połączenie z jej systemem dystrybucji w celu transferu paliwa lub innych płynów.", "B_LiquidExtractor": "Ten budynek można wznieść wyłącznie nad basenem geotermalnym, z którego automatycznie zacznie wydobywać czysty płyn.", "B_Organiser": "Ten budynek może monitorować wiele tras dronów i łączyć je w pełnoprawne łańcuchy produkcyjne. Fundament dobrze zorganizowanej logistyki.", "B_PathwayHolder": "Ta potężna konstrukcja jest w stanie utrzymać stabilność istniejącego tunelu czasoprzestrzennego nawet w polu grawitacyjnym planety. Statek może się przemieszczać przez taki korytarz tranzytowy, korzystając ze standardowego napędu nadświetlnego.", "B_PowerTransmitter": "Ten budynek wykorzystuje najnowszą technologię tarcz oraz grawitacyjną deformację czasoprzestrzeni do bezstratnego wysyłania elektryczności między bazami w tym samym układzie słonecznym.", "B_RecyclingPlant": "Ten budynek przetwarza odpady, aby odzyskać ich różne komponenty i przygotować do ponownego wykorzystania w przemyśle.", "B_Shipyard": "Ta platforma umożliwia statkowi dokowanie do bazy w celu modyfikacji konstrukcji i wymiany modułów. Działa podobnie jak stocznie na stacjach kosmicznych.", "B_ShuttlePad": "Ta platforma umożliwia wahadłowcowi dokowanie do bazy oraz transport towarów w obie strony.", "B_Smelter": "Ten budynek przetwarza surową rudę w przemysłowe sztabki. Jako zautomatyzowana alternatywa dla ręcznej huty może działać nieprzerwanie bez udziału człowieka, co czyni go odpowiednim do produkcji na dużą skalę.", "B_SmelterSA": "Firma Meitner & Karl dopracowała metodę przerabiania rudy na sztabki w tym mikropiecu. Jest mniejszy i szybszy niż typowa huta, więc to idealny sprzęt na długi, ciężki dzień ręcznego wytwarzania przedmiotów.", "B_SolarPanel": "Ten budynek przekształca promieniowanie elektromagnetyczne w prąd elektryczny, zasilając sieć energetyczną bazy. Zajmuje miejsce i musi być odpowiednio ustawiony, ale działa bez paliwa.", "B_Warehouse": "Ten budynek służy do przechowywania materiałów stałych, które łatwo mogą być transportowane przez drony.", "BarrierShield1": "Ten moduł osłony plazmowej ma wystarczający ładunek, aby chronić statek kosmiczny przed lekką bronią stworzoną przez człowieka, ale ładuje się wolniej niż standardowe osłony.", "Battery": "Urządzenie, które może magazynować energię chemiczną i przekształcać ją w elektryczność. Stanowi podstawę większych akumulatorowych ZMS.", "Battery1": "Ten moduł może magazynować energię chemiczną i łatwo przekształcać ją w prąd elektryczny do zasilania innych ZMS.", "Beacon": "Eksperymentalna metoda komunikacji o wysokiej prędkości. Ta boja może natychmiast ujawnić swoją pozycję sygnaturze kwantowej w całej galaktyce, niezależnie od miejsca, w którym się znajduje.", "BeaconKey": "Eksperymentalna metoda komunikacji o wysokiej prędkości. To urządzenie może natychmiast odczytać pozycję powiązanej z nim boi.", "Beam1": "Wydłużony element metalowy o przekroju w kształcie litery H. Powszechnie stosowany w budownictwie do zapewnienia wytrzymałości konstrukcyjnej.", "BlastMissile0": "Materiały wybuchowe są często wykorzystywane w operacjach wydobywczych do uzyskania dostępu do minerałów chronionych przez twarde warstwy powierzchniowe.", "Blueprint": "Ten szczegółowy plan zawiera wszystkie niezbędne instrukcje do budowy konkretnego modułu statku. Może go odczytać człowiek lub maszyna.", "BottlePlasma_Empty": "Wytrzymały pojemnik na mag-plazmę, który umożliwia przechowywanie substancji w standardowych ładowniach.", "Bottle_Empty": "Prosty, ale niezawodny pojemnik na substancje ciekłe lub półpłynne, który umożliwia przechowywanie ich w standardowych ładowniach.", "CalcifiedInvariant": "Starożytne kamienie, skąpane w pierwotnej energii Wielkiego Wybuchu, czasem posiadają sygnaturę energetyczną, która czyni je wyjątkowo rozpoznawalnymi.", "Calcite": "Węglanowy kryształ znany również jako alabaster. Jako główny składnik wapienia i marmuru stanowi doskonały materiał rzeźbiarski.", "Carbon": "Materiał niezbędny w większości gałęzi przemysłu niezależnie od tego, czy występuje w postaci węgla, diamentu, czy grafitu. Jest też jednym z zaledwie sześciu pierwiastków chemicznych występujących we wszystkich znanych formach życia.", "CarbonGenerator": "Ten moduł zużywa paliwo na bazie węgla, aby wytwarzać prąd elektryczny do zasilania innych ZMS.", "CarbonicFuel": "Wysoko przetworzona pochodna węgla. Opracowana jako bardziej wydajna alternatywa dla naturalnych paliw kopalnych.", "Cartridge_Iron": "Broń pociskowa wciąż jest używana przez Korpus Obrony Powszechnej, który wykorzystuje szereg standardów dla różnokalibrowych magazynków.", "Cinnabar": "Skrystalizowany siarczek rtęci. Zanim odkryto wysoką toksyczność rtęci, wykorzystywano go jako pigment ze względu na jasnoczerwony kolor.", "Cockpit_AE1": "Indywidualny kokpit Aegir ma opływowy kształt, który zmniejsza ryzyko krytycznych uszkodzeń podczas skoków nadświetlnych. Wyposażono go też w niewielką, ale bardzo wydajną baterię zasilającą.", "Cockpit_AE2": "Duży kokpit Aegir to cud techniki: potrafi zapisać dokładną lokalizację, do której może powrócić skokiem w każdej chwili bez zużycia mag-plazmy i ryzyka uszkodzeń.", "Cockpit_DA1": "Indywidualny kokpit Damona to majstersztyk inżynierii izolacyjnej, który zmniejsza jego podatność na temperatury zewnętrzne, ale jednocześnie spowalnia chłodzenie laserowe. Wyposażony jest także w mały radiator, który pomaga statkowi odprowadzać nadmiar ciepła lub wytwarzać je w niskich temperaturach.", "Cockpit_MK1": "Indywidualny kokpit Meitner & Karl został zoptymalizowany pod kątem przestrzeni ładunkowej i odporności na kolizje, co czyni go idealnym wyborem do transportu towarów przez pola asteroid.", "Cockpit_MK2": "Duży kokpit Meitner & Karl jest na tyle przestronny, że może pomieścić pokładową hutę podobną do tych, które buduje się w bazie naziemnej.", "Cockpit_TC1": "Podstawowy kokpit Firmy. Montowany głównie w pojazdach testowych.", "Coil": "Proste urządzenie przekształcające pola magnetyczne w prąd elektryczny i odwrotnie.", "Concrete": "Sztuczna mieszanina minerałów spajanych substancją chemiczną zwaną cementem. Wykorzystywany głównie w budownictwie. Był najczęściej produkowanym materiałem na Ziemi.", "ControlBaseCore": "To urządzenie przejmuje kontrolę nad otaczającym terenem na potrzeby bazy użytkownika oraz zasila ją w energię elektryczną. Jego użycie jest zarezerwowane dla autoryzowanych współpracowników wybranych przez Firmę.", "ControlBaseKit": "To autonomiczne urządzenie potrafi rozlokować bazę planetarną w ciągu kilku sekund. Jego użycie jest zarezerwowane dla autoryzowanych współpracowników wybranych przez Firmę.", "CopperIngot": "Materiał o wysokiej przewodności. Ceniony za swoją wszechstronność. Występuje w naturze jako metal rodzimy, ale można go też znaleźć w postaci kryształów.", "CorpoCredits": "Te kredyty należą do korporacji, a nie do jednostki.", "CorpoReputation": "Wraz z realizacją kolejnych zleceń przez daną korporację jej reputacja w galaktyce rośnie.", "Crystal": "Kamienie szlachetne mogą mieć różny skład, wygląd i właściwości. Łączy je estetyczna atrakcyjność, która czyni je cennymi dla ludzi.", "CrystalLattice_C": "Precyzyjnie oszlifowany kryształ, który może być używany w urządzeniach optycznych. Jego struktura sześcienna jest najprostszą formą kryształu występującą w naturze.", "CrystalLattice_H": "Precyzyjnie oszlifowany kryształ, który może być używany w urządzeniach optycznych. Jego struktura heksagonalna jest najczęściej spotykaną w naturze.", "CrystalLattice_M": "Precyzyjnie oszlifowany kryształ, który można używać w urządzeniach optycznych. Jego struktura monoklinalna jest wyjątkowo asymetryczna.", "Diamond": "Krystaliczna forma czystego węgla. To wciąż najtwardszy i najlepiej przewodzący ciepło materiał, jaki kiedykolwiek odkryto.", "Drone0": "Ten autonomiczny pojazd transportuje ładunki z jednego punktu do drugiego po wyznaczonej trasie.", "Elmerium": "Stosunkowo słabo poznany materiał, którego właściwości elektromagnetyczne pozwalają kształtować pola plazmy. Jego odkrycie w erze Zjednoczonych Planet zapoczątkowało rozwój osłon nadświetlnych.", "ElmeriumEngine": "Urządzenie zdolne do rozpraszania pola plazmy w przestrzeni kulistej. Kluczowy element większości modeli osłon.", "Emerald": "Kryształ z rodziny beryli. Wykorzystywany jako kamień szlachetny i ceniony za swoją charakterystyczną ciemnozieloną barwę.", "EngineBooster": "Podstawowy moduł pomocniczego silnika od Luo Ri. Zapewnia znaczną przewagę prędkości pilotom z ograniczonym budżetem.", "Ethanol": "Choć etanol jest znany głównie z właściwości rekreacyjnych, sprawdza się też jako biopaliwo i przydatny rozpuszczalnik do tłustych plam.", "ExplodingToolMk1": "Moduł używany do uderzania ładunkiem wybuchowym w oddalone cele.", "FTLEngine1": "Uznawany za największy wynalazek ery Zjednoczonych Planet. Ten typ modułów potrafi kurczyć i rozszerzać przestrzeń, umożliwiając podróże nadświetlne.", "FTLEngine3_Solo": "Uznawany za największy wynalazek ery Zjednoczonych Planet. Ten typ modułów potrafi kurczyć i rozszerzać przestrzeń, umożliwiając podróże nadświetlne. Ten model jest zoptymalizowany dla pojedynczego statku.", "FTLEngine3_Support": "Uznawany za największy wynalazek ery Zjednoczonych Planet. Ten typ modułów potrafi kurczyć i rozszerzać przestrzeń, umożliwiając podróże nadświetlne. Ten model może transportować jednocześnie kilka statków.", "FTLTank1": "Ten moduł magazynowy jest przystosowany do aktywnej mag-plazmy. Jego złącza MACS umożliwiają zasilanie osłon ZMS.", "FToiL": "Odkrycie tego niezwykłego paliwa umożliwiło opracowanie skoków nadświetlnych.", "Fertilizer_Neutral": "Sproszkowany suplement, który można podać obcym roślinom, by zapewnić im określone składniki odżywcze.", "FluidPumpingTool1": "Moduł zaprojektowany z myślą o zbieraniu różnego rodzaju cieczy obecnych w środowisku dzięki potężnej mocy ssącej.", "Focuser": "Urządzenie optyczne służące do skupiania promieniowania za pomocą wypolerowanych kryształów.", "Graphene": "Materiał złożony z powiązanych atomów węgla. Jego niezrównana wytrzymałość na rozciąganie czyni go idealnym rozwiązaniem tam, gdzie lekkość musi iść w parze z wytrzymałością.", "Graphenoid": "Struktura grafenowa wykazująca kwantowe efekty molekularne. Niezbędna dla umożliwienia zaawansowanym silnikom nadświetlnym osiągnięcia ujemnej masy.", "GraphiteCrystal": "Kryształ złożony z wielu warstw grafenu. Choć można go opisać jako niedokończony diament, jest na tyle tani, że używa się go w ołówkach.", "Grating": "Urządzenie optyczne, które rozbija światło na spektrum częstotliwości.", "GraviteDetector": "Ten wyspecjalizowany detektor potrafi z dużą precyzją lokalizować kamienie grawitu. Znacznie różni się od innych detektorów, które potrafią wykrywać praktycznie wszystko poza grawitem.", "Gunpowder": "Związek chemiczny, który ulega gwałtownemu spalaniu przy podgrzaniu.", "Heater": "Grzejnik służy do usuwania skutków niskich temperatur, które panują na zewnątrz, poprzez przekształcanie energii elektrycznej w\u00a0cieplną.", "Hematite": "Krystaliczny tlenek żelaza. Przydatny do osłon przed promieniowaniem ze względu na wysoką gęstość. Jest również znany z przewodnictwa elektrycznego.", "HullMK1_004": "Statki kosmiczne składają się z trzech głównych warstw: zewnętrznego poszycia wykonanego z materiału odpornego na działanie próżni, wewnętrznego szkieletu zbudowanego z ciężkich dźwigarów oraz systemów umożliwiających funkcjonowanie statku i załogi.", "IronIngot": "Materiał ściśle związany z rozwojem ludzkiej cywilizacji. Szeroko wykorzystywany w przemyśle. Jest jednym z najpowszechniejszych pierwiastków na planetach typu ziemskiego.", "Kaolinite": "Bardzo powszechny minerał krzemianowy. Szeroko stosowany w produkcji papieru, farb i nierzadko wyrobów ceramicznych. Bezpieczny do spożycia w małych ilościach, więc jest częstym składnikiem pasty do zębów.", "KineticShield1": "Wykorzystując parę cewek Tesli, moduł ten generuje bańkę naładowanej plazmy, która może chronić statek kosmiczny przed promieniowaniem i cząstkami.", "Levinium": "Niedawno odkryty materiał metaliczny, który wyróżnia się niezwykłą lekkością. Jego właściwości i zastosowania wciąż nie są do końca poznane.", "LicensePoints": "Regulują dostęp do licencji przemysłowych i są przyznawane przez Powszechną Agencję Licencyjną Republiki.", "Light_01": "Dobre światło, które pozwalało na otwarcie drogi w ciemności.", "Lime": "Składnik mineralny powszechnie stosowany w cemencie i betonie. Otrzymywane przez karbonatyzację wapienia składa się głównie z tlenków wapnia.", "LiquidStorage1": "Ten moduł magazynowy jest przeznaczony do materiałów ciekłych lub półpłynnych. Jego złącza MACS umożliwiają zasilanie innych modułów ZMS, jeśli ładownia zawiera paliwo lub płyn chłodzący.", "MagSheet": "Magnetycznie spolaryzowana płyta z elmerium. Powszechnie stosowana w wewnętrznych powłokach zbiorników mag-plazmy.", "MagneticChamber": "Urządzenie umożliwiające przepływ prądu plazmy w szybkim ruchu kołowym bez utraty trajektorii.", "MalachiteStone": "Węglanowy kryształ złożony głównie z miedzi. Używany jako ozdoba funeralna, począwszy od starożytnego Egiptu, a skończywszy na cywilizacji Majów w Mezoameryce.", "Mercury": "Rtęć to jedyny znany metal, który w temperaturze pokojowej ma formę płynną. Łatwo miesza się z innymi metalami i jest wysoce toksyczny dla ludzi.", "MetalBolt": "Proste urządzenie wykorzystujące siłę skręcającą do łączenia elementów.", "MetalSheet1": "Przemysłowo przetworzona płaska płyta metalu. Powszechnie stosowana jako podstawowy materiał konstrukcyjny.", "MicroChip": "Urządzenie elektroniczne wykonujące programy komputerowe poprzez serię prostych operacji matematycznych. Znane również jako „jednostka centralna”.", "MiningTool1": "Ten moduł optyczny wzmacnia światło do natężenia zdolnego odparować wiele materiałów. Obecnie jest to najdokładniejszy sposób cięcia.", "MiningTool_Cold": "Ten strumień skroplonego gazu pod wysokim ciśnieniem stanowi alternatywę dla wiązek laserowych, wywołując odwrotny efekt temperaturowy na celu. Obu rozwiązań można używać razem.", "MissileAirframe_Small": "Metalowa obudowa i struktura napędowa zdolna do przenoszenia ładunku wybuchowego.", "ModuleCasing1": "Uniwersalny standard stanowiący podstawę dla wszystkich zależnych modułów statków. Mocuje ZMS do przypisanego statku za pomocą elektropermanentnych magnesów B-Switch.", "Motor": "Urządzenie przekształcające energię elektryczną w ruch i odwrotnie.", "Navigator": "Ten moduł wykorzystuje złożone algorytmy i precyzyjne współrzędne przestrzenne, by pomagać nieuważnym wykonawcom wytyczyć drogę pośród gwiazd.", "P_ColdSuit": "Ten dodatek zwiększa zdolność skafandra do izolacji przed niskimi temperaturami. Można stosować wiele modułów, aby zwiększyć skuteczność.", "P_ConstructionTool": "„Synteza schematu” uwalnia chmurę unoszących się nanobotów, które potrafią rozpoznawać, ciąć i składać materiały według zdefiniowanego schematu. W skrócie: buduje rzeczy.", "P_DismentlingTool": "To ulepszone narzędzie zawiera funkcję „Desyntezy materiału”, która pozwala odwrócić proces budowy przy minimalnych uszkodzeniach komponentów.", "P_FarmingTool": "Zasadzenie brudnego nasiona do wyrośnięcia może się wydawać banalną czynnością, ale to narzędzie wynosi sztukę umiejscowienia kiełków obcych roślin na wyższy poziom, by zapewnić sukces całej operacji.", "P_HeatSuit": "Ten dodatek zwiększa zdolność skafandra do izolacji przed wysokimi temperaturami. Można stosować wiele modułów, aby zwiększyć skuteczność.", "P_Jetpack": "[NOTIMPL]", "P_JetpackV2": "[NOTIMPL]", "P_MovingTool": "To ulepszone narzędzie zawiera funkcję „Ciągłej integralności”, która pozwala przenosić budowle w obrębie bazy bez konieczności ich wcześniejszego demontażu.", "P_RadSuit": "Ten dodatek zwiększa zdolność skafandra do izolacji przed promieniowaniem. Można stosować wiele modułów, aby zwiększyć skuteczność.", "P_ThermoSuit": "Ten dodatek zwiększa zdolność skafandra do izolacji zarówno przed wysokimi, jak i niskimi temperaturami. Można stosować wiele modułów, aby zwiększyć skuteczność.", "PathwayAmmo": "W połączeniu z: [PathwayPuncher] ziarno to może stworzyć nowy korytarz tranzytowy do dowolnego dostępnego: [B_PathwayHolder]. Taki korytarz umożliwia następnie przemieszczanie się między dwoma lokalizacjami przy użyciu standardowego napędu nadświetlnego.", "PathwayPuncher": "Moduł, który przebija niewielki otwór w\u00a0kontinuum czasoprzestrzennym. Umożliwia to rozmieszczenie: [PathwayAmmo] w celu stworzenia korytarza tranzytowego do\u00a0istniejącego: [B_PathwayHolder].", "Pipe1": "Proste urządzenie przemieszczające płyny między dwoma punktami.", "Plate1": "Gruba metalowa płyta odporna na trudne warunki atmosferyczne. Powszechnie stosowana w konstrukcjach zewnętrznych lub kadłubach statków.", "PlatinumIngot": "Metal szlachetny o szczególnie wysokiej wartości. Jego wyjątkowa odporność na korozję czyni go cenionym składnikiem przemysłowym.", "PressureStorage1": "Ten moduł magazynowy jest przeznaczony do gazów w stanie ciekłym, które wymagają ekstremalnego ciśnienia. Jego złącza MACS umożliwiają zasilanie innych modułów ZMS, jeśli ładownia zawiera paliwo lub płyn chłodzący.", "Protein": "Podstawowy składnik organizmów żywych. Białka to biomolekuły zbudowane z łańcuchów aminokwasów.", "Pump": "Urządzenie tłoczące płyny przez połączone rury.", "Pyrite": "Krystaliczny siarczek żelaza. Choć na tyle tani, że nazwano go „złotem głupców”, jest użytecznym półprzewodnikiem i powszechnym składnikiem ogniw fotowoltaicznych.", "Quartz": "Kryształ złożony głównie z krzemionki będącej istotnym składnikiem wielu obiektów astronomicznych. Jego liczne odmiany są przedmiotem handlu jako kamienie szlachetne już od starożytności.", "RBattery0": "Ten moduł może magazynować energię kinetyczną za pomocą wirującego koła, zasilając inne ZMS i jednocześnie unikając wad baterii chemicznych.", "Radar0": "Emitując fale elektromagnetyczne i analizując ich załamanie, radar ten może wykrywać i identyfikować metaliczne obiekty w dużym promieniu.", "Radar_Smart": "Wykorzystując analizę spektralną i porównanie z bazą danych komponentów, ten detektor może identyfikować znane surowce z dużej odległości.", "Radar_Sniffer": "Korzystając z próbki danego surowca, ten detektor może lokalizować pobliskie złoża zawierające ten sam pierwiastek.", "Radiator": "Ten moduł może odprowadzać duże ilości energii cieplnej. Jest głównie używany do chłodzenia wnętrza statku poprzez rozpraszanie ciepła w przestrzeni kosmicznej.", "Radon": "Niebezpieczny, promieniotwórczy gaz, z którym nie należy się obchodzić bez odpowiedniego wyposażenia.", "Rockwood_DreamwoodFruit": "Stanowczo odradza się spożycie tych owoców. Efekty uboczne mogą obejmować: halucynacje, ostre napady paranoi i nagłą śmierć.", "Rockwood_GlowwoodBark": "Ta ciemna, gruba kora pochodzi z\u00a0radioaktywnego środowiska, które nie zdołało jej uszkodzić.", "Rockwood_GlowwoodFruit": "Ta świecąca jagoda jest ciepła w dotyku, co stanowi dowód na jej utajoną radioaktywność.", "Rockwood_Seed": "Skałodrzewo łączy związki mineralne i organiczne w niezwykły sposób. Często tworzy złożone struktury mineralne, rzadko spotykane gdziekolwiek indziej w naturze.", "Sandstone": "Skała osadowa złożona głównie z utlenionego krzemu. Składnik szkła, ceramiki i cementu. Jest tak powszechny, że planety typu ziemskiego nazywane są „planetami krzemianowymi”.", "Scanner0": "Ten moduł identyfikuje skład próbki za pomocą spektrometrii mas. Lasery wydobywcze mogą być używane wyłącznie na surowcach zidentyfikowanych w tym procesie.", "SeekerMissile0": "Przed exodusem chemiczna broń wybuchowa była bardzo powszechna. Istnieją bardziej niszczycielskie opcje, ale nie są tanie ani łatwe w produkcji.", "Semiconductor": "Baza dla przyszłego mikroukładu lub ogniwa słonecznego.", "Shuttle0": "Ten autonomiczny pojazd transportuje ładunki między bazami.", "SiliciumIngot": "Wyjątkowo zrównoważony półprzewodnik stosowany w większości urządzeń elektronicznych. Ten półmetal występuje także w glinie, szkle oraz licznych rodzajach skał.", "SiliconeGel": "Niereaktywny, silnie chłonny półstały materiał. Stosowany szczególnie w chemii, filtracji wody i chłodzeniu.", "SilverIngot": "Najlepiej przewodzący i najbardziej refleksyjny ze wszystkich metali. Występuje naturalnie w czystej postaci. Od tysięcy lat znajduje zastosowanie w wielu dziedzinach przemysłu oraz sztuki.", "SolarCell": "Urządzenie elektroniczne, które przekształca fale elektromagnetyczne w energię elektryczną.", "SolarPanel1": "Ten moduł przekształca promieniowanie elektromagnetyczne w prąd elektryczny do zasilania innych ZMS.", "SpaceWheat_FrostPulp": "Mimo swej nazwy ta pulpa jest dziwnie ciepła, jak gdyby temperatura otoczenia nie miała na nią najmniejszego wpływu.", "SpaceWheat_PlainPulp": "Ta pulpa jest niemal pozbawiona smaku mimo zawartych w niej składników odżywczych.", "SpaceWheat_Seed": "Kosmokłos to wysoce przystosowujący się obcy organizm. Co więcej, stanowi źródło pożywienia zgodnego z ludzką biologią.", "SpaceWheat_SourPulp": "Ta pulpa najwyraźniej się zepsuła i może być źródłem związków fermentacyjnych.", "SpaceWheat_WoolyKorn": "Ta twarda, włóknista skorupa powinna zawierać kilka ziaren kosmokłosu. Do ich wydobycia konieczny jest młynek.", "Steel": "Stop żelaza i węgla, który często zawiera chrom zapobiegający utlenianiu. Jego niezawodność oraz niski koszt sprawiają, że jest podstawą większości gałęzi przemysłu.", "SteelCasingMK1": "Modułowy kadłub osłaniający statek lub ZMS. Oprócz ograniczania tarcia w atmosferze zapewnia ochronę przed promieniowaniem elektromagnetycznym.", "Storage1": "Ten moduł magazynowy jest przeznaczony do materiałów stałych. System stabilizacji magnetycznej chroni ładunek przed uderzeniami niezależnie od ruchów statku.", "Sulfur": "Materiał krystaliczny, składnik chemiczny i nawóz. Opisywana w Biblii jako piekielna siarka. Jest jednym z zaledwie sześciu pierwiastków chemicznych występujących we wszystkich znanych formach życia.", "SupportCasing": "Ustandaryzowany zestaw kabli i rur, który umożliwia komunikację wszystkich ZMS z przypisanym statkiem. Zgodny z konwencją „Modułowa Asemblacja Cyrkulacji Systemu” (MACS).", "ThermalIsolant": "Włókno mineralne, które zatrzymuje cienkie warstwy powietrza w celu spowolnienia przewodzenia ciepła. Jego nazwa przywołuje wspomnienie czasów, gdy prawdziwa wełna jeszcze istniała.", "ThermalPaste": "Tę na wpół organiczną pastę cechuje wyjątkowa odporność na zmiany temperatury. Można ją stosować do zabezpieczania przed ekstremalnymi warunkami klimatycznymi.", "ThermalSheet": "Przemysłowo przetworzona płyta metalu o wyjątkowo niskiej przewodności cieplnej.", "Thruster0": "To elektryczne urządzenie napędowe może zapewniać ciąg i siłę nośną statkowi kosmicznemu bez potrzeby spalania paliwa czy użycia nieodnawialnych źródeł energii.", "ThrusterAE1": "Ten delikatny silnik AEgir w pełni integruje się z systemami statku, by osiągnąć maksymalną efektywność energetyczną i dotrzeć w najdalsze zakątki.", "ThrusterDA1": "Nauka często prowadzi najbystrzejsze umysły poza granice bezpieczeństwa. Damona zapewnia drogę powrotu na bezpieczną pustkę przestrzeni kosmicznej dzięki temu silnikowi.", "ThrusterMK1": "Firma Meitner & Karl zaprojektowała ten potężny silnik, by poradził sobie w gorących oraz suchych warunkach podczas ekstremalnej wyprawy górniczej.", "TitaniumIngot": "Materiał powszechnie stosowany w stopach ze względu na lekkość, wytrzymałość i biokompatybilność. Występuje również w większości organizmów żywych.", "TungstenIngot": "Wolfram to twardy materiał o dużej gęstości i nadzwyczaj wysokiej temperaturze topnienia, co sprawia, że jest trudny w obróbce, ale jednocześnie niezbędny w produkcji wielu stopów.", "Turquoise": "Nieprzezroczysty kamień szlachetny powstały w wyniku oddziaływania meteorytowej wody i porfiru miedziowego.", "Unbendinium": "Ów tajemniczy stop okazał się niezwykle ważny dla ludzkości przy podboju kosmosu. Jest rozciągliwy, a jednocześnie bardziej wytrzymały niż jakikolwiek inny metal znany człowiekowi.", "UraniumNugget": "Niebezpieczny, promieniotwórczy materiał, z którym nie należy się obchodzić bez odpowiedniego wyposażenia.", "VanadiumIngot": "Materiał powszechnie stosowany w stopach stali. Może również występować jako toksyna w wielu organizmach żywych.", "Vitriol": "Kwas siarkowy jest jedną z najczęściej wykorzystywanych substancji przemysłowych. Istnieje wiele sposobów jego wytwarzania i jeszcze więcej zastosowań.", "Water": "Jako wyjątkowo neutralny rozpuszczalnik o silnej polarności i niewielkim rozmiarze cząsteczek, woda jest niezbędna dla wszystkich znanych form życia i większości znanych gałęzi przemysłu.", "Water_Brine": "Duże, otwarte zbiorniki wodne pod gołym niebem są zanieczyszczone wieloma związkami chemicznymi. Wymagają zatem oczyszczenia przed wykorzystaniem w procesach chemicznych.", "Wire": "Proste urządzenie przesyłające prąd elektryczny między dwoma punktami.", "XenicOil": "Olej kseniczny to organiczny węglowodór wydobywany z obcych nasion, który służy jako smar i średniej jakości paliwo.", "ZirconiumIngot": "Materiał wyjątkowo odporny na korozję i wysokie temperatury. Potrafi także magazynować energię promieniotwórczą przy minimalnych stratach."}, "pt-BR": map[schema.GDID]string{"ActivatedCoal": "Uma forma porosa de carbono com excelentes propriedades de adsorção. Amplamente utilizado para filtrar gases e fluidos.", "Actuator": "Um dispositivo que converte pressão de fluido em movimentos precisos e controlados.", "Alternator": "Um dispositivo capaz de produzir um forte efeito Hall, permitindo que propulsores iônicos acelerem seu propelente.", "AluK": "Uma liga de alumínio, com baixo peso e excelente isolamento térmico.", "AluminiumIngot": "Um material conhecido por sua baixíssima densidade e alta condutividade. Embora abundante, quase nunca aparece naturalmente em forma pura.", "Antimatter_Empty": "Um recipiente para conter antipartículas. Muito difícil de produzir, e a antimatéria é ainda mais difícil de armazenar.", "Aquamarine": "Um cristal da família do berilo, comercializado como pedra preciosa e valorizado por sua característica tonalidade azul-clara.", "AutoBoostModule": "Esta pequena peça de computação melhora o controle dos propulsores: toque [key.Booster] para alternar o turbo.", "AutoMineModule": "Esta pequena peça de computação melhora o controle dos lasers de mineração: toque [key.Mine] para alternar a habilidade de mineração.", "AzuriteStone": "Um cristal de carbonato composto principalmente de cobre e muito usado como pigmento ao longo da história humana.", "BTitanium": "Uma liga de titânio e vanádio, valorizada por sua maleabilidade, o que a torna um excelente material para soldagem.", "B_AntimatterSynthPH": "Esta estrutura consome enormes quantidades de eletricidade para produzir pequenas quantidades de antimatéria, o que por si só é incrível.", "B_Battery": "Esta estrutura armazena energia química quando a rede de energia produz um excedente. Em seguida, ela rapidamente converte a energia de volta em eletricidade durante picos de consumo.", "B_BottlingPlant": "Esta estrutura engarrafa produtos líquidos ou semifluidos em contêineres padronizados.", "B_Chemical": "Esta estrutura converte elementos químicos em compostos industriais. Ela funciona continuamente sem ação humana. Isso a torna apropriada para produção em larga escala.", "B_Chest": "Esta pequena caixa permite que qualquer uma da mesma corporação que a controladora da base deixe, ou recolha, presentes.", "B_Cistern": "Esta estrutura armazena materiais líquidos ou semifluidos.", "B_ControlBase": "Esta estrutura central fornece a armazenagem, a energia e os sistemas administrativos básicos necessários para operar uma pequena base terrestre. Posicionar uma base constitui uma reivindicação legal sobre a área e as jazidas nela contidas. Ela também vem com máquinas manuais básicas de fundição e fabricação.", "B_ControlBase2": "Esta estrutura permite expandir a base por uma área de nível 2, o que duplica sua extensão máxima e desbloqueia limiares de experiência de até 800 pontos.", "B_ControlBase3PH": "Esta estrutura permite expandir a base por uma área de nível 3, o que duplica sua extensão máxima e desbloqueia limiares de experiência de até 2000 pontos.", "B_ControlBase_Corpo1": "Uma corporação legalizada de renome normalmente precisa de um local para centralizar suas operações. Essa estrutura aumenta o tamanho máximo de uma base da corporação e conta com máquinas de fabricação, uma sala de conferências e muitos espaços personalizáveis.", "B_Crystaliser": "Esta estrutura usa soluções químicas para gerar cristais em velocidades excepcionalmente velozes, em comparação com o processo natural de formação.", "B_ElectricPillar": "Este poste dá suporte a cabos elétricos e permite conectar a rede elétrica da base a outra estrutura. Para conectar um cabo a ele, mire no topo da torre e aperte E.", "B_Extractor": "Esta estrutura só pode ser montada sobre uma jazida de recursos. Ela perfura a jazida e extrai minério bruto automaticamente.", "B_FTLCistern": "Esta estrutura armazena magnetoplasma ativo.", "B_Factory1": "Esta estrutura transforma recursos básicos em compostos industriais. É uma alternativa automatizada à oficina manual, que pode funcionar continuamente sem ação humana. Isso a torna apropriada para produção em larga escala.", "B_Factory2": "Os componentes maiores de nave só podem ser construídos em uma grande fábrica personalizada que consume muita energia.", "B_Farm": "Esta estrutura fornece um ambiente propício para o cultivo de organismos vivos.", "B_Generator": "Esta estrutura consome combustível a base de carbono para produzir corrente elétrica, que alimenta os sistemas elétricos da base. É eficaz e compacta, mas consome muitos recursos.", "B_LaboPH": "Essa estrutura contém um compacto laboratório do Grupo Ninmah com tudo o que é necessário para analisar substâncias exóticas.", "B_LandingPad": "Esta plataforma permite que uma nave atraque na base e se conecte ao sistema de distribuição para transferir combustível ou outros fluidos.", "B_LiquidExtractor": "Esta estrutura só pode ser montada sobre uma fonte geotérmica, onde ela extrai fluidos puros naturalmente.", "B_Organiser": "Esta estrutura é capaz de monitorar várias rotas de drones e uni-las em verdadeiras cadeias de produção. É a espinha dorsal de uma linha de produção bem organizada.", "B_PathwayHolder": "Essa estrutura pode manter um túnel estável no espaço-tempo, mesmo dentro da esfera de influência gravitacional de um planeta. Uma nave consegue atravessar essas passagens com um motor SVL ordinário.", "B_PowerTransmitter": "Essa estrutura explora tecnologias defensivas de ponta e deformações espaçotemporais gravitacionais para emitir, sem perdas, eletricidade entre bases do mesmo sistema solar.", "B_RecyclingPlant": "Esta estrutura processa restos de materiais e extrai seus componentes, de modo a prepará-los para reutilização.", "B_Shipyard": "Esta plataforma permite atracar uma nave na base para que sua estrutura seja modificada e seus módulos sejam substituídos. Funciona de forma similar a estaleiros de estações espaciais.", "B_ShuttlePad": "Esta plataforma permite que um transporte atraque na base para carregar ou descarregar mercadorias.", "B_Smelter": "Esta estrutura converte minério bruto em lingotes industriais. É uma alternativa automatizada à fundição manual, que pode funcionar continuamente sem ação humana. Isso a torna apropriada para produção em larga escala.", "B_SmelterSA": "Meitner & Karls refinaram o processo de tornar minério em lingotes usando a microfornalha. Menor e mais veloz que uma fundição normal, é o acessório perfeito para os seus dias de fabricação manual intensa.", "B_SolarPanel": "Esta estrutura converte radiação eletromagnética em corrente elétrica, alimentando os sistemas elétricos da base. Ela ocupa espaço e precisa estar na orientação correta, mas não consome combustível.", "B_Warehouse": "Esta estrutura armazena materiais sólidos, que podem ser inseridos ou retirados com facilidade via drones.", "BarrierShield1": "Este módulo de escudo de plasma tem carga suficiente para proteger uma nave contra armas leves feitas por humanos, mas leva mais tempo para carregar do que escudos comuns.", "Battery": "Um dispositivo que pode armazenar energia química e convertê-la em eletricidade. Forma a base de RSMs de bateria maiores.", "Battery1": "Este módulo pode armazenar energia química e convertê-la rapidamente em corrente elétrica para alimentar outros RSMs.", "Beacon": "Um método experimental de comunicação em alta velocidade. Este sinalizador é capaz de revelar instantaneamente a posição para uma assinatura quântica em qualquer lugar da galáxia.", "BeaconKey": "Um método experimental de comunicação em alta velocidade. Este dispositivo é capaz de captar instantaneamente a posição do sinalizador ao qual está vinculado.", "Beam1": "Uma peça metálica alongada com seção transversal em forma de H. Comumente usada na construção para resistência estrutural.", "BlastMissile0": "Explosivos costumam ser usados em operações de mineração para acessar minerais protegidos por materiais de superfície pesados.", "Blueprint": "Este plano detalhado contém todas as instruções necessárias para se fabricar um determinado módulo de nave. Ele pode ser lido por humanos ou por máquinas.", "BottlePlasma_Empty": "Um recipiente resistente para magnetoplasma, tornando possível armazenar essa substância em compartimentos de carga comuns.", "Bottle_Empty": "Um recipiente rudimentar, porém confiável, para substâncias líquidas ou semilíquidas, tornando possível armazená-las em compartimentos de carga comuns.", "CalcifiedInvariant": "Pedras antigas, banhadas pelas energias primordiais do big bang, às vezes possuem uma energia que as torna unicamente identificáveis.", "Calcite": "Um cristal de carbonato também conhecido como alabastro. Como principal componente do calcário e do mármore, é o material ideal para esculturas.", "Carbon": "Um material essencial na maioria das indústrias, seja na forma de carvão, diamante ou grafite. Também é um dos únicos seis elementos químicos encontrados em todas as formas de vida conhecidas.", "CarbonGenerator": "Este módulo consome combustível à base de carbono para produzir corrente elétrica e alimentar outros RSMs.", "CarbonicFuel": "Um derivado de carbono ultraprocessado, projetado como uma alternativa mais eficiente aos combustíveis fósseis naturais.", "Cartridge_Iron": "Armas de projéteis continuam a ser amplamente utilizadas pelo Corpo de Defesa Universal, que desenvolveu um conjunto de padrões para calibres de cartucho.", "Cinnabar": "Um cristal de sulfeto de mercúrio, esse mineral amplamente usado como pigmento, devido à sua intensa tonalidade vermelha, até a alta toxicidade do mercúrio ter sido reconhecida.", "Cockpit_AE1": "A cabine individual da Aegir é aerodinâmica para reduzir a probabilidade de danos críticos durante saltos SVL. Também vem com uma pequena, porém altamente eficiente, bateria de energia.", "Cockpit_AE2": "A cabine de grande porte da Aegir é uma maravilha tecnológica, capaz de salvar uma localização precisa para a qual pode saltar de volta a qualquer momento, sem uso de magnetoplasma e sem risco de danos.", "Cockpit_DA1": "A cabine individual da Damona é um feito de engenharia de isolamento, o que a torna menos vulnerável a temperaturas externas, mas desacelera o resfriamento a laser. Também vem com um pequeno radiador para ajudar a nave a dissipar o excesso de calor ou gerar algum quando estiver frio.", "Cockpit_MK1": "A cabine individual da Meitner & Karls é otimizada para espaço de armazenagem e resistência a colisões, tornando-se a escolha perfeita para transportar cargas por campos de asteroides.", "Cockpit_MK2": "A cabine de grande porte da Meitner & Karls é grande o suficiente para incluir uma fundição integrada, semelhante às que você pode construir em uma base terrestre.", "Cockpit_TC1": "A cabine de entrada d'A Companhia, geralmente equipado em veículos de teste.", "Coil": "Um dispositivo simples que converte campos magnéticos em corrente elétrica e vice-versa.", "Concrete": "Um agregado artificial de minerais mantidos juntos por uma substância química conhecida como cimento. Usado principalmente na construção, o concreto foi o material mais produzido na Terra.", "ControlBaseCore": "Este dispositivo pode reivindicar a área ao redor para a base do usuário e fornecer energia elétrica. Seu uso é reservado a associados autorizados selecionados pel'A Companhia.", "ControlBaseKit": "Este dispositivo autônomo pode implantar uma base planetária em questão de segundos. Seu uso é reservado a associados autorizados selecionados pel'A Companhia.", "CopperIngot": "Um material altamente condutor conhecido por sua versatilidade. Ocorre na natureza como metal nativo, mas também pode ser encontrado em cristais.", "CorpoCredits": "Estes créditos são de propriedade de uma corporação, ao invés de um indivíduo.", "CorpoReputation": "Conforme cada corporação conclui diversos pedidos, a reputação dela pela galáxia aumenta.", "Crystal": "As gemas podem ter diferentes composições, aspectos e propriedades. Sua característica comum é um apelo estético que as torna valiosas para os humanos.", "CrystalLattice_C": "Um cristal lapidado que pode ser usado em um dispositivo óptico. Sua estrutura cúbica é a forma cristalina mais simples encontrada na natureza.", "CrystalLattice_H": "Um cristal lapidado que pode ser usado em um dispositivo óptico. Sua estrutura hexagonal é a mais comum na natureza.", "CrystalLattice_M": "Um cristal lapidado que pode ser usado em um dispositivo óptico. Sua estrutura monoclínica é notavelmente assimétrica.", "Diamond": "Uma forma cristalina de carbono puro. Continua sendo o material mais rígido e com maior condutividade térmica já observado.", "Drone0": "Este veículo autônomo transporta cargas de um ponto a outro ao longo de uma rota predefinida.", "Elmerium": "Um material ainda pouco compreendido, cujas propriedades eletromagnéticas podem moldar campos de plasma. Sua descoberta durante a Era dos Planetas Unidos impulsionou o desenvolvimento de escudos SVL.", "ElmeriumEngine": "Um dispositivo capaz de dispersar um campo de plasma em um volume esférico. Um componente essencial da maioria dos modelos de escudo.", "Emerald": "Um cristal da família do berilo, comercializado como pedra preciosa e valorizado por sua característica tonalidade verde-escura.", "EngineBooster": "O módulo de motor auxiliar de nível básico da Luo Ri dá uma vantagem significativa de velocidade para pilotos com orçamento limitado.", "Ethanol": "Além de suas conhecidas propriedades recreativas, o etanol também é um biocombustível de alta densidade e solvente para manchas de óleo.", "ExplodingToolMk1": "Módulo utilizado para lançar uma única carga explosiva contra um alvo remoto.", "FTLEngine1": "Considerado a maior invenção da Era dos Planetas Unidos, esta categoria de módulos pode contrair e expandir o espaço, tornando possível viajar mais rápido do que a luz.", "FTLEngine3_Solo": "Considerado a maior invenção da Era dos Planetas Unidos, esta categoria de módulos pode contrair e expandir o espaço, tornando possível viajar mais rápido do que a luz. Este modelo é otimizado para uso em uma única nave.", "FTLEngine3_Support": "Considerado a maior invenção da *Era dos Planetas Unidos*, esta categoria de módulos pode contrair e expandir o espaço, tornando possível viajar mais rápido do que a luz. Este modelo pode transportar várias naves ao mesmo tempo.", "FTLTank1": "Este módulo de armazenagem é adequado para magnetoplasma ativo. Suas conexões SCMM permitem abastecer RSMs de escudo.", "FToiL": "A descoberta desse combustível notável foi o que tornou possível a invenção dos saltos SVL.", "Fertilizer_Neutral": "Um suplemento em pó que pode ser ministrado a plantas alienígenas para fornecer nutrientes específicos.", "FluidPumpingTool1": "Um módulo projetado para coletar todo o tipo de fluido presente no ambiente, através de uma poderosa sucção.", "Focuser": "Um dispositivo óptico para concentrar radiação através de cristais polidos.", "Graphene": "Um material composto por átomos de carbono interligados. Sua resistência incomparável à tração o torna uma solução ideal quando leveza e solidez são essenciais.", "Graphenoid": "Uma estrutura de grafeno que apresenta efeitos moleculares quânticos, essencial para a capacidade de motores SVL avançados alcançarem massa negativa.", "GraphiteCrystal": "Um cristal composto por múltiplas camadas de grafeno. Embora possa ser descrito como um diamante inacabado, é barato o suficiente para ser usado em lápis.", "Grating": "Um dispositivo ótico que decompõe a luz em um espectro de frequências.", "GraviteDetector": "Este detector especializado é capaz de localizar pedras de gravite com precisão. Ele é bem diferente de outros detectores, que conseguem localizar praticamente tudo, exceto gravite.", "Gunpowder": "Um composto químico que deflagra ao ser aquecido.", "Heater": "Um aquecedor pode ser utilizado para combater condições exteriores adversas ao transformar eletricidade em calor.", "Hematite": "Um óxido de ferro cristalino útil na blindagem contra radiação devido à sua alta densidade. Também é notável por sua condutividade elétrica.", "HullMK1_004": "As naves espaciais são compostas por três camadas principais: uma camada exterior, feita de material resistente e à prova de vácuo; um esqueleto interno estruturalmente sólido, composto por vigas pesadas; e sistemas internos que mantêm a nave habitável e operante.", "IronIngot": "Um material muito associado ao surgimento da civilização humana. Amplamente utilizado na indústria, é um dos elementos mais abundantes em planetas terrestres.", "Kaolinite": "Um tipo muito comum de mineral de silicato, encontrado em camadas de argila e amplamente utilizado na produção de papel e tinta. Seguro para ingestão em pequenas quantidades, é um ingrediente comum em pasta de dente.", "KineticShield1": "Usando um par de bobinas de Tesla, este módulo gera uma bolha de plasma carregado que pode proteger uma nave contra radiação e partículas.", "Levinium": "Um material metálico descoberto recentemente, conhecido por sua leveza. Suas propriedades e aplicações ainda são relativamente desconhecidas.", "LicensePoints": "Esses pontos, emitidos pela Agência de Licenciamento Universal da República, regulamentam o acesso a licenças industriais.", "Light_01": "Uma eficaz fonte de luz que mostra o caminho na escuridão.", "Lime": "Um componente mineral comumente usado em cimento e concreto. Obtido pela carbonatação do calcário, ele é composto principalmente por óxidos de cálcio.", "LiquidStorage1": "Este módulo de armazenagem é adequado para materiais líquidos ou semilíquidos. Suas conexões SCMM permitem abastecer outros RSMs se contiver combustível ou fluido de resfriamento.", "MagSheet": "Uma chapa de elmério polarizada magneticamente que costuma ser usada nas camadas internas de tanques de magnetoplasma.", "MagneticChamber": "Um dispositivo que permite que a corrente de plasma flua em movimento circular de alta velocidade sem sair da trajetória.", "MalachiteStone": "Um cristal de carbonato composto principalmente de cobre e usado como decoração funerária desde o Antigo Egito até a Mesoamérica Maia.", "Mercury": "O mercúrio é o único metal conhecido que é líquido à temperatura ambiente. Ele forma amálgamas com vários metais, além de ser altamente tóxico para humanos.", "MetalBolt": "Um dispositivo simples que utiliza força de torção para unir componentes.", "MetalSheet1": "Uma chapa metálica processada industrialmente que costuma ser usada como material básico de construção.", "MicroChip": "Um dispositivo eletrônico que executa programas de computador por meio de uma série de operações matemáticas simples. Também conhecido como \"Unidade Central de Processamento\".", "MiningTool1": "Este módulo óptico amplifica a luz a uma intensidade capaz de vaporizar muitos materiais. Atualmente é a forma mais precisa de cortar materiais.", "MiningTool_Cold": "Este fluxo de gás liquefeito de alta pressão oferece uma alternativa aos raios de laser, com efeito oposto na temperatura do alvo. Os dois podem ser usados em conjunto.", "MissileAirframe_Small": "Uma carcaça metálica e estrutura de propulsão capaz de transportar uma ogiva explosiva.", "ModuleCasing1": "Um padrão universal que serve como base para todos os \"módulos de nave confiáveis\". Fixa o RSM à nave associada com ímãs B-Switch eletropermanentes.", "Motor": "Um dispositivo que converte energia elétrica em movimento e vice-versa.", "Navigator": "Esse módulo de algoritmos complexos e coordenadas espaciais precisas auxilia prestadores distraídos no planejamento de rotas interestelares.", "P_ColdSuit": "Este acessório aumenta a capacidade de isolamento do traje contra baixas temperaturas. Vários chips podem ser aplicados para maior eficiência.", "P_ConstructionTool": "\"Síntese de Projeto\" libera uma nuvem de nanorrobôs flutuantes que podem reconhecer, cortar e montar materiais com base em um padrão predefinido. Resumindo, ele constrói coisas.", "P_DismentlingTool": "Esta ferramenta aprimorada inclui o recurso \"Dessíntese de Material\", que é capaz de reverter um processo de construção finalizado com dano mínimo aos componentes envolvidos.", "P_FarmingTool": "Colocar uma semente suja de molho pode parecer uma tarefa mundana, mas esta ferramenta eleva a arte de posicionar um pedaço germinante de planta alienígena no local perfeito para o sucesso do seu desenvolvimento.", "P_HeatSuit": "Este acessório aumenta a capacidade de isolamento do traje contra altas temperaturas. Vários chips podem ser aplicados para maior eficiência.", "P_Jetpack": "[NOTIMPL]", "P_JetpackV2": "[NOTIMPL]", "P_MovingTool": "Esta ferramenta aprimorada inclui o recurso \"Integridade Contínua\", que é capaz de realocar uma estrutura dentro de uma base sem desmontá-la primeiro.", "P_RadSuit": "Este acessório aumenta a capacidade de isolamento do traje contra radiação. Vários chips podem ser aplicados para maior eficiência.", "P_ThermoSuit": "Este acessório aumenta a capacidade de isolamento do traje contra altas e baixas temperaturas. Vários chips podem ser aplicados para maior eficiência.", "PathwayAmmo": "Utilizado com um [PathwayPuncher], esse núcleo para criar uma passagem em qualquer [B_PathwayHolder] disponível. Essa passagem pode ser utilizada para viajar entre dois locais com um motor SVL comum.", "PathwayPuncher": "Um módulo abre uma singela cavidade no contínuo espaço-temporal. Isso possibilita posicionar [PathwayAmmo], abrindo uma passagem até [B_PathwayHolder].", "Pipe1": "Um dispositivo simples para transportar fluidos entre dois pontos.", "Plate1": "Um painel metálico espesso que pode resistir a condições climáticas severas. Comumente usado em construções externas ou cascos de naves.", "PlatinumIngot": "Um metal nobre de valor bem alto. Sua notável resistência a corrosão o torna um componente industrial muito valorizado.", "PressureStorage1": "Este módulo de armazenagem é adequado para gases liquefeitos que exigem pressurização extrema. Suas conexões SCMM permitem abastecer outros RSMs se contiver combustível ou fluido de resfriamento.", "Protein": "Um componente essencial dos organismos vivos, as proteínas são biomoléculas compostas por cadeias de aminoácidos.", "Pump": "Um dispositivo para impulsionar fluidos por tubulações conectadas.", "Pyrite": "Um sulfeto de ferro cristalino. Barato o suficiente para ser conhecido como \"ouro de tolo\", ainda assim é um semicondutor útil e um componente fotovoltaico comum.", "Quartz": "Um cristal composto principalmente de sílica e componente importante de muitos objetos astronômicos. Suas numerosas variedades são comercializadas como pedras preciosas desde a antiguidade humana.", "RBattery0": "Este módulo pode armazenar energia cinética com uma roda giratória para alimentar outros RSMs, evitando as desvantagens das baterias químicas.", "Radar0": "Ao emitir ondas eletromagnéticas e interpretar sua refração, este radar é capaz de detectar e identificar objetos metálicos dentro de um grande perímetro.", "Radar_Smart": "Usando análise espectral e comparação com um banco de dados de componentes, este detector pode identificar recursos conhecidos à distância.", "Radar_Sniffer": "Usando uma amostra de um recurso específico, este detector é capaz de localizar jazidas próximas com o mesmo elemento.", "Radiator": "Este módulo é capaz de liberar grandes quantidades de energia térmica. É usado principalmente para resfriar o interior de uma nave, dissipando o calor no espaço.", "Radon": "Um perigoso gás radioativo que nunca deveria ser manuseado sem o equipamento adequado.", "Rockwood_DreamwoodFruit": "Não se recomenda o consumo dessa fruta. Seus efeitos colaterais incluem: alucinações vívidas, paranoia aguda e morte súbita.", "Rockwood_GlowwoodBark": "Essa casca grossa e escura floresce em um ambiente radioativo, sem parecer ter sofrido com isso.", "Rockwood_GlowwoodFruit": "Esse fruto lustroso é levemente quente ao toque, um sinal de radioatividade latente.", "Rockwood_Seed": "A litoflora combina compostos minerais e orgânicos de uma forma incomum. Costuma produzir estruturas minerais complexas que raramente são encontradas em outros lugares na natureza.", "Sandstone": "Uma rocha sedimentar composta principalmente de silício oxidado. Presente no vidro, cerâmica e cimento, é tão abundante que planetas terrestres também são conhecidos como \"planetas de silicato\".", "Scanner0": "Este módulo identifica a composição de uma amostra por espectrometria de massa. Lasers de mineração só podem ser usados em recursos identificados por esse processo.", "SeekerMissile0": "Antes do êxodo, explosivos químicos simples eram uma arma recorrente. Existem opções mais destrutivas, mas nenhuma tão barata e fácil de produzir.", "Semiconductor": "Uma base em branco para um futuro microchip ou célula solar.", "Shuttle0": "Este veículo autônomo transporta cargas entre duas bases diferentes.", "SiliciumIngot": "Um semicondutor equilibrado, utilizado na maioria dos dispositivos eletrônicos. Este metaloide também pode ser encontrado em argila, vidro e diversos tipos de rocha.", "SiliconeGel": "Um semissólido altamente absorvente e não reativo, amplamente utilizado em química, filtragem de água e resfriamento.", "SilverIngot": "O mais condutor e reflexivo de todos os metais. Pode ser encontrado em sua forma pura na natureza e tem sido usado em inúmeros aspectos da indústria e da arte humanas por milênios.", "SolarCell": "Um dispositivo eletrônico que converte ondas eletromagnéticas em eletricidade.", "SolarPanel1": "Este módulo converte radiação eletromagnética em corrente elétrica para alimentar outros RSMs.", "SpaceWheat_FrostPulp": "Apesar do nome, essa polpa é estranhamente morna, como se a temperatura externa não a afetasse.", "SpaceWheat_PlainPulp": "Essa polpa é basicamente insípida, mesmo contendo nutrientes pouco comuns.", "SpaceWheat_Seed": "O grão sideral é um organismo alienígena altamente adaptável. Ele ainda é uma fonte de nutrientes compatível com a biologia humana.", "SpaceWheat_SourPulp": "Essa polpa claramente passou do ponto, mas pode ser uma fonte de compostos fermentados.", "SpaceWheat_WoolyKorn": "Essa casca, dura e fibrosa, contém algumas sementes de grão sideral. Um moedor é necessário para extraí-las.", "Steel": "Uma liga de ferro e carbono que costuma incorporar cromo para evitar oxidação. Sua confiabilidade e baixo custo fazem dele um elemento essencial para a maioria das indústrias.", "SteelCasingMK1": "Uma carcaça modular que envolve uma nave ou um RSM. Além de reduzir o atrito em ambientes atmosféricos, a carcaça oferece proteção contra radiação eletromagnética.", "Storage1": "Este módulo de armazenagem é adequado para materiais sólidos. Seu sistema de estabilização magnética protege a carga contra colisões, independentemente dos movimentos da nave.", "Sulfur": "Um material cristalino, componente químico e fertilizante. Descrito na Bíblia como o enxofre do inferno, é um dos únicos seis elementos químicos encontrados em todas as formas de vida conhecidas.", "SupportCasing": "Um conjunto padronizado de cabos e tubulações que permite que todos os RSMs se comuniquem com a nave associada. Segue a convenção \"Sistema Circulatório de Montagem de Módulos\" ou SCMM.", "ThermalIsolant": "Uma fibra mineral que retém finas camadas de ar para desacelerar a condução térmica. O nome evoca a lembrança de um tempo em que lã de verdade ainda existia.", "ThermalPaste": "Esta pasta semiorgânica é excepcionalmente resistente a mudanças de temperatura. Ela pode ser utilizada para proteção contra condições extremas.", "ThermalSheet": "Uma chapa metálica processada industrialmente com condutividade térmica extremamente baixa.", "Thruster0": "Este dispositivo de propulsão elétrica pode fornecer impulso e sustentação a uma nave sem exigir combustão ou combustível não renovável.", "ThrusterAE1": "Esse sútil propulsor Aegir se integra intimamente com o sistema de uma nave para atingir o ápice, tanto da eficiência energética quanto das profundezas inexploradas.", "ThrusterDA1": "A ciência rotineiramente empurra mentes questionadoras para além do limiar da segurança. Com esse propulsor, Damona propicia uma forma de retornar prontamente à vacuidade do espaço.", "ThrusterMK1": "Meitner & Karls projetaram esse poderoso propulsor para enfrentar o calor seco das mais intensas expedições de mineração.", "TitaniumIngot": "Um material muito utilizado em ligas por sua leveza, resistência e biocompatibilidade. Também pode ser encontrado na maioria dos organismos vivos.", "TungstenIngot": "Denso, duro, e com ponto de fusão excepcionalmente alto, o tungstênio é um metal difícil de trabalhar, mas as suas propriedades também o tornam um componente crítico de muitas ligas.", "Turquoise": "Uma gema opaca formada pelo contato entre água meteórica e pórfiro de cobre.", "Unbendinium": "Essa liga misteriosa tem sido peça fundamental na logística espacial humana. Sua resistência à tração e ao escoamento é inigualável por qualquer outro metal conhecido.", "UraniumNugget": "Um perigoso material radioativo que nunca deveria ser manuseado sem o equipamento adequado.", "VanadiumIngot": "Um material comumente utilizado em ligas de aço. Também pode ser encontrado como toxina em diversos organismos vivos.", "Vitriol": "O ácido sulfúrico é uma das substâncias industriais mais comuns. Existem muitas formas de produzir esse componente e ainda mais formas de utilizá-lo.", "Water": "Solvente notavelmente neutro, com forte polaridade e pequeno tamanho molecular, a água é essencial para todas as formas de vida conhecidas e para a maioria das indústrias.", "Water_Brine": "Grandes massas desprotegidas de água tendem a conter diversos contaminantes, precisando de tratamento antes de se tornarem viáveis para aplicação química.", "Wire": "Um dispositivo simples para transmitir corrente elétrica entre dois pontos.", "XenicOil": "Hidrocarboneto orgânico extraído de sementes alienígenas, o óleo xênico é um lubrificante útil e combustível medíocre.", "ZirconiumIngot": "Um material muito resistente a corrosão e a altas temperaturas. Também é capaz de armazenar energia radioativa com perda mínima."}, "ru": map[schema.GDID]string{"ActivatedCoal": "Пористая форма углерода с выдающимися адсорбционными свойствами. Широко используется для фильтрации газов и жидкостей.", "Actuator": "Устройство, преобразующее давление жидкости в точное управляемое движение.", "Alternator": "Устройство, способное создавать сильный эффект Холла, позволяющий ионным двигателям ускорять топливо.", "AluK": "Сплав алюминия, обладающий малым весом и превосходными теплоизоляционными свойствами.", "AluminiumIngot": "Этот материал отличается очень низкой плотностью и высокой проводимостью. Несмотря на свою распространенность, он редко встречается в природе в чистом виде.", "Antimatter_Empty": "Контейнер для удержания античастиц. Антиматерия печально известна своей сложностью в производстве, но еще сложнее ее хранить.", "Aquamarine": "Кристалл из семейства бериллов, продаваемый как драгоценный камень и ценимый за свой характерный светло-голубой оттенок.", "AutoBoostModule": "Этот небольшой компьютерный компонент улучшает управление двигателями: нажмите [key.Booster], чтобы включить/выключить усиление.", "AutoMineModule": "Этот небольшой компьютерный компонент улучшает управление шахтерским лазером: нажмите [key.Booster], чтобы включить/выключить добычу.", "AzuriteStone": "Карбонатный кристалл, состоящий преимущественно из меди и часто использовавшийся в качестве пигмента на протяжении всей истории человечества.", "BTitanium": "Сплав титана и ванадия, ценимый за замечательную пластичность, что делает его превосходным сварочным материалом.", "B_AntimatterSynthPH": "Это здание потребляет огромное количество электроэнергии для производства незначительного количества антиматерии, что само по себе довольно примечательно.", "B_Battery": "Это здание накапливает химическую энергию, когда энергосеть производит избыточную мощность. Затем оно может легко преобразовать эту энергию обратно в электричество во время скачков потребления.", "B_BottlingPlant": "Это здание упаковывает жидкие или полутвердые продукты в стандартизированные контейнеры.", "B_Chemical": "Это здание собирает химические элементы в промышленные соединения. Оно может функционировать непрерывно без участия человека, что делает его подходящим для крупносерийного производства.", "B_Chest": "Этот небольшой ящик позволяет любому члену той же корпорации, что и владелец базы, оставлять или забирать подарки.", "B_Cistern": "Это здание подходит для хранения жидких или полутвердых материалов.", "B_ControlBase": "Это центральное здание обеспечивает базовое хранение, электричество и административные системы, необходимые для работы небольшой наземной базы. Развертывание базы является законным заявлением прав на территорию и ресурсы, на которых она расположена. Также оснащено базовыми ручными плавильными и ремонтными станками.", "B_ControlBase2": "Это здание позволяет базе расширяться на территорию 2-го уровня, удваивая ее максимальную площадь и открывая пороги опыта до 800\u00a0очков.", "B_ControlBase3PH": "Это здание позволяет базе расширяться на территорию 3-го уровня, удваивая ее максимальную площадь и открывая пороги опыта до 2000\u00a0очков.", "B_ControlBase_Corpo1": "Юридически признанной корпорации, имеющей важное значение, часто требуется место для централизации своей деятельности. Это здание увеличивает максимальный размер отдельной базы корпорации и включает производственные машины, конференц-зал и множество персонализируемых помещений.", "B_Crystaliser": "Это здание использует химические растворы для генерации кристаллов с исключительно высокой скоростью по сравнению с их естественным процессом формирования.", "B_ElectricPillar": "Эта опора может поддерживать электрические кабели и подключать энергосеть базы к другому зданию. Чтобы подключить кабель, выберите верхнюю часть столба и нажмите «E».", "B_Extractor": "Это здание может быть собрано только над залежами ресурсов, которые оно затем будет бурить для автоматической добычи руды.", "B_FTLCistern": "Это строение подходит для хранения активной маг-плазмы.", "B_Factory1": "Это здание собирает базовые ресурсы в промышленные соединения. Будучи автоматизированной альтернативой ручной мастерской, оно может функционировать непрерывно без участия человека, что делает его подходящим для крупносерийного производства.", "B_Factory2": "Материалы для крупнейших кораблей можно производить только на специализированном крупногабаритном заводе, который потребляет много энергии.", "B_Farm": "Это здание обеспечивает подходящую среду для выращивания живых организмов.", "B_Generator": "Это здание потребляет углеродное топливо для выработки электрического тока, питая энергосеть базы. Станция эффективна и компактна, но требует много ресурсов.", "B_LaboPH": "В этом здании расположена компактная лаборатория Ninmah, оснащенная всем необходимым для анализа экзотических веществ.", "B_LandingPad": "Эта платформа позволяет кораблю пристыковываться к базе и подключаться к ее распределительной системе для передачи топлива или других жидкостей.", "B_LiquidExtractor": "Это здание может быть собрано только над геотермальным бассейном, из которого оно будет автоматически извлекать чистую жидкость.", "B_Organiser": "Это здание может отслеживать несколько маршрутов дронов и объединять их в полноценные производственные цепочки. Основа хорошо организованной системы.", "B_PathwayHolder": "Эта высокая конструкция способна стабилизировать существующий пространственно-временной туннель даже в гравитационном колодце планеты. Корабль может путешествовать по такому маршруту с помощью обычного двигателя ССП.", "B_PowerTransmitter": "В этом здании используются передовые технологии экранирования и гравитационная деформация пространства-времени для передачи электроэнергии без потерь между различными базами в пределах одной звездной системы.", "B_RecyclingPlant": "Это здание перерабатывает обрезки для извлечения их различных компонентов и подготовки их к промышленному повторному использованию.", "B_Shipyard": "Эта платформа позволяет кораблю пристыковываться к базе для модификации его структуры и замены модулей. Она аналогична корабельным докам космических станций.", "B_ShuttlePad": "Эта платформа позволяет шаттлу пристыковываться к базе, транспортируя товары внутрь и наружу.", "B_Smelter": "Это здание перерабатывает руду в промышленные слитки. Будучи автоматизированной альтернативой ручной плавильной печи, оно может функционировать непрерывно без участия человека, что делает его подходящим для крупносерийного производства.", "B_SmelterSA": "Компания Meitner\u00a0&\u00a0Karls усовершенствовала превращение руды в слитки с помощью этой микропечи. Она меньше и быстрее обычной плавильни и станет идеальным помощником в дни, когда вы вынуждены интенсивно изготавливать предметы вручную.", "B_SolarPanel": "Это здание преобразует электромагнитное излучение в электрический ток, питая энергосеть базы. Оно занимает место и должно быть правильно сориентировано, но работает без топлива.", "B_Warehouse": "Это здание подходит для хранения твердых материалов, которые могут быть легко перемещены дронами.", "BarrierShield1": "В этом модуле плазменного щита достаточно заряда, чтобы защитить космический корабль от легкого человеческого вооружения, но заряжается он дольше, чем обычный щит.", "Battery": "Устройство, способное накапливать химическую энергию и преобразовывать ее в электричество. Является основой для более крупных аккумуляторных ЗМКК.", "Battery1": "Этот модуль может накапливать химическую энергию и легко преобразовывать ее в электрический ток для питания других ЗМКК.", "Beacon": "Экспериментальный метод высокоскоростной связи. Этот маяк может мгновенно раскрыть свое местоположение любому квантовому устройству по всей галактике, независимо от того, где он находится.", "BeaconKey": "Экспериментальный метод высокоскоростной связи. Это устройство может мгновенно определить местоположение маяка, с которым установлен контакт.", "Beam1": "Удлиненный металлический элемент с Н-образным поперечным сечением. Широко используется в строительстве для обеспечения несущей способности.", "BlastMissile0": "Взрывчатка часто используется в горнодобывающих работах для доступа к полезным ископаемым, защищенным тяжелыми поверхностными материалами.", "Blueprint": "Этот детальный план содержит все необходимые инструкции для постройки конкретного модуля корабля. Его может прочитать человек или машина.", "BottlePlasma_Empty": "Прочный контейнер с маг-плазмой, позволяющий хранить это вещество в обычных грузовых трюмах.", "Bottle_Empty": "Простейший, но надежный контейнер для жидких или полужидких веществ, позволяющий хранить их в обычных грузовых трюмах.", "CalcifiedInvariant": "Древние камни, пропитанные первобытной энергией Большого взрыва, иногда можно опознать по специфической энергетической сигнатуре.", "Calcite": "Карбонатный кристалл, также известный как алебастр. Этот основной компонент известняка и мрамора служит незаменимым материалом для скульптур.", "Carbon": "Важнейший материал в большинстве отраслей промышленности, будь то уголь, алмаз или графит. Кроме того, это один из шести химических элементов, встречающихся во всех известных формах жизни.", "CarbonGenerator": "Этот модуль потребляет углеродное топливо для выработки электрического тока, питающего другие ЗМКК.", "CarbonicFuel": "Ультрапереработанная производная углерода, разработанная как более эффективная альтернатива природному ископаемому топливу.", "Cartridge_Iron": "Кинетическое оружие по-прежнему широко используется Вселенским корпусом обороны, разработавшим ряд стандартов для калибров патронов.", "Cinnabar": "Этот кристалл сульфида ртути широко использовался в качестве красителя благодаря своему ярко-красному оттенку, пока не стало известно о высокой токсичности ртути.", "Cockpit_AE1": "Индивидуальный кокпит Aegir оптимизирован для снижения вероятности критических повреждений во время прыжков ССП. Он также оснащен небольшим, но очень эффективным силовым аккумулятором.", "Cockpit_AE2": "Просторный кокпит Aegir — технологическое чудо, способное сохранять точные координаты, к которым в любой момент можно вернуться без расхода маг-плазмы и без риска повреждений.", "Cockpit_DA1": "Индивидуальный кокпит Damona — это достижение изоляционной техники, которое делает его менее уязвимым к внешним температурам, но также замедляет лазерное охлаждение. Также оснащен небольшим радиатором, который помогает кораблю отводить избыточное тепло или вырабатывать его, когда становится холодно.", "Cockpit_MK1": "Индивидуальный кокпит Meitner\u00a0&\u00a0Karls оптимизирован для увеличения грузового пространства и устойчивости к столкновениям, что делает его идеальным выбором для транспортировки грузов через астероидные поля.", "Cockpit_MK2": "Просторный кокпит Meitner\u00a0&\u00a0Karls настолько велик, что в нем хватает места для бортовой плавильной печи, подобной тем, что можно построить на наземной базе.", "Cockpit_TC1": "Базовый кокпит Компании, которым в основном оснащают пробные корабли.", "Coil": "Простое устройство, преобразующее магнитные поля в электрический ток и наоборот.", "Concrete": "Искусственная смесь минералов, связанных химическим веществом, известным как цемент. В основном используемый в строительстве, из всех материалов на Земле бетон производился чаще всего.", "ControlBaseCore": "Это устройство может присоединить окружающую территорию к базе пользователя и снабжать ее электричеством. Его использование разрешено только авторизованным партнерам, отобранным Компанией.", "ControlBaseKit": "Это автономное устройство может развернуть планетарную базу за считанные секунды. Его использование разрешено только авторизованным партнерам, отобранным Компанией.", "CopperIngot": "Высокопроводящий материал, известный своей универсальностью. Встречается в природе в виде самородного металла, но также может быть обнаружен в кристаллической форме.", "CorpoCredits": "Эти кредиты принадлежат корпорации, а не отдельным лицам.", "CorpoReputation": "По мере того, как каждая корпорация выполняет различные запросы, ее репутация по всей галактике улучшается.", "Crystal": "Драгоценные камни могут иметь разный состав, внешний вид и свойства. Их общая черта\u00a0— эстетическая привлекательность, за которую ее ценят люди.", "CrystalLattice_C": "Чисто ограненный кристалл, который можно использовать в оптическом устройстве. Его кубическая структура — самая простая форма кристаллов, встречающаяся в природе.", "CrystalLattice_H": "Чисто ограненный кристалл, который можно использовать в оптическом устройстве. Его гексагональная структура наиболее распространена в природе.", "CrystalLattice_M": "Чисто ограненный кристалл, который можно использовать в оптическом устройстве. Его моноклинная структура замечательно асимметрична.", "Diamond": "Кристаллическая форма чистого углерода. Это самый твердый и самый теплопроводный материал из всех когда-либо наблюдавшихся.", "Drone0": "Это автономное транспортное средство перевозит грузы из одной точки в другую по заданному маршруту.", "Elmerium": "Относительно малоизученный материал, электромагнитные свойства которого способны формировать плазменные поля. Его открытие в эпоху Федерации планет дало толчок развитию ССП-щитов.", "ElmeriumEngine": "Устройство, способное рассеивать плазменное поле по сферической области. Важный компонент большинства моделей щита.", "Emerald": "Кристалл из семейства бериллов, продаваемый как драгоценный камень и ценимый за свой характерный темно-зеленый оттенок.", "EngineBooster": "Начальный вспомогательный двигательный модуль Luo Ri (LR) может дать значительное преимущество в скорости пилотам с ограниченным бюджетом.", "Ethanol": "Хотя этанол хорошо известен своими рекреационными свойствами, он также является плотным биотопливом и эффективным растворителем масляных пятен.", "ExplodingToolMk1": "Модуль, используемый для доставки заряда взрывчатого вещества к удаленной цели.", "FTLEngine1": "Считающаяся величайшим изобретением эпохи Федерации планет, эта категория модулей способна сжимать и расширять пространство, делая возможными путешествия со сверхсветовой скоростью (ССП).", "FTLEngine3_Solo": "Считающаяся величайшим изобретением эпохи Федерации планет, эта категория модулей способна сжимать и расширять пространство, делая возможными путешествия со сверхсветовой скоростью (ССП). Эта модель оптимизирована для одного корабля.", "FTLEngine3_Support": "Считающаяся величайшим изобретением эпохи *Федерации планет*, эта категория модулей способна сжимать и расширять пространство, делая возможными путешествия со сверхсветовой скоростью (ССП). Эта модель может перемещать одновременно несколько кораблей.", "FTLTank1": "Этот модуль хранения подходит для активной маг-плазмы. Его разъемы МЦС позволяют ему питать щитовые ЗМКК.", "FToiL": "Именно открытие этого замечательного топлива сделало возможным изобретение прыжков ССП.", "Fertilizer_Neutral": "Порошковая добавка, которую можно применять в качестве питательной подкормки для инопланетных растений.", "FluidPumpingTool1": "Этот модуль предназначен для мощного всасывания всех видов жидкостей, присутствующих в окружающей среде.", "Focuser": "Оптическое устройство для концентрации излучения с помощью полированных кристаллов.", "Graphene": "Материал, состоящий из взаимосвязанных атомов углерода. Его непревзойденная прочность на растяжение делает его идеальным для случаев, когда важно сочетать легкость и прочность.", "Graphenoid": "Графеновая структура, демонстрирующая квантовые молекулярные эффекты, которые используются в высокопроизводительных двигателях ССП, чтобы достичь отрицательной массы.", "GraphiteCrystal": "Кристалл, состоящий из нескольких слоев графена. Хотя его можно описать как необработанный алмаз, он достаточно дешев, чтобы использовать его в карандашах.", "Grating": "Оптическое устройство, разлагающее свет на спектр частот.", "GraviteDetector": "Этот специализированный детектор может точно находить гравитные камни. Он сильно отличается от других детекторов, которые могут найти практически все, кроме гравита.", "Gunpowder": "Химическое соединение, которое воспламеняется при нагревании.", "Heater": "Обогреватель используется для борьбы с суровым холодом снаружи, преобразуя электрическую энергию в тепловую.", "Hematite": "Кристаллический оксид железа, используемый для защиты от излучения благодаря своей высокой плотности. Также славится электропроводностью.", "HullMK1_004": "Космические аппараты состоят из трех основных уровней: вакуумонепроницаемой внешней оболочки, изготовленной из стойкого материала; конструктивно прочного внутреннего каркаса из тяжелых балок; и внутренних систем, обеспечивающих пригодность корабля для жизни и его функционирование.", "IronIngot": "Материал, тесно связанный с зарождением человеческой цивилизации. Широко используемый в промышленности, это один из самых распространенных элементов на землеподобных планетах.", "Kaolinite": "Очень распространенный тип силикатного минерала, широко используемый в производстве бумаги и красок и часто обнаруживаемый в глиняной посуде. Безопасен для употребления в небольших количествах, также является распространенным ингредиентом зубной пасты.", "KineticShield1": "Используя пару катушек Теслы, этот модуль генерирует пузырь из заряженной плазмы, который может защитить космический корабль от радиации и частиц.", "Levinium": "Недавно открытый металлический материал, известный своей исключительной легкостью. Его свойства и области применения пока относительно мало изучены.", "LicensePoints": "Эти баллы, регулирующие доступ к промышленным лицензиям, выдаются Вселенским лицензионным агентством Республики.", "Light_01": "Хороший источник света, помогающий видеть в темноте.", "Lime": "Минеральный компонент, обычно используемый в цементе и бетоне. Получаемый карбонизацией известняка, он в основном состоит из оксидов кальция.", "LiquidStorage1": "Этот модуль хранения подходит для жидких или полужидких материалов. Его разъемы МЦС позволяют ему снабжать другие ЗМКК, если он содержит топливо или охлаждающую жидкость.", "MagSheet": "Магнитно-поляризованный лист из эльмерия, обычно используемый во внутренних оболочках резервуаров из маг-плазмы.", "MagneticChamber": "Устройство, позволяющее плазменному току течь с высокой скоростью по круговой траектории, не выходя за ее пределы.", "MalachiteStone": "Карбонатный кристалл, состоящий преимущественно из меди и использовавшийся в качестве погребального украшения от Древнего Египта до цивилизации майя в Мезоамерике.", "Mercury": "Ртуть — единственный известный металл, находящийся в жидком состоянии при комнатной температуре. Она образует амальгамы со многими другими металлами и крайне токсична для человека.", "MetalBolt": "Простое устройство, использующее вращательное усилие для скрепления компонентов.", "MetalSheet1": "Металлический лист, обработанный промышленным способом и широко используемый в качестве основного строительного материала.", "MicroChip": "Электронное устройство, выполняющее компьютерные программы посредством ряда простых математических операций. Также известно как «центральный процессор».", "MiningTool1": "Этот оптический модуль усиливает свет до интенсивности, способной испарять многие материалы. В настоящее время это самый точный способ резки.", "MiningTool_Cold": "Эта струя сжиженного газа под высоким давлением является альтернативой лазерным лучам, оказывает противоположный эффект на температуру цели. Их можно комбинировать.", "MissileAirframe_Small": "Металлический корпус и двигательная установка, способные доставить взрывную боеголовку.", "ModuleCasing1": "Универсальный стандарт, служащий основой всех зависимых модулей космических кораблей. Крепит ЗМКК к соответствующим кораблям с помощью электромагнитов и постоянных магнитов B-Switch.", "Motor": "Устройство, преобразующее электрическую энергию в движение и наоборот.", "Navigator": "Используемые в этом модуле сложные алгоритмы и точные пространственные координаты помогают рассеянному подрядчику спланировать маршрут среди звезд.", "P_ColdSuit": "Этот аксессуар увеличивает защиту костюма от низких температур. Для повышения эффективности можно применить несколько чипов.", "P_ConstructionTool": "«Синтез чертежа» высвобождает облако парящих наноботов, которые распознают, режут и собирают материалы на основе заданного шаблона. Короче говоря, он строит вещи.", "P_DismentlingTool": "Этот улучшенный инструмент включает функцию «Разбор материала», которая может обратить вспять законченный процесс строительства с минимальным повреждением задействованных компонентов.", "P_FarmingTool": "Замачивание грязного семени может показаться рутинной задачей, но этот инструмент возводит в ранг искусства точное размещение прорастающей части инопланетного растения в идеальном месте для успешного развития.", "P_HeatSuit": "Этот аксессуар увеличивает защиту костюма от высоких температур. Для повышения эффективности можно применить несколько чипов.", "P_Jetpack": "[NOTIMPL]", "P_JetpackV2": "[NOTIMPL]", "P_MovingTool": "Этот улучшенный инструмент включает функцию «Непрерывная целостность», с помощью которой можно перемещать здание внутри базы без его предварительного демонтажа.", "P_RadSuit": "Этот аксессуар увеличивает защиту костюма от радиации. Для повышения эффективности можно применить несколько чипов.", "P_ThermoSuit": "Этот аксессуар увеличивает способность костюма защищать как от высоких, так и от низких температур. Для повышения эффективности можно применить несколько чипов.", "PathwayAmmo": "Взаимодействие: [PathwayPuncher]. Направление: любой доступный [B_PathwayHolder]. Это ядро может проложить маршрут, который затем можно будет использовать для перемещений между двумя точками с помощью обычного двигателя ССП.", "PathwayPuncher": "Модуль, который проделывает крошечное отверстие в пространственно-временном континууме. При этом [PathwayAmmo] разворачивается и получает возможность проделать путь (направление: [B_PathwayHolder]).", "Pipe1": "Простое устройство для перемещения жидкостей между двумя точками.", "Plate1": "Толстая металлическая панель, способная выдерживать суровые погодные условия. Обычно используется в наружном строительстве или при изготовлении корпусов кораблей.", "PlatinumIngot": "Благородный металл, имеющий особую ценность. Его исключительная коррозионная стойкость делает его ценным промышленным компонентом.", "PressureStorage1": "Этот модуль хранения подходит для сжиженного газа, требующего экстремального давления. Его разъемы МЦС позволяют ему снабжать другие ЗМКК, если он содержит топливо или охлаждающую жидкость.", "Protein": "Незаменимый компонент живых организмов, белки — это биомолекулы, состоящие из цепочек аминокислот.", "Pump": "Устройство для перекачивания жидкостей по соединенным трубам.", "Pyrite": "Кристаллический сульфид железа. Достаточно дешевый, чтобы его называли «золотом дураков», он, тем не менее, является полезным полупроводником и распространенным компонентом фотогальванических элементов.", "Quartz": "Кристалл, состоящий преимущественно из кремнезема и являющийся важным компонентом многих астрономических объектов. Многочисленные его разновидности продавались в качестве драгоценных камней с древних времен.", "RBattery0": "Этот модуль может накапливать кинетическую энергию с помощью вращающегося маховика, чтобы питать другие ЗМКК, не имея при этом недостатков химических аккумуляторов.", "Radar0": "Испуская электромагнитные волны и интерпретируя их преломление, этот радар может обнаруживать и идентифицировать металлические объекты в большом радиусе.", "Radar_Smart": "Используя спектральный анализ и сравнение с базой данных компонентов, этот детектор может идентифицировать известные ресурсы на расстоянии.", "Radar_Sniffer": "Используя образец определенного ресурса, этот детектор может найти близлежащие залежи, содержащие тот же элемент.", "Radiator": "Этот модуль может высвобождать большие объемы тепловой энергии. В основном он используется для охлаждения внутреннего пространства космического корабля путем рассеивания его тепла в космосе.", "Radon": "Опасный радиоактивный газ, с которым нельзя работать без надлежащего оборудования.", "Rockwood_DreamwoodFruit": "Употреблять такие плоды явно не стоит, так как среди побочных эффектов встречаются яркие галлюцинации, острая паранойя и внезапная смерть.", "Rockwood_GlowwoodBark": "Эта темная толстая кора выросла в радиационной среде, но, похоже, не пострадала от нее.", "Rockwood_GlowwoodFruit": "Эта блестящая ягода слегка теплая на ощупь, что является признаком скрытой радиоактивности.", "Rockwood_Seed": "В скальном дереве минеральные и органические соединения сочетаются необычным образом. Зачастую оно образует сложные минеральные структуры, которые редко встречаются в природе.", "Sandstone": "Осадочная порода, состоящая преимущественно из окисленного кремния. Являясь компонентом стекла, керамики и цемента, она настолько распространена, что землеподобные планеты также известны как «силикатные планеты».", "Scanner0": "Этот модуль определяет состав образца с помощью масс-спектрометрии. Шахтерские лазеры можно использовать только на ресурсах, идентифицированных таким образом.", "SeekerMissile0": "До исхода простые химические взрывчатые вещества были обычным видом оружия. Существуют и более разрушительные варианты, но ни один из них не является столь же дешевым и простым в производстве.", "Semiconductor": "Чистый лист для будущего микрочипа или солнечной батареи.", "Shuttle0": "Это автономное транспортное средство перевозит грузы внутрь и наружу базы, доставляя их на другие базы или с них.", "SiliciumIngot": "Замечательно сбалансированный полупроводник, используемый в большинстве электронных устройств. Этот металлоид также встречается в глине, стекле и многих видах камня.", "SiliconeGel": "Нереактивное полутвердое вещество с высокой впитывающей способностью, широко используемое в химии, фильтрации воды и системах охлаждения.", "SilverIngot": "Самый проводящий и отражающий из всех металлов. Он встречается в природе в чистом виде и тысячелетиями использовался в различных областях человеческой промышленности и искусства.", "SolarCell": "Электронное устройство, преобразующее электромагнитные волны в электричество.", "SolarPanel1": "Этот модуль преобразует электромагнитное излучение в электрический ток для питания других ЗМКК.", "SpaceWheat_FrostPulp": "Несмотря на название, эта масса на удивление прохладна, словно температура снаружи на нее не действует.", "SpaceWheat_PlainPulp": "Эта целлюлоза практически безвкусна, несмотря на содержащиеся в ней необычные питательные вещества.", "SpaceWheat_Seed": "Космокукуруза — это инопланетный организм с высокой адаптивностью. Более того, она является источником питательных веществ, совместимых с человеческой биологией.", "SpaceWheat_SourPulp": "Эта целлюлоза явно испортилась и может быть источником ферментированных соединений.", "SpaceWheat_WoolyKorn": "Под этой твердой волокнистой оболочкой должно содержаться несколько семян космокукурузы. Для их извлечения требуется дробилка.", "Steel": "Сплав железа и углерода, часто с добавлением хрома для предотвращения окисления. Надежность и низкая стоимость делают его незаменимым материалом в большинстве отраслей промышленности.", "SteelCasingMK1": "Модульный корпус, оболочка для корабля или ЗМКК. Помимо ограничения трения в атмосферных пространствах, кожух обеспечивает защиту от электромагнитного излучения.", "Storage1": "Этот модуль хранения подходит для твердых материалов. Его система магнитной стабилизации защищает груз от столкновений независимо от движений корабля.", "Sulfur": "Кристаллическое вещество, химический компонент и удобрение. В Библии такое называется жупелом. Один из шести химических элементов, встречающихся во всех известных формах жизни.", "SupportCasing": "Стандартизированный набор кабелей и труб, позволяющих всем ЗМКК взаимодействовать с соответствующим кораблем. Соответствует Стандарту на модульные циркуляционные системы (Стандарт МЦС).", "ThermalIsolant": "Минеральное волокно, которое удерживает тонкие слои воздуха, чтобы замедлить теплопроводность. Его название пробуждает тоску по времени, когда еще существовала настоящая шерсть.", "ThermalPaste": "Эта полуорганическая масса необычайно устойчива к перепадам температуры. Ее можно использовать для защиты от экстремальных условий.", "ThermalSheet": "Металлический лист, обработанный промышленным способом и обладающий удивительно низкой теплопроводностью.", "Thruster0": "Это электротяговое устройство может обеспечивать тягу и подъемную силу космического корабля, не требуя сгорания или использования невозобновляемого топлива.", "ThrusterAE1": "Этот изящный двигатель AEgir глубоко интегрируется с системами корабля, достигая вершин энергоэффективности и позволяя проникать в неизведанную тьму.", "ThrusterDA1": "Наука часто заставляет пытливые умы выходить из зоны комфорта. С помощью этого двигателя Damona предоставляет им возможность быстро вернуться в безопасную пустоту космоса.", "ThrusterMK1": "Meitner\u00a0&\u00a0Karls разработали этот мощный двигатель, способный справиться с сухой жарой, характерной для самой интенсивной горной добычи.", "TitaniumIngot": "Материал, широко используемый в сплавах благодаря своей легкости, прочности и биосовместимости. Он также встречается в большинстве живых организмов.", "TungstenIngot": "Вольфрам — плотный и твердый металл с исключительно высокой температурой плавления. Его трудно обрабатывать, но благодаря своим свойствам он является важным компонентом многих сплавов.", "Turquoise": "Непрозрачный драгоценный камень, образовавшийся в результате контакта метеоритной воды с медным порфиром.", "Unbendinium": "Этот загадочный сплав имеет решающее значение для логистики космических полетов человечества. Предел прочности и текучести у него не имеет равных среди всех известных человеку металлов.", "UraniumNugget": "Опасный радиоактивный материал, с которым нельзя работать без надлежащего оборудования.", "VanadiumIngot": "Этот материал широко используется в стальных сплавах. Он также может быть токсичным для ряда живых организмов.", "Vitriol": "Серная кислота — одно из наиболее широко используемых промышленных веществ. Существует множество способов производства этого компонента и еще больше способов его применения.", "Water": "Вода, являясь удивительно нейтральным растворителем с сильной полярностью и малым размером молекул, необходима для всех известных форм жизни и большинства известных отраслей промышленности.", "Water_Brine": "Крупные открытые водоемы под открытым небом загрязнены множеством соединений и требуют очистки перед использованием в химических процессах.", "Wire": "Простое устройство для передачи электрического тока между двумя точками.", "XenicOil": "Ксеноновое масло — это извлекаемый из инопланетных семян органический углеводород, которым удобно смазывать устройства, но крайне бесполезно заправлять.", "ZirconiumIngot": "Этот материал обладает коррозионной стойкостью и устойчивостью к высоким температурам. Он также способен накапливать радиоактивную энергию с минимальными потерями."}, "zh": map[schema.GDID]string{"ActivatedCoal": "是一种多孔碳材料，具备出色的吸附性。广泛用于过滤气体与液体。", "Actuator": "促动器是能将流体压力转化为精准、可控运动的装置。", "Alternator": "此设备能够产生强霍尔效应，从而使离子推进器能够加速其推进剂。", "AluK": "一种铝合金，重量轻，隔热性能优秀。", "AluminiumIngot": "该材料因密度极低且导电性高著称。虽然储量充足，但在自然环境中几乎找不到纯铝矿。", "Antimatter_Empty": "能够储存反粒子的容器。反物质向来制造难度极高，储存它更是难上加难。", "Aquamarine": "一种绿柱石晶体，可作为交易用的宝石，以其特有的浅蓝色著称。", "AutoBoostModule": "该小型计算机组件可以改善对推进器的控制：轻按[key.Booster]切换助推。", "AutoMineModule": "该小型计算机组件可以改善对采矿激光器的控制：轻按[key.Mine]切换采矿技能。", "AzuriteStone": "主要由铜构成的碳酸盐晶体，在人类历史上常被用作颜料。", "BTitanium": "一种钛钒合金，以可塑性极佳著称，因此是一种极佳的焊接材料。", "B_AntimatterSynthPH": "该建筑能够生产微量的反物质，虽然需要消耗大量电力，但与收获相比，这些投入不算什么。", "B_Battery": "该建筑能在电网产生富余电力时，将电力转化为化学能储存起来。在用电高峰期，可迅速将化学能重新转化为电能。", "B_BottlingPlant": "该建筑可将液体或半流体灌装到标准化容器中。", "B_Chemical": "该建筑可将化学元素合成为工业化合物。无需人工操作即可持续运行，适用于大规模生产。", "B_Chest": "与基地所有者同属一家企业的人，可在该箱子内放入或拿取礼物。", "B_Cistern": "该建筑适合用于储存液体或半流体材料。", "B_ControlBase": "这座核心建筑提供小型陆地基地运营所需的基本仓储、电力与行政系统。建筑部署后，即可合法拥有所占区域及区域内的矿脉。还配备了基础的手动熔炼和制造设备。", "B_ControlBase2": "该建筑可将基地拓展为 2 级地块，最大占地面积增加一倍，并解锁最高 800 点的经验值门槛。", "B_ControlBase3PH": "该建筑可将基地拓展为 3 级地块，最大占地面积增加一倍，并解锁最高 2000 点的经验值门槛。", "B_ControlBase_Corpo1": "受法律认可的重要企业需要一个集中运营的场所。该建筑可提升企业单个基地的最大规模，内置各类制造设施、会议室，以及多种自定义空间。", "B_Crystaliser": "该建筑利用化学溶液生成晶体，生成速度比自然结晶快得多。", "B_ElectricPillar": "这根柱子可以支撑电缆，将基地电网与其它建筑相连。如需将电缆接到电塔上，请对准电塔顶部按 E。", "B_Extractor": "该建筑只能建造在资源矿脉上，会自动钻探、开采原矿。", "B_FTLCistern": "该建筑适合用于储存活性磁等离子体。", "B_Factory1": "该建筑可将基础资源组装为工业产品。它是手动工作台的自动化替代方案，无需人工操作即可持续运转，适用于大规模生产。", "B_Factory2": "只有定制化的大型工厂能够制造最大型的飞船材料，这类工厂能耗极高。", "B_Farm": "该建筑为培育生物体提供适宜的环境。", "B_Generator": "该建筑消耗碳基燃料产生电流，为基地供电。体积小巧紧凑，而且发电效率高，但资源消耗较大。", "B_LaboPH": "该建筑包含一座紧凑型宁玛赫实验室，设备齐全，能分析异域物质。", "B_LandingPad": "该平台可供飞船停靠，还能接入基地的分配系统，便于传输燃料或其它流体。", "B_LiquidExtractor": "该建筑只能建造在地热池上，会自动提取纯净的流体。", "B_Organiser": "该建筑可监控多条无人机航线，还能将其整合成完整的生产链。是可以让生产流程秩序井然的中枢系统。", "B_PathwayHolder": "支柱的塔型结构能保持现有时空通道的稳定性，即使在行星的引力井内也不受影响。飞船可以利用常规超光速引擎，在通道中穿梭。", "B_PowerTransmitter": "该建筑利用前沿的屏蔽技术与引力时空扭曲技术，可在同一恒星系内的不同基地之间实现无损电力传输。", "B_RecyclingPlant": "该建筑可处理废料并从中提取各种部件。提取的产物可再次用于工业生产。", "B_Shipyard": "该平台可供飞船停靠，便于检修结构、更换模块。其功能与空间站中的造船坞类似。", "B_ShuttlePad": "该平台可供穿梭机停靠，便于在基地内外运输货物。", "B_Smelter": "该建筑可将原矿加工成工业锭材。它是手动熔炼炉的自动化替代方案，无需人工操作即可持续运行，适用于大规模生产。", "B_SmelterSA": "梅特纳与卡尔斯出品的微型熔炉，改良了锭材冶炼工艺。相较普通熔炼炉，它尺寸更小、效率更高。是满足大量手动制造需求的理想配件。", "B_SolarPanel": "该建筑可将电磁辐射转化为电流，为基地供电。会占用一定空间，而且朝向必须得当，但运转无需燃料。", "B_Warehouse": "该建筑适合用于储存固体材料，无人机可以很方便地进行装卸。", "BarrierShield1": "这种等离子体护盾的电荷充足，能够抵御轻型人造武器的攻击，但它的充能时间比普通护盾更久。", "Battery": "能够储存化学能并转化为电能的装置。是 RSM 大型电池的基础。", "Battery1": "该模块可储存化学能并转化为电流，为其它 RSM 供电。", "Beacon": "实验性的高速通信方式。无论信标位于何处，都能即时向银河系内的量子签名发送位置。", "BeaconKey": "实验性的高速通信方式。该装置可即时接收已配对信标的位置。", "Beam1": "截面呈 H 形的长条金属件。常用于建筑中，提供结构抗力。", "BlastMissile0": "在采矿作业中，经常使用爆炸物开采外壳坚硬的矿物。", "Blueprint": "这份详细的图纸包含建造特定飞船模块所需的全部说明。人类和机器都可读取此蓝图。", "BottlePlasma_Empty": "坚固的磁等离子体容器，能够装入常规货舱。", "Bottle_Empty": "简陋但可靠的容器，可用于储存液体或半流体，可以放入普通货舱。", "CalcifiedInvariant": "宇宙大爆炸时，这些古老的石头受到原初能量的洗礼，有些带有独特的能量特征，极具辨识度。", "Calcite": "一种碳酸盐晶体，也被称作雪花石膏。它是石灰石与大理石的主要成分，是雕塑的必备材料。", "Carbon": "无论以哪种形态存在——煤、钻石或石墨，在大部分行业中，它都是不可或缺的材料。它也是在所有已知生命形式中都存在的四种化学元素之一。", "CarbonGenerator": "该模块通过消耗碳基燃料产生电流，为其它 RSM 供电。", "CarbonicFuel": "经超加工制成的碳衍生物，用于替代天然化石燃料，并提供更高能效。", "Cartridge_Iron": "宇宙防卫军仍然大范围使用射弹武器，并为此制定了一系列弹药口径标准。", "Cinnabar": "朱砂是一种硫化汞晶体。人们认识到汞具有高毒性之前，朱砂因其色泽鲜红被广泛用作颜料。", "Cockpit_AE1": "埃吉尔品牌旗下的单人驾驶舱采用流线型设计，可降低在超光速跃迁期间发生严重损伤的概率。还配备了一块体积虽小但效率极高的动力电池。", "Cockpit_AE2": "埃吉尔品牌旗下的大型驾驶舱堪称技术奇迹，能够精准保存定位，可以随时跃迁到已保存的定位地点。且该过程无需消耗磁等离子体，也不会造成损伤。", "Cockpit_DA1": "达默娜品牌旗下的单人驾驶舱，隔热性能极佳，可降低外界温度影响，但激光的冷却时间较慢。同时配备小型散热器，可在过热时排出多余热量，或在低温时产生热量。", "Cockpit_MK1": "梅特纳与卡尔斯 (M&K) 品牌旗下的单人驾驶舱，其储存空间与抗撞击能力经过优化，是在小行星带中运输货物的上好选择。", "Cockpit_MK2": "梅特纳与卡尔斯品牌旗下的大型驾驶舱，内部空间巨大，足以容纳一座陆地基地标准的熔炼炉。", "Cockpit_TC1": "公司的入门级驾驶舱，通常装配在测试飞行器上。", "Coil": "能够将磁场转换为电流，或反向将电流转换为磁场的基础装置。", "Concrete": "由人造矿物骨料与名为“水泥”的化学物质混合制成。主要用于建筑，曾是地球上产量最大的材料。", "ControlBaseCore": "该装置可将周边区域划为用户基地，并为其供电。仅公司选定的授权合作人员有使用权限。", "ControlBaseKit": "该自主装置可在几秒内完成行星基地部署。仅公司选定的授权合作人员有使用权限。", "CopperIngot": "此材料导电性能极佳且用途广泛。可以作为天然金属存在，但也常见于晶体中。", "CorpoCredits": "这些信用点归属于企业，而非个人。", "CorpoReputation": "企业完成的委托越多，在星系中的声望越高。", "Crystal": "宝石的成分、外观与性质各异。它们的共同点是，对于人类而言都有很高的审美价值。", "CrystalLattice_C": "经过精密切割、可用于光学装置的晶体。其立方晶结构是自然界中最简单的晶体形态。", "CrystalLattice_H": "经过精密切割、可用于光学装置的晶体。其六方晶结构在自然界中最为常见。", "CrystalLattice_M": "经过精密切割、可用于光学装置的晶体。其单斜晶结构具有显著不对称性。", "Diamond": "纯碳的晶体形态。它仍是目前已知的硬度最高、导热性最强的材料。", "Drone0": "这种自主载具能够按照既定航线，在两点之间运送货物。", "Elmerium": "与其它材料相比，许多人对此材料没有正确认知。它的电磁性质能够形成等离子场。发现于联合行星时代，推动了超光速护盾的研发。", "ElmeriumEngine": "能够在球形区域内扩散等离子体场的装置。是大部分护盾型号不可或缺的关键部件。", "Emerald": "一种绿柱石晶体，可作为交易用的宝石，以其特有的深绿色著称。", "EngineBooster": "落日品牌旗下的入门级辅助引擎模块，能帮预算有限的飞行员显著提升航速。", "Ethanol": "乙醇（俗称酒精）广为人知，不仅因为喝酒令人愉悦，还因为乙醇本身既是高密度生物燃料，也是清除油性污渍的有效溶剂。", "ExplodingToolMk1": "该模块能够向远程目标投放一枚爆炸弹药。", "FTLEngine1": "此类模块被视为联合行星时代最伟大的发明，它能够收缩与扩展空间，实现超光速航行。", "FTLEngine3_Solo": "此类模块被视为联合行星时代最伟大的发明，它能够收缩与扩展空间，实现超光速航行。本型号为单艘飞船做了优化设计。", "FTLEngine3_Support": "此类模块被视为*联合行星*时代最伟大的发明，它能够收缩与扩展空间，实现超光速航行。本型号可一次性传送多艘飞船。", "FTLTank1": "该储存模块适合存放活性磁等离子体。配备 MACS 接口，可为护盾类 RSM 供能。", "FToiL": "这种非凡燃料的发现，为超光速跃迁的发明奠定了基础。", "Fertilizer_Neutral": "这种粉末状营养剂可在种植外星植物时使用，为植株提供特定的营养成分。", "FluidPumpingTool1": "该模块吸力强劲，能够收集环境中出现的各种流体。", "Focuser": "使用抛光晶体聚集辐射的光学装置。", "Graphene": "碳原子相互连接构成的材料。具备无与伦比的抗拉强度，因此是兼顾轻量化与坚固性的理想材料。", "Graphenoid": "呈现量子分子效应的石墨烯结构，是高端超光速引擎实现负质量能力的关键。", "GraphiteCrystal": "由多层石墨烯构成的晶体。尽管有人称其为未加工的钻石，但它的价格十分低廉，甚至是制造铅笔的原料。", "Grating": "光栅是一种光学装置，能将光分解为不同频率的光谱。", "GraviteDetector": "能够精准定位引力石的专用探测仪。其它探测仪能够探测各种物品，唯独无法探测引力石，但这款探测仪则截然不同。", "Gunpowder": "火药是一种受热时会发生爆燃的化合物。", "Heater": "加热器能够将电能转化为热量，抵御外部严寒。", "Hematite": "一种结晶氧化铁，由于密度高，适合用于屏蔽辐射。也具备较好的导电性。", "HullMK1_004": "飞船主要由三层结构组成：最外层是由耐久材料构成的真空防护层，中间是由重型梁构成的稳固内部骨架，最内层是维持飞船居住设施与功能运转的内部系统。", "IronIngot": "此材料与人类文明起源密切相关。广泛应用于各类工业，是类地行星上最丰富的元素之一。", "Kaolinite": "一种十分常见的硅酸盐矿物，广泛用于生产纸张和涂料。是黏土壳的常见成分。少量摄入无害，也是牙膏的常用成分。", "KineticShield1": "该模块会通过一对特斯拉线圈生成一个由带电等离子体构成的气泡，可保护飞船抵挡辐射与粒子冲击。", "Levinium": "此金属材料近些年才被发现，以重量极轻著称。目前尚不清楚它的性质和用途。", "LicensePoints": "这些点数由共和国宇宙执照管理局发放，可用于获取工业执照。", "Light_01": "一盏好灯，在黑暗中为你照亮前路。", "Lime": "常用于水泥与混凝土的矿物材料。通过碳化石灰石制成，主要成分是氧化钙。", "LiquidStorage1": "该储存模块适合存放液体或半流体材料。若装有燃料或冷却液，可使用配备的 MACS 接口供应其它 RSM。", "MagSheet": "由埃尔默制成的磁极化板材，常用于制造磁等离子体的内胆。", "MagneticChamber": "该装置使等离子体电流高速环形运动时不偏离轨道。", "MalachiteStone": "主要由铜构成的碳酸盐晶体，从古埃及文明到玛雅文明，都是一种丧葬装饰。", "Mercury": "汞是目前已知的唯一一种在室温下呈液体状态的金属。它对人类毒性极高，还能和许多其它金属发生反应，形成汞合金。", "MetalBolt": "利用扭力将部件固定在一起的基础装置。", "MetalSheet1": "经工业加工的金属板材，常被用作基础建材。", "MicroChip": "通过一系列简单的数学运算来执行计算机程序的电子装置。也被称为“中央处理器 (CPU)”。", "MiningTool1": "该光学模块将光线增强至足以汽化物质。是目前最精确的切割方法。", "MiningTool_Cold": "与汽化物质的激光相反，冷却激光器可以射出高压液化气流，给物体表面降温。也可以两者结合使用。", "MissileAirframe_Small": "能够运载爆炸弹头的金属外壳及推进结构。", "ModuleCasing1": "通用的标准组件，是“瑞氏耐用飞船模块 (RSM)”系列产品的基础。可使用 B-Switch 电永磁体将 RSM 固定到对应飞船上。", "Motor": "能够将电能转换为运动，或反向将运动转换为电能的装置。", "Navigator": "该模块利用复杂的算法与精确的空间坐标，帮心不在焉的合约工规划星际航线。", "P_ColdSuit": "该配件能够增强服装隔绝低温的性能。若要提升效果，可安装多枚芯片。", "P_ConstructionTool": "“蓝图合成”会释放一团悬浮的纳米机器人云，能够根据预设模板识别、切割、组装材料。简单来说，它是用来造东西的。", "P_DismentlingTool": "这款改进版工具包含“材料分解”功能，可以逆转一次已完成的建造进程，且相关部件受到的损伤极小。", "P_FarmingTool": "把一颗沾满泥土的种子浸泡在水里看似简单，但有了这件工具，才能将每株外星植物幼体安置在最利于生长的位置。至此，种植才升华成了一门艺术。", "P_HeatSuit": "该配件能够增强服装隔绝高温的性能。若要提升效果，可安装多枚芯片。", "P_Jetpack": "[NOTIMPL]", "P_JetpackV2": "（未实装]", "P_MovingTool": "这款改进版工具包含“连续集成”功能，可在基地内移动整个建筑，无需拆除。", "P_RadSuit": "该配件能够增强服装隔绝辐射的性能。若要提升效果，可安装多枚芯片。", "P_ThermoSuit": "该配件能够增强服装的隔温性能，抵御高温或低温。若要提升效果，可安装多枚芯片。", "PathwayAmmo": "通道核心需与[PathwayPuncher]配合使用，核心能够钻出一条通道，通向任意可用的[B_PathwayHolder]。通道建立后，可使用常规超光速引擎在两地之间往返跃迁。", "PathwayPuncher": "该模块可在时空连续体中钻出一个微小孔洞，从而部署[PathwayAmmo]，钻出一条通向现有[B_PathwayHolder]的通道。", "Pipe1": "在两点之间输送流体的基础装置。", "Plate1": "能抵御恶劣天气的厚实金属板。常用于户外建筑或飞船船体。", "PlatinumIngot": "价值极高的贵金属。具备超强的耐腐蚀性，因此是珍贵的工业材料。", "PressureStorage1": "该储存模块适合存放需要极高加压的液态气体。若装有燃料或冷却液，可使用配备的 MACS 接口供应其它 RSM。", "Protein": "生物体不可或缺的组成部分，蛋白质是由氨基酸链构成的生物分子。", "Pump": "在相接的管道中推动流体的装置。", "Pyrite": "一种结晶硫化铁。尽管因其价格低廉，也被称作“愚人金”，但它仍然是实用的半导体材料，也是常见的光伏元件。", "Quartz": "主要由二氧化硅构成的晶体，也是许多天体的主要成分。自人类远古时代起，各种各样的石英就是交易用的宝石。", "RBattery0": "该模块通过旋转轮储存动能，为其它 RSM 供电。使用它可以规避化学电池的缺点。", "Radar0": "通过发射电磁波并进行折射分析，该雷达能够在较大范围内探测含有金属物体。", "Radar_Smart": "该探测仪使用光谱分析和数据库比对，能够远距离识别已知资源。", "Radar_Sniffer": "该探测仪利用指定资源的样本，能够定位附近含有相同元素的矿脉。", "Radiator": "该模块能够释放大量热能。能将热量散发到外太空，因此主要用于给飞船内部降温。", "Radon": "氡是一种危险的放射性气体，如未穿戴适当的防护装备，不宜接触。", "Rockwood_DreamwoodFruit": "强烈建议不要食用这种果实。可能存在的副作用包括：逼真的幻觉、急性偏执症、猝死。", "Rockwood_GlowwoodBark": "这种厚实的深色树皮虽然生长在放射性环境中，但似乎并未因此受损。", "Rockwood_GlowwoodFruit": "这颗闪亮的果子摸起来微微发热，意味着它可能具有放射性。", "Rockwood_Seed": "岩木以独特的方式将矿物和有机化合物结合在一起。常常会形成自然界罕见的复杂矿物结构。", "Sandstone": "主要由氧化硅构成的沉积岩。它是玻璃、陶瓷和水泥的成分之一。它在类地行星上的储量极为丰富，类地行星也因此被称为“硅酸盐行星”。", "Scanner0": "该模块可通过质谱分析识别样本成分。采矿激光只对已识别成分的资源生效。", "SeekerMissile0": "在人类大迁徙之前，简易化学爆炸物曾是常见的武器。虽然也有其它杀伤力更强的选择，但这是成本最低、最容易制造的。", "Semiconductor": "可用于制造微芯片或太阳能电池的空白基板。", "Shuttle0": "这种自主载具能将货物运进或运出基地，在不同基地之间执行运输任务。", "SiliciumIngot": "性能极其均衡的半导体，在诸多电子设备中被广泛应用。它是一种类金属元素，也存在于黏土、玻璃，以及各种各样的岩石之中。", "SiliconeGel": "此材料性质稳定且吸附性强，主要用于化学操作、滤水和冷却系统。", "SilverIngot": "在所有金属中，它的导电性和反射性最强。纯银矿存在于自然环境中，数千年以来，一直广泛应用于人类工业和艺术的各个领域。", "SolarCell": "将电磁波转换为电能的电子装置。", "SolarPanel1": "该模块可将电磁辐射转化为电流，为其它 RSM 供电。", "SpaceWheat_FrostPulp": "尽管名字叫作霜浆，但奇怪的是，这种浆液似乎不受外部气温影响，暖呼呼的。", "SpaceWheat_PlainPulp": "该浆液几乎无味，但含有异常丰富的营养成分。", "SpaceWheat_Seed": "太空玉米是一种适应力很强的外星作物。更妙的是，它提供的营养与人类生理兼容。", "SpaceWheat_SourPulp": "该浆液已经变质，可能含有发酵化合物。", "SpaceWheat_WoolyKorn": "坚硬的纤维壳内，可能包裹着几颗太空玉米种子，提取种子需使用研磨机。", "Steel": "由铁与碳构成的合金，通常还会加入铬，以防止氧化。可靠性高、成本低，因此是许多行业的必备材料。", "SteelCasingMK1": "用于包裹飞船或 RSM 的模块化船体既能减少飞船在大气层受到的摩擦，也能防护电磁辐射。", "Storage1": "该储存模块适合存放固体材料。配备磁力稳定系统，无论飞船如何移动，都能保护货物不受碰撞。", "Sulfur": "既是晶体材料，也是化学成分与肥料。硫磺石在《圣经》中被称为地狱的产物，但是硫元素是所有已知生命形式共有的六种化学元素之一。", "SupportCasing": "一套标准化的电缆与管道系统，可使所有 RSM 都能与对应飞船通信。遵循“模块组装循环系统 (MACS)”规范。", "ThermalIsolant": "一种矿物纤维，能够锁住薄薄的空气层，减缓热传导。它的名字令人想起绵羊毛还存在的温柔岁月。", "ThermalPaste": "这种半有机膏状物对温度变化的耐受性极高。可用于抵御极端环境。", "ThermalSheet": "经工业加工的金属板材，导热性极低。", "Thruster0": "电动推进装置，无需燃烧或使用不可再生燃料。可为穿梭机提供推力和升力。", "ThrusterAE1": "这款埃吉尔品牌的推进器设计精巧，与飞船系统深度融合，具备顶级能效，助你在黑暗中探索未知的边界。", "ThrusterDA1": "求知若渴之人为了探索科学奥秘，常常处于危险边缘。达默娜品牌的这款推进器正是为此设计，能够让求知者迅速地返回安全、辽阔的太空中。", "ThrusterMK1": "梅特纳与卡尔斯品牌的这款推进器动力强劲，专为应对最残酷的干热采矿环境设计。", "TitaniumIngot": "该材料重量轻、强度高，且具备生物兼容性，因此常常用于制造合金。也存在于大多数生物体内。", "TungstenIngot": "钨是一种高密度、坚硬、熔点极高的金属。虽然难以加工，但由于性能优异，在许多种合金中，钨都是不可或缺的成分。", "Turquoise": "由陨石水与铜斑岩相互作用形成的不透明宝石。", "Unbendinium": "抗弯金属是一种神秘的合金，在人类的太空物流中发挥重要作用。其抗拉强度和屈服强度，都远比人类已知的其它金属更强。", "UraniumNugget": "铀是一种危险的放射物质，如未穿戴适当的防护装备，不宜接触。", "VanadiumIngot": "此材料常用于制造钢合金。在一些生物体内，它也是一种毒素。", "Vitriol": "硫酸是应用范围最广的工业化学品之一。生产方式多样，用途想当广泛。", "Water": "水是一种极性强、分子体积小的极佳中性溶剂，对所有已知生命形式和大多数现有行业都至关重要。", "Water_Brine": "一种大型露天水体，常受到各种物质污染。需要先经过处理才能在化工流程中使用。", "Wire": "在两点之间传输电流的基础装置。", "XenicOil": "异星油是从外星种子中提取出的一种有机烃，作为润滑剂使用十分有效，但作为燃料使用则表现平平。", "ZirconiumIngot": "此材料极其耐腐蚀、耐高温。储存放射性能量时的能量损耗极低。"}}

